CA;AACF;;AAEA;AACF;;AAEA;AACE;;AAEA;AACE;;AAEA;AACE;AACF;;AAEA;AACA;AACF;AACF;;AAEA;AACE;;AAEA;;AAEA;AACE;AACA;AACE;AACA;AACA;AACF;AACF;AACA;AACE;AACA;;AAEA;AACE;AACF;AACA;AACE;AACF;AACF;;AAEA;AACF;;AAEA;AACE;;AAEA;AACF;;AAEA;AACE;;AAEA;AACE;AACF;;AAEA;AACF;;;AAGA;AACA;;AAEA;;AAEA;AACA;AACA;AACA;AACA;AACA;AACA;AACE;AACA;AACE;;AAEF;;AAEA;;AAEA;;AAEA;AACF;;AAEA;AACA;AACE;AACA;AACA;AACA;AACF;;AAEA;AACA;AACE;AACA;AACA;AACA;AACF;;AAEA;AACA;AACE;AACA;AACF;;AAEA;AACA;;AAEA;AACA;AACA;AACE;AACE;AACA;AACA;AACE;AACF;AACE;AACE;AACF;AACA;AACA;AACA;AACA;AACF;AACA;AACF;AACA;AACE;AACA;AACE;AACF;AACA;AACF;AACF;;AAEA;AACA;;AAEA;;AAEA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA;AACE;AACO;AACT;;AAEA;AACE;AACF;AACA;AACA;AACE;AACF;AACA;AACE;AACF;AACA;AACE;AACA;AACA;AACF;;AAEA;AACA;AACE;AACE;AACF;AACF;AACA;;AAEA;AACE;AACF;AACA;AACE;AACE;AACA;AACF;AACF;AACA;AACE;AACE;AACA;AACF;AACF;AACA;AACE;AACE;AACA;AACF;AACF;;AAEA;AACA;AACE;AACE;AACF;AACE;AACF;AACE;AACF;AACF;;AAEA;AACE;AACE;AACF;AACA;AACF;;AAEA;AACA;AACA;AACA;AACE;AACA;AACE;AACE;AACE;AACA;AACF;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACE;AACJ;AACF;AACA;AACF;;AAEA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA;AACA;AACA;;AAEA;AACA;;AAEA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA;AACE;AACA;AACE;AACA;AACF;AACE;AACF;AACF;;AAEA;AACA;AACA;;AAEA;AACA;AACA;AACA;;AAEA;AACA;AACE;AACA;AACA;AACA;AACF;;AAEA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACE;AACA;AACA;AACE;AACA;AACA;AACF;AACA;AACF;;AAEA;;AAEA;;AAEA;AACA;AACA;AACF;AACA"}}, {:offset=>{:line=>3058, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/helpers.rb"], :sourcesContent=>["# helpers: type_error, coerce_to\n\nmodule ::Opal\n  def self.bridge(constructor, klass)\n    `Opal.bridge(constructor, klass)`\n  end\n\n  def self.coerce_to!(object, type, method, *args)\n    coerced = `$coerce_to(object, type, method, args)`\n\n    unless type === coerced\n      ::Kernel.raise `$type_error(object, type, method, coerced)`\n    end\n\n    coerced\n  end\n\n  def self.coerce_to?(object, type, method, *args)\n    return unless object.respond_to? method\n\n    coerced = `$coerce_to(object, type, method, args)`\n\n    return if coerced.nil?\n\n    unless type === coerced\n      ::Kernel.raise `$type_error(object, type, method, coerced)`\n    end\n\n    coerced\n  end\n\n  def self.try_convert(object, type, method)\n    return object if type === object\n\n    if object.respond_to? method\n      object.__send__ method\n    end\n  end\n\n  def self.compare(a, b)\n    compare = a <=> b\n\n    if `compare === nil`\n      ::Kernel.raise ::ArgumentError, \"comparison of \#{a.class} with \#{b.class} failed\"\n    end\n\n    compare\n  end\n\n  def self.destructure(args)\n    %x{\n      if (args.length == 1) {\n        return args[0];\n      }\n      else if (args.$$is_array) {\n        return args;\n      }\n      else {\n        var args_ary = new Array(args.length);\n        for(var i = 0, l = args_ary.length; i < l; i++) { args_ary[i] = args[i]; }\n\n        return args_ary;\n      }\n    }\n  end\n\n  def self.respond_to?(obj, method, include_all = false)\n    %x{\n      if (obj == null || !obj.$$class) {\n        return false;\n      }\n    }\n\n    obj.respond_to?(method, include_all)\n  end\n\n  def self.instance_variable_name!(name)\n    name = ::Opal.coerce_to!(name, ::String, :to_str)\n\n    unless `/^@[a-zA-Z_][a-zA-Z0-9_]*?$/.test(name)`\n      ::Kernel.raise ::NameError.new(\"'\#{name}' is not allowed as an instance variable name\", name)\n    end\n\n    name\n  end\n\n  def self.class_variable_name!(name)\n    name = ::Opal.coerce_to!(name, ::String, :to_str)\n\n    if `name.length < 3 || name.slice(0,2) !== '@@'`\n      ::Kernel.raise ::NameError.new(\"`\#{name}' is not allowed as a class variable name\", name)\n    end\n\n    name\n  end\n\n  def self.const_name?(const_name)\n    %x{\n      if (typeof const_name !== 'string') {\n        \#{const_name = ::Opal.coerce_to!(const_name, ::String, :to_str)}\n      }\n\n      return \#{const_name}[0] === \#{const_name}[0].toUpperCase()\n    }\n  end\n\n  def self.const_name!(const_name)\n    const_name = ::Opal.coerce_to!(const_name, ::String, :to_str) if defined? ::String\n\n    %x{\n      if (!const_name || const_name[0] != const_name[0].toUpperCase()) {\n        \#{raise ::NameError, \"wrong constant name \#{const_name}\"}\n      }\n    }\n\n    const_name\n  end\n\n  # @private\n  # Mark some methods as pristine in order to apply optimizations when they\n  # are still in their original form. This could probably be moved to\n  # the `Opal.def()` JS API, but for now it will stay manual.\n  #\n  # @example\n  #\n  #   Opal.pristine Array, :allocate, :copy_instance_variables, :initialize_dup\n  #\n  #   class Array\n  #     def dup\n  #       %x{\n  #         if (\n  #           self.$allocate.$$pristine &&\n  #           self.$copy_instance_variables.$$pristine &&\n  #           self.$initialize_dup.$$pristine\n  #         ) return self.slice(0);\n  #       }\n  #\n  #       super\n  #     end\n  #   end\n  #\n  # @param owner_class [Class] the class owning the methods\n  # @param method_names [Array<Symbol>] the list of methods names to mark\n  # @return [nil]\n  def self.pristine(owner_class, *method_names)\n    %x{\n      var method_name, method;\n      for (var i = method_names.length - 1; i >= 0; i--) {\n        method_name = method_names[i];\n        method = owner_class.$$prototype[Opal.jsid(method_name)];\n\n        if (method && !method.$$stub) {\n          method.$$pristine = true;\n        }\n      }\n    }\n    nil\n  end\n\n  `var inspect_stack = []`\n\n  # Performs a safe call to inspect for any value, whether\n  # native or Opal-wrapped.\n  #\n  # @param value [Object]\n  # @return [String]\n  def self.inspect(value = undefined)\n    `var pushed = false`\n    begin\n      %x{\n        if (value === null) {\n          // JS null value\n          return 'null';\n        }\n        else if (value === undefined) {\n          // JS undefined value\n          return 'undefined';\n        }\n        else if (typeof value.$$class === 'undefined') {\n          // JS object / other value that is not bridged\n          return Object.prototype.toString.apply(value);\n        }\n        else if (typeof value.$inspect !== 'function' || value.$inspect.$$stub) {\n          // BasicObject and friends\n          return \#{\"#<\#{`value.$$class`}:0x\#{value.__id__.to_s(16)}>\"}\n        }\n        else if (inspect_stack.indexOf(\#{value.__id__}) !== -1) {\n          // inspect recursing inside inspect to find out about the\n          // same object\n          return \#{\"#<\#{`value.$$class`}:0x\#{value.__id__.to_s(16)}>\"}\n        }\n        else {\n          // anything supporting Opal\n          inspect_stack.push(\#{value.__id__});\n          pushed = true;\n          return value.$inspect();\n        }\n      }\n      nil\n    rescue ::Exception => e # rubocop:disable Lint/RescueException\n      \"#<\#{`value.$$class`}:0x\#{value.__id__.to_s(16)}>\"\n    ensure\n      `if (pushed) inspect_stack.pop()`\n    end\n  end\nend\n"], :names=>["<top (required)>", "<module:Opal>", "bridge", "self", "constructor", "klass", "coerce_to!", "object", "type", "method", "coerced", "Kernel", "raise", "coerce_to?", "respond_to?", "nil?", "try_convert", "__send__", "compare", "a", "b", "<=>", "ArgumentError", "class", "destructure", "args", "obj", "include_all", "instance_variable_name!", "name", "Opal", "String", "NameError", "new", "class_variable_name!", "const_name?", "const_name", "const_name!", "pristine", "owner_class", "inspect", "value", "__id__", "to_s", "16", "Exception", "e"], :mappings=>"AAAAA,kCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;;;IACEC,MAAIC,IAAJD,aAAAA,kBAAgBE,WAAD,EAAcC,KAA7BH;AAAAA;MACEA,OAACA,+BAADA;IADFA,CAAAA;IAIAI,MAAIH,IAAJG,iBAAAA,gCAAoBC,MAAD,EAASC,IAAT,EAAeC,MAAf,EAPrB,EAOEH;AAAAA,MAAAA;;;MAPF;MAO4C;MACxCI,UAAWJ;MAEX,KAAA,QAAOE,IAAP,EAAgBE,OAAhB,CAAA;Q