obj.$$id = Opal.uid();\n      return obj;\n    }\n  end\n\n  def descendants\n    subclasses + subclasses.map(&:descendants).flatten\n  end\n\n  def inherited(cls)\n  end\n\n  def initialize_dup(original)\n    initialize_copy(original)\n    %x{\n      self.$$name = null;\n      self.$$full_name = null;\n    }\n  end\n\n  def new(*args, &block)\n    %x{\n      var object = \#{allocate};\n      Opal.send(object, object.$initialize, args, block);\n      return object;\n    }\n  end\n\n  def subclasses\n    %x{\n      if (typeof WeakRef !== 'undefined') {\n        var i, subclass, out = [];\n        for (i = 0; i < self.$$subclasses.length; i++) {\n          subclass = self.$$subclasses[i].deref();\n          if (subclass !== undefined) {\n            out.push(subclass);\n          }\n        }\n        return out;\n      }\n      else {\n        return self.$$subclasses;\n      }\n    }\n  end\n\n  def superclass\n    `self.$$super || nil`\n  end\n\n  def to_s\n    %x{\n      var singleton_of = self.$$singleton_of;\n\n      if (singleton_of && singleton_of.$$is_a_module) {\n        return \#{\"#<Class:\#{`singleton_of`.name}>\"};\n      }\n      else if (singleton_of) {\n        // a singleton class created from an object\n        return \#{\"#<Class:#<\#{`singleton_of.$$class`.name}:0x\#{`Opal.id(singleton_of)`.to_s(16)}>>\"};\n      }\n\n      return \#{super()};\n    }\n  end\n\n  def attached_object\n    %x{\n      if (self.$$singleton_of != null) {\n        return self.$$singleton_of;\n      }\n      else {\n        \#{::Kernel.raise ::TypeError, \"`\#{self}' is not a singleton class\"}\n      }\n    }\n  end\n\n  alias inspect to_s\nend\n"], :names=>["<top (required)>", "self", "require", "<class:Class>", "new", "superclass", "Object", "block_given?", "class_eval", "block", "to_proc", "allocate", "descendants", "+", "subclasses", "map", "flatten", "inherited", "initialize_dup", "original", "initialize_copy", "to_s", "name", "16", "attached_object", "Kernel", "raise", "TypeError"], :mappings=>"AAAAA,gCAAAA,gBAAAA;EAAAA;;;EAAAC,IAAAC,SAAAA,CAAQF,gBAARE;EAEAF,OAAAG;EAAAA;;IAAAA;;;IACEC,MAAIH,IAAJG,UAAAA,sBAAaC,UAAbD;AAAAA,MAAAA;;MAAAA;;;MAAa,qCAAaE;;AAE5BF;AACAA;AACAA;;AAEAA;AACAA;AACAA,MAAQ,CAA8BG,eAA9B,GAAA,CAAOC,MAAPJ,CAACA,KAADA,CAAOI,cAAAA,EAAAA,EAAAA,EAAaC,KAADC,SAAAA,CAAAA,CAAZF,CAAP,IAAA,GAAA;AACRJ;AACAA;IAVEA,CAAAA,IAAAA;;AAaAO,IAAAA,wBAAAA,oBAAAA;AAAAA,MAAAA;;;AAEFA;AACAA;AACAA;AACAA;IALEA,CAAAA;;AAQAC,IAAAA,2BAAAA,uBAAAA;AAAAA,MAAAA;;MACEA,OAAWC,SAAXZ,IAAAa,YAAAA,CAAAA,CAAWD,EAAYE,MAAVd,IAAAa,YAAAA,CAAAA,CAAUC,OAAAA,EAAAA,EAAAA,EAAM,aAADL,SAAAA,CAAAA,CAALK,CAAmBC,SAAAA,CAAAA,CAA/BH;IADbD,CAAAA;;AAIAK,IAAAA,yBAAAA,YA5BF,GA4BEA,CAAAA;;AAGAC,IAAAA,8BAAAA,0BAAmBC,QAAnBD;AAAAA,MAAAA;;;MACEjB,IAAAmB,iBAAAA,CAAgBD,QAAhBC;;AAEJF;AACAA;AACAA;IALEA,CAAAA;;AAQAd,IAAAA,mBAAAA,sBAvCF,EAuCEA;AAAAA,MAAAA;;MAAAA;;;MAvCF;MAuCU;;AAEVA,mBAAqBH,IAAAU,UAAAA,CAAAA,CAASP;AAC9BA;AACAA;AACAA;IALEA,CAAAA,IAAAA;;AAQAU,IAAAA,0BAAAA,sBAAAA;AAAAA,MAAAA;;;AAEFA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;IAfEA,CAAAA;;AAkBAT,IAAAA,0BAAAA,sBAAAA;AAAAA,MAAAA;;MACEA,OAACA,mBAADA;IADFA,CAAAA;;AAIAgB,IAAAA,oBAAAA,gBAAAA;AAAAA,MAAAA;;MAAAA;;AAEFA;;AAEAA;AACAA,eAAkBA,UAAD,GAAA,CAAWA,CAACA,YAADA,CAAcC,MAAAA,CAAAA,CAAzB,CAAA,GAA+BD,GAAGA;AACnDA;AACAA;AACAA;AACAA,eAAkBA,YAAD,GAAA,CAAaA,CAACA,oBAADA,CAAsBC,MAAAA,CAAAA,CAAnC,CAAA,GAAyCD,KAAzC,GAAA,CAA8CA,CAACA,qBAADA,CAAuBA,MAAAA,CAAME,EAANF,CAArE,CAAA,GAA+EA,IAAIA;AACpGA;;AAEAA,aAAe,OAAApB,IAAA,EAAA,8CAAA,QAAA,EAAA,EAAA,EAAA,IAAA,CAAQoB;AACvBA;IAbEA,CAAAA;;AAgBAG,IAAAA,+BAAAA,2BAAAA;AAAAA,MAAAA;;;AAEFA;AACAA;AACAA;AACAA;AACAA,QAAUC,OAAQC,OAAAA,CAAOC,gBAAf,EAA6BH,GAAD,GAAA,CAAIvB,IAAJ,CAAA,GAASuB,4BAA7BE;AAClBF;AACAA;IAREA,CAAAA;IAWArB,OAAA,aAAM,SAAN,EAAc,MAAd;EA9FFA,GAAM,IAANA,EAAAA,IAAAA;AAFAH;"}}, {:offset=>{:line=>4408, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/basic_object.rb"], :sourcesContent=>["# use_strict: true\n\nclass ::BasicObject\n  def initialize(*)\n  end\n\n  def ==(other)\n    `self === other`\n  end\n\n  def eql?(other)\n    self == other\n  end\n\n  alias equal? ==\n\n  def __id__\n    %x{\n      if (self.$$id != null) {\n        return self.$$id;\n      }\n      Opal.prop(self, '$$id', Opal.uid());\n      return self.$$id;\n    }\n  end\n\n  def __send__(symbol, *args, &block)\n    %x{\n      if (!symbol.$$is_string) {\n        \#{raise ::TypeError, \"\#{inspect} is not a symbol nor a string\"}\n      }\n\n      var func = self[Opal.jsid(symbol)];\n\n      if (func) {\n        if (block !== nil) {\n          func.$$p = block;\n        }\n\n        return func.apply(self, args);\n      }\n\n      if (block !== nil) {\n        self.$method_missing.$$p = block;\n      }\n\n      return self.$method_missing.apply(self, [symbol].concat(args));\n    }\n  end\n\n  def !\n    false\n  end\n  ::Opal.pristine :!\n\n  def !=(other)\n    !(self == other)\n  end\n\n  def instance_eval(*args, &block)\n    if block.nil? && `!!Opal.compile`\n      ::Kernel.raise ::ArgumentError, 'wrong number of arguments (0 for 1..3)' unless (1..3).cover? args.size\n\n      string, file, _lineno = *args\n      default_eval_options = { file: (file || '(eval)'), eval: true }\n      compiling_options = __OPAL_COMPILER_CONFIG__.merge(default_eval_options)\n      compiled = ::Opal.compile string, compiling_options\n      block = ::Kernel.proc do\n        %x{new Function(\"Opal,self\", \"return \" + compiled)(Opal, self)}\n      end\n    elsif block.nil? && args.length >= 1 && args.first[0] == '@'\n      # get instance variable\n      return instance_variable_get(args.first)\n    elsif args.any?\n      ::Kernel.raise ::ArgumentError, \"wrong number of arguments (\#{args.size} for 0)\"\n    end\n\n    %x{\n      var old = block.$$s,\n          result;\n\n      block.$$s = null;\n\n      // Need to pass $$eval so that method definitions know if this is\n      // being done on a class/module. Cannot be compiler driven since\n      // send(:instance_eval) needs to work.\n      if (self.$$is_a_module) {\n        self.$$eval = true;\n        try {\n          result = block.call(self, self);\n        }\n        finally {\n          self.$$eval = false;\n        }\n      }\n      else {\n        result = block.call(self, self);\n      }\n\n      block.$$s = old;\n\n      return result;\n    }\n  end\n\n  def instance_exec(*args, &block)\n    ::Kernel.raise ::ArgumentError, 'no block given' unless block\n\n    %x{\n      var block_self = block.$$s,\n          result;\n\n      block.$$s = null;\n\n      if (self.$$is_a_module) {\n        self.$$eval = true;\n        try {\n          result = block.apply(self, args);\n        }\n        finally {\n          self.$$eval = false;\n        }\n      }\n      else {\n        result = block.apply(self, args);\n      }\n\n      block.$$s = block_self;\n\n      return result;\n    }\n  end\n\n  def singleton_method_added(*)\n  end\n\n  def singleton_method_removed(*)\n  end\n\n  def singleton_method_undefined(*)\n  end\n\n  def method_missing(symbol, *args, &block)\n    inspect_result = ::Opal.inspect(self)\n    ::Kernel.raise ::NoMethodError.new(\n      \"undefined method `\#{symbol}' for \#{inspect_result}\", symbol, args\n    ), nil, ::Kernel.caller(1)\n  end\n\n  ::Opal.pristine(self, :method_missing)\n\n  def respond_to_missing?(method_name, include_all = false)\n    false\n  end\nend\n"], :names=>["<top (required)>", "<class:BasicObject>", "initialize", "==", "other", "eql?", "self", "__id__", "__send__", "symbol", "raise", "TypeError", "inspect", "!", "Opal", "pristine", "!=", "instance_eval", "block", "nil?", "1", "3", "cover?", "args", "size", "Kernel", "ArgumentError", "string", "file", "_lineno", "default_eval_options", "$ret_or_1", "compiling_options", "__OPAL_COMPILER_CONFIG__", "merge", "compiled", "compile", "proc", "block in instance_eval", "block (2 levels) in instance_eval", ">=", "length", "first", "[]", "0", "instance_variable_get", "a