s[i][2];\n\n        klass = Opal.klass(self, Opal.SystemCallError, class_name);\n        klass.errno = errno;\n\n        \#{\n          class << klass\n            def new(name = nil)\n              message = `default_message`\n              message += \" - \#{name}\" if name\n              super(message)\n            end\n          end\n        }\n      })();\n    }\n  }\nend\n\nclass ::SystemCallError < ::StandardError\n  def errno\n    self.class.errno\n  end\n\n  class << self\n    attr_reader :errno\n  end\nend\n"], :names=>["<top (required)>", "<module:Errno>", "errors", "22", "17", "21", "24", "29", "13", "1", "2", "36", "klass", "new", "name", "message", "+", "self", "<class:SystemCallError>", "errno", "class", "attr_reader", "StandardError"], :mappings=>"AAAAA,sCAAAA,gBAAAA;EAAAA;;;EAAAC;EAAAA;;IAAAA;;;IACEC,SAAS,CACP,CAAC,QAAD,EAAUD,kBAAV,EAA8BE,EAA9B,CADO,EAEP,CAAC,QAAD,EAAUF,aAAV,EAAyBG,EAAzB,CAFO,EAGP,CAAC,QAAD,EAAUH,gBAAV,EAA4BI,EAA5B,CAHO,EAIP,CAAC,QAAD,EAAUJ,qBAAV,EAAiCK,EAAjC,CAJO,EAKP,CAAC,QAAD,EAAUL,cAAV,EAA0BM,EAA1B,CALO,EAMP,CAAC,QAAD,EAAUN,mBAAV,EAA+BO,EAA/B,CANO,EAOP,CAAC,OAAD,EAASP,yBAAT,EAAoCQ,CAApC,CAPO,EAQP,CAAC,QAAD,EAAUR,2BAAV,EAAuCS,CAAvC,CARO,EASP,CAAC,cAAD,EAAgBT,oBAAhB,EAAsCU,EAAtC,CATO;IAYTC,QAAQ;;AAGVX;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA,QACU;;MACE,OAAAY,mBAAAA,gBAAQC,IAARD;AAAAA,QAAAA;;QAAAA;;QAAQ,yBAAO;QACbE,UAAWF;QACX,IAAA,QAA2BC,IAA3B,CAAA;UAAAC,UAAQC,SAARD,OAAQC,EAAIH,KAAD,GAAA,CAAMC,IAAN,CAAHE;QAAR;QACAH,OAAA,OAAAI,IAAA,EAAA,6CAAA,OAAA,EAAA,CAAMF,OAAN,CAAA,EAAA,IAAA;MAHFF,CAAAA,IAAAA;IADF,4BAASD,KAAT;AAQVX;AACAA;AACAA;EArCAA,GAAO,IAAPA;EAwCAD,OAAAkB;EAAAA;;IAAAA;;;;AACEC,IAAAA,qBAAAA,iBAAAA;AAAAA,MAAAA;;MACEA,OAAAF,IAAIG,OAAAA,CAAAA,CAAMD,OAAAA,CAAAA;IADZA,CAAAA;IAIAD,OAAA;;MACE,OAAAD,IAAAI,aAAAA,CAAY,OAAZA;IADF,4BAASJ,IAAT;EALFC,GAAM,IAANA,EAA0BI,oBAA1BJ;AAxCAlB;"}}, {:offset=>{:line=>5806, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/error.rb"], :sourcesContent=>["class ::Exception < `Error`\n  `Opal.prop(self.$$prototype, '$$is_exception', true)`\n  `var stack_trace_limit`\n\n  `Error.stackTraceLimit = 100`\n\n  def self.new(*args)\n    %x{\n      var message   = (args.length > 0) ? args[0] : nil;\n      var error     = new self.$$constructor(message);\n      error.name    = self.$$name;\n      error.message = message;\n      error.cause   = \#{$!};\n      Opal.send(error, error.$initialize, args);\n\n      // Error.captureStackTrace() will use .name and .toString to build the\n      // first line of the stack trace so it must be called after the error\n      // has been initialized.\n      // https://nodejs.org/dist/latest-v6.x/docs/api/errors.html\n      if (Opal.config.enable_stack_trace && Error.captureStackTrace) {\n        // Passing Kernel.raise will cut the stack trace from that point above\n        Error.captureStackTrace(error, stack_trace_limit);\n      }\n\n      return error;\n    }\n  end\n  `stack_trace_limit = self.$new`\n\n  def self.exception(*args)\n    new(*args)\n  end\n\n  def initialize(*args)\n    # using self.message aka @message to retain compatibility with native exception's message property\n    `self.message = (args.length > 0) ? args[0] : nil`\n  end\n\n  %x{\n    // Convert backtrace from any format to Ruby format\n    function correct_backtrace(backtrace) {\n      var new_bt = [], m;\n\n      for (var i = 0; i < backtrace.length; i++) {\n        var loc = backtrace[i];\n        if (!loc || !loc.$$is_string) {\n          /* Do nothing */\n        }\n        /* Chromium format */\n        else if ((m = loc.match(/^    at (.*?) \\((.*?)\\)$/))) {\n          new_bt.push(m[2] + \":in `\" + m[1] + \"'\");\n        }\n        else if ((m = loc.match(/^    at (.*?)$/))) {\n          new_bt.push(m[1] + \":in `undefined'\");\n        }\n        /* Node format */\n        else if ((m = loc.match(/^  from (.*?)$/))) {\n          new_bt.push(m[1]);\n        }\n        /* Mozilla/Apple format */\n        else if ((m = loc.match(/^(.*?)@(.*?)$/))) {\n          new_bt.push(m[2] + ':in `' + m[1] + \"'\");\n        }\n      }\n\n      return new_bt;\n    }\n  }\n\n  def backtrace\n    %x{\n      if (self.backtrace) {\n        // nil is a valid backtrace\n        return self.backtrace;\n      }\n\n      var backtrace = self.stack;\n\n      if (typeof(backtrace) !== 'undefined' && backtrace.$$is_string) {\n        return self.backtrace = correct_backtrace(backtrace.split(\"\\n\"));\n      }\n      else if (backtrace) {\n        return self.backtrace = correct_backtrace(backtrace);\n      }\n\n      return [];\n    }\n  end\n\n  def backtrace_locations\n    %x{\n      if (self.backtrace_locations) return self.backtrace_locations;\n      self.backtrace_locations = \#{backtrace&.map do |loc|\n        ::Thread::Backtrace::Location.new(loc)\n      end}\n      return self.backtrace_locations;\n    }\n  end\n\n  def cause\n    `self.cause || nil`\n  end\n\n  def exception(str = nil)\n    %x{\n      if (str === nil || self === str) {\n        return self;\n      }\n\n      var cloned = \#{clone};\n      cloned.message = str;\n      if (self.backtrace) cloned.backtrace = self.backtrace.$dup();\n      cloned.stack = self.stack;\n      cloned.cause = self.cause;\n      return cloned;\n    }\n  end\n\n  # not using alias message to_s because you need to be able to override to_s and have message use overridden method, won't work with alias\n  def message\n    to_s\n  end\n\n  def full_message(kwargs = nil)\n    unless defined? Hash\n      # We are dealing with an unfully loaded Opal library, so we should\n      # do with as little as we can.\n\n      return \"\#{@message}\\n\#{`self.stack`}\"\n    end\n\n    kwargs = { highlight: $stderr.tty?, order: :top }.merge(kwargs || {})\n    highlight, order = kwargs[:highlight], kwargs[:order]\n\n    ::Kernel.raise ::ArgumentError, \"expected true or false as highlight: \#{highlight}\" unless [true, false].include? highlight\n    ::Kernel.raise ::ArgumentError, \"expected :top or :bottom as order: \#{order}\" unless %i[top bottom].include? order\n\n    if highlight\n      bold_underline = \"\\e[1;4m\"\n      bold = \"\\e[1m\"\n      reset = \"\\e[m\"\n    else\n      bold_underline = bold = reset = ''\n    end\n\n    bt = backtrace.dup\n    bt = caller if !bt || bt.empty?\n    first = bt.shift\n\n    msg = \"\#{first}: \"\n    msg += \"\#{bold}\#{to_s} (\#{bold_underline}\#{self.class}\#{reset}\#{bold})\#{reset}\\n\"\n\n    msg += bt.map { |loc| \"\\tfrom \#{loc}\\n\" }.join\n\n    msg += cause.full_message(highlight: highlight) if cause\n\n    if order == :bottom\n      msg = msg.split(\"\\n\").reverse.join(\"\\n\")\n      msg = \"\#{bold}Traceback\#{reset} (most recent call last):\\n\" + msg\n    end\n\n    msg\n  end\n\n  def inspect\n    as_str = to_s\n    as_str.empty? ? self.class.to_s : \"#<\#{self.class.to_s}: \#{to_s}>\"\n  end\n\n  def set_backtrace(backtrace)\n    %x{\n      var valid = true, i, ii;\n\n      if (backtrace === nil) {\n        self.backtrace = nil;\n        self.stack = '';\n      } else if (backtrace.$$is_string) {\n        self.backtrace = [backtrace];\n        self.stack = '  from ' + backtrace;\n      } else {\n        if (backtrace.$$is_array) {\n          for (i = 0, ii = backtrace.length; i < ii; i++) {\n            if (!backtrace[i].$$is_string) {\n              valid = false;\n              break;\n            }\n          }\n        } else {\n          valid = false;\n        }\n\n        if (valid === false) {\n          \#{::Kernel.raise ::TypeError, 'backtrace must be Array of String'}\n        }\n\n        self.backtrace = backtrace;\n        self.stack = \#{`backtrace`.map { |i| '  from ' + i }}.join(\"\\n\");\n      }\n\n      return backtrace;\n    }\n  end\n\n  def to_s\n    # using self.message aka @message to retain compatibility with native exception's message property\n    (@message && @message.to_s) || self.class.to_s\n  end\nend\n\n# keep the indentation, it makes the exception hierarchy clear\nclass ::ScriptError       < ::Exception; end\nclass ::SyntaxError         < ::ScriptError; end\nclass ::LoadError           < ::ScriptError; end\nclass ::NotImplementedError < ::ScriptError; end\n\nclass ::SystemExit        < ::Exception; end\nclass ::NoMemoryError     < ::Exception; end\nclass ::SignalException   < ::Exception; end\nclass ::Interrupt           < ::SignalException; end\nclass ::SecurityError     < ::Exception; end\nclass ::SystemStackError  < ::Exception; end\n\nclass ::StandardError     < ::Exception; end\nclass ::EncodingError       < ::StandardError; end\nclass ::ZeroDivisionError   < ::StandardError; end\nclass ::NameError           < ::StandardError; end\nclass ::NoMethodError         < ::NameError; end\nclass ::RuntimeError        < ::StandardError; end\nclass ::FrozenError           < ::RuntimeError; end\nclass ::LocalJumpError      < ::StandardError; end\nclass ::TypeError           < ::StandardError; end\nclass ::ArgumentError       < ::StandardError; end\nclass ::UncaughtThrowError    < ::ArgumentError; end\nclass ::IndexError          < ::StandardError; end\nclass ::StopIteration         < ::IndexError; end\nclass ::ClosedQueueError        < ::StopIteration; end\nclass ::KeyError              < ::IndexError; end\nclass ::RangeError          < ::StandardError; end\nclass ::FloatDomainError      < ::RangeError; end\nclass ::IOError             < ::StandardError; end\nclass ::EOFError              < ::IOError; end\nclass ::SystemCallError     < ::StandardError; end\nclass ::RegexpError         < ::StandardError; end\nclass ::ThreadError         < ::StandardError; end\nclass ::FiberError          < ::StandardError; end\n\n::Object.autoload :Errno, 'corelib/error/errno'\n\nclass ::FrozenError < ::RuntimeError\n  attr_reader :receiver\n\n  def initialize(message, receiver: nil)\n    super message\n    @receiver = receiver\n  end\nend\n\nclass ::UncaughtThrowError < ::ArgumentError\n  attr_reader :tag, :value\n\n  def initialize(tag, value = nil)\n    @tag = tag\n    @value = value\n\n    super(\"uncaught throw \#{@tag.inspect}\")\n  end\nend\n\nclass ::NameError\n  attr_reader :name\n\n  def initialize(message, name = nil)\n    super message\n    @name = name\n  end\nend\n\nclass ::NoMethodError\n  attr_reader :args\n\n  def initialize(message, name = nil, args = [])\n    super message, name\n    @args = args\n  end\nend\n\nclass ::StopIteration\n  attr_reader :result\nend\n\nclass ::KeyError\n  def initialize(message, receiver: nil, key: nil)\n    super(message)\n    @receiver = receiver\n    @key = key\n  end\n\n  def receiver\n    @receiver || ::Kernel.raise(::ArgumentError, 'no receiver is available')\n  end\n\n  def key\n    @key || ::Kernel.raise(::ArgumentError, 'no key is available')\n  end\nend\n\nmodule ::JS\n  class Error\n  end\nend\n"], :names=>["<top (required)>", "<class:Exception>", "new", "self", "$!", "exception", "args", "initialize", "backtrace", "backtrace_locations", "block in backtrace_locations", "loc", "block (2 levels) in backtrace_locations", "Thread::Backtrace::Location", "Thread::Backtrace", "Thread", "cause", "str", "clone", "message", "to_s", "full_message", "kwargs", "@message", "$stderr", "tty?", "merge", "$ret_or_1", "[]", "highlight", "order", "include?", "Kernel", "raise", "ArgumentError", "bold_underline", "bold", "reset", "bt", "dup", "empty?", "caller", "first", "shift", "msg", "+", "class", "map", "block in full_message", "block (2 levels) in full_message", "join", "split", "reverse", "inspect", "as_str", "set_backtrace", "TypeError", "block in set_backtrace", "i", "block (2 levels) in set_backtrace", "$ret_or_2", "<class:ScriptError>", "Exception", "<class:SyntaxError>", "ScriptError", "<class:LoadError>", "<class:NotImplementedError>", "<class:SystemExit>", "<class:NoMemoryError>", "<class:SignalException>", "<class:Interrupt>", "SignalException", "<class:SecurityError>", "<class:SystemStackError>", "<class:StandardError>", "<class:EncodingError>