f >(other)\n    `cmp_or_fail(self, other) > 0`\n  end\n\n  def >=(other)\n    `cmp_or_fail(self, other) >= 0`\n  end\n\n  def <(other)\n    `cmp_or_fail(self, other) < 0`\n  end\n\n  def <=(other)\n    `cmp_or_fail(self, other) <= 0`\n  end\n\n  def between?(min, max)\n    return false if self < min\n    return false if self > max\n    true\n  end\n\n  def clamp(min, max = nil)\n    %x{\n      var c, excl;\n\n      if (max === nil) {\n        // We are dealing with a new Ruby 2.7 behaviour that we are able to\n        // provide a single Range argument instead of 2 Comparables.\n\n        if (!Opal.is_a(min, Opal.Range)) {\n          \#{::Kernel.raise ::TypeError, \"wrong argument type \#{min.class} (expected Range)\"}\n        }\n\n        excl = min.excl;\n        max = min.end;\n        min = min.begin;\n\n        if (max !== nil && excl) {\n          \#{::Kernel.raise ::ArgumentError, 'cannot clamp with an exclusive range'}\n        }\n      }\n\n      if (min !== nil && max !== nil && cmp_or_fail(min, max) > 0) {\n        \#{::Kernel.raise ::ArgumentError, 'min argument must be smaller than max argument'}\n      }\n\n      if (min !== nil) {\n        c = cmp_or_fail(self, min);\n\n        if (c == 0) return self;\n        if (c < 0) return min;\n      }\n\n      if (max !== nil) {\n        c = cmp_or_fail(self, max);\n\n        if (c > 0) return max;\n      }\n\n      return self;\n    }\n  end\nend\n"], :names=>["<top (required)>", "<module:Comparable>", ">", "0", "<", "$ret_or_1", "Integer", "Float", "Kernel", "raise", "ArgumentError", "class", "<=>", "==", "other", "self", "equal?", "cmp", ">=", "<=", "between?", "min", "max", "clamp", "TypeError"], :mappings=>"AAAAA,qCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;;;AAEAA;AACAA;;AAEAA,UAAmBC,OAAND,IAAMC,EAAEC,CAAFD,CAAID;AACvBA,UAAmBG,OAANH,IAAMG,EAAED,CAAFC,CAAIH;AACvBA;AACAA;;AAEAA;AACAA;AACAA,MAEQ,CAhBR,CAAA,QAgBa,GAhBb,EAeQI,CAAAA,YAAMJ,GAANI,CAfR,CAAA,IAAA,CAAA,CAAA,QAgBkB,IAhBlB,EAAA,SAAA,CAAA,IAAA,CAAA