OAAAA,CAAOiE,iBAAf,EAA8BpE,kCAAD,GAAA,CAAmCuE,IAAIvE,OAAAA,CAACwB,CAADxB,CAAvC,CAArBG;AACpBH;AACAA,eAAiBb,IAAAmD,gBAAAA,CAAAA,CAActC,OAAAA,CAACuE,IAAIvE,OAAAA,CAACwB,CAADxB,CAALA;AAC/BA;AACAA;AACAA,eAAyBA,MAAR+D,YAAQ/D,MAAAA,EAAC,MAACuE,IAAD,CAADvE;AACzBA;AACAA;IAXEA,CAAAA,IAAAA;;AAcAwE,IAAAA,sBAAAA,kBAAW3E,CAAX2E;AAAAA,MAAAA;;;AAEFA;AACAA,QAAUtE,OAAQC,OAAAA,CAAOsE,oBAAf,EAAgCD,4CAAxBrE;AAClBqE;AACAA;AACAA;IANEA,CAAAA;;AASAxD,IAAAA,kBAAAA,8BAAOC,KAAPD;AAAAA,MAAAA;;;MACE,KAAA,QAAoBa,gBAApB,EAAoCZ,KAApC,CAAA;QAAA,OAAO;MAAP;MAEA,IAAA,QAAAK,CAAAA,YAAA,CAAA,QAAAoD,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAC5D,2BAAD4D,CAAA,CAAA,GAAA,CACG5D,iDADH,IAAA,CAAA,SAAA,CAAA,CAAA2D,CAAA,CAAA,GAAA,CAEG3D,iCAFH,IAAA,CAAA,SAAA,CAAA,CAAA0D,CAAA,CAAA,GAAA,CAGG1D,mCAHH,IAAA,CAAA,SAAA,CAAA,CAAAM,CAAA,CAAA;QAIEN,OAACA,yBAADA;MAJF;QAAAA,OAAA;MAAA;IAHFA,CAAAA;;AAUAO,IAAAA,qBAAAA,iBAAU1B,CAAV0B;AAAAA,MAAAA;;;AAEFA;AACAA,QAAUrB,OAAQC,OAAAA,CAAOsE,oBAAf,EAAgClD,2CAAxBpB;AAClBoB;AACAA;AACAA;IANEA,CAAAA;;AASAsD,IAAAA,mBAAAA,eAAQhF,CAARgF;AAAAA,MAAAA;;;AAEFA;AACAA,QAAU3E,OAAQC,OAAAA,CAAOsE,oBAAf,EAAgCI,yCAAxB1E;AAClB0E;AACAA;AACAA;IANEA,CAAAA;;AASAC,IAAAA,wBAAAA,oBAAAA;AAAAA,MAAAA;;MACEA,OAAGf,YAASe;IADdA,CAAAA;;AAIAxC,IAAAA,8BAAAA,0BAAAA;AAAAA,MAAAA;;;MACEyC,UAAU5F,IAAA2F,UAAAA,CAAAA;MACVxC,OAAqBC,MAArBpD,IAAAsB,QAAAA,CAAAA,CAAM6B,gBAAAA,CAAAA,CAAeC,oBAAAA,EAAAA,EAAAA,EAArBG,cAA2CC,CAA3CD;;QAA2C;QACzCE,OAAAmC,OAAO/E,OAAAA,CAAQgF,UAAPrC,CAACK,MAAAA,CAAAA,CAAMgC,EAAE5F,CAAF4F,CAARhF,EADT0C,CAAqBH;IAFvBD,CAAAA;;AAOAN,IAAAA,qBAAAA,iBAAAA;AAAAA,MAAAA;;MACEA,OAAA7C,IAAAsB,QAAAA,CAAAA,CAAMuB,OAAAA,CAAAA;IADRA,CAAAA;;AAIAL,IAAAA,uBAAAA,mBAAAA;AAAAA,MAAAA;;;AAEFA,iCAAmCA,CAAGoC,YAASpC,GAAZA,CAAgBA,SAAAA,CAAAA,CAASA;;AAE5DA,UAAYxC,IAAAsB,QAAAA,CAAAA,CAAMuB,OAAAA,CAAAA,CAAMiD,WAAAA,CAAAA,CAAQtD;AAChCA,iCAAmCoC,YAASpC;AAC5CA,iCAAmCA,CAAGoC,YAASpC,GAAZA,CAAgBA,SAAAA,CAAAA,CAASA;AAC5DA;AACAA;AACAA;AACAA,QAAyBuD,MAAd/F,IAAAmD,gBAAAA,CAAAA,CAAc4C,QAAAA,EAAAA,EAAAA,EAAdC,cAAwBC,CAAD,EAAIC,CAA3BF;;QAAwB;QAAG;QACzBG,OACbA,4BAA8BF,CAAEE,SAAWD,CAAC1D,SAAAA,CAAAA,EAFjCwD,CAAcD;AAKzBvD;;AAEAA;AACAA;IAlBEA,CAAAA;;AAqBAwC,IAAAA,sBAAAA,kBAAAA;AAAAA,MAAAA;;MACEA,OAAGJ,YAASI;IADdA,CAAAA;;AAIAoB,IAAAA,oBAAAA,aACE,SADFA,CAAAA;;AAIAC,IAAAA,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAAGzB,YAASyB;IADdA,CAAAA;;AAIAC,IAAAA,yBAAAA,qBA/bF,EA+bEA;AAAAA,MAAAA;;;MA/bF;MA+bgB;;AAEhBA;;AAEAA;;AAEAA;AACAA,cAAgBA,CAACA,OAADA,CAASF,MAAAA,CAAAA,CAAME;AAC/BA;AACAA;AACAA;;AAEAA,gBAAkB/E,KAAMC,eAAAA,CAAa8E,OAAnB,EAA6B3D,cAA7B,EAAwC,QAAlCnB,CAA2C8E;;AAEnEA;AACAA,mBAAqB1B,YAAS0B;AAC9BA;AACAA;AACAA;AACAA;AACAA;;AAEAA,oBAAsB1B,YAAS0B;AAC/BA;;AAEAA;AACAA;IA1BEA,CAAAA,IAAAA;IA6BA,aAAM,MAAN,EAAW,IAAX;IACArC,OAAA,aAAM,MAAN,EAAW,QAAX;EAvKFA,GAAAA,WAAAA,EAAAA,IAAAA;AAtTArE;"}}, {:offset=>{:line=>7241, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/string.rb"], :sourcesContent=>["# helpers: coerce_to, respond_to, global_multiline_regexp, prop\n\nrequire 'corelib/comparable'\nrequire 'corelib/regexp'\n\nclass ::String < `String`\n  include ::Comparable\n\n  %x{\n    Opal.prop(\#{self}.$$prototype, '$$is_string', true);\n  }\n\n  def __id__\n    `self.toString()`\n  end\n\n  def self.try_convert(what)\n    ::Opal.coerce_to?(what, ::String, :to_str)\n  end\n\n  def self.new(*args)\n    %x{\n      var str = args[0] || \"\";\n      var opts = args[args.length-1];\n      str = $coerce_to(str, \#{::String}, 'to_str');\n      if (opts && opts.$$is_hash) {\n        if (opts.$$smap.encoding) str = str.$force_encoding(opts.$$smap.encoding);\n      }\n      str = new self.$$constructor(str);\n      if (!str.$initialize.$$pristine) \#{`str`.initialize(*args)};\n      return str;\n    }\n  end\n\n  # Our initialize method does nothing, the string value setup is being\n  # done by String.new. Therefore not all kinds of subclassing will work.\n  # As a rule of thumb, when subclassing String, either make sure to override\n  # .new or make sure that the first argument given to a constructor is\n  # a string we want our subclass-string to hold.\n  def initialize(str = undefined, encoding: nil, capacity: nil)\n  end\n\n  def %(data)\n    if ::Array === data\n      format(self, *data)\n    else\n      format(self, data)\n    end\n  end\n\n  def *(count)\n    %x{\n      count = $coerce_to(count, \#{::Integer}, 'to_int');\n\n      if (count < 0) {\n        \#{::Kernel.raise ::ArgumentError, 'negative argument'}\n      }\n\n      if (count === 0) {\n        return '';\n      }\n\n      var result = '',\n          string = self.toString();\n\n      // All credit for the bit-twiddling magic code below goes to Mozilla\n      // polyfill implementation of String.prototype.repeat() posted here:\n      // https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/String/repeat\n\n      if (string.length * count >= 1 << 28) {\n        \#{::Kernel.raise ::RangeError, 'multiply count must not overflow maximum string size'}\n      }\n\n      for (;;) {\n        if ((count & 1) === 1) {\n          result += string;\n        }\n        count >>>= 1;\n        if (count === 0) {\n          break;\n        }\n        string += string;\n      }\n\n      return result;\n    }\n  end\n\n  def +(other)\n    other = `$coerce_to(\#{other}, \#{::String}, 'to_str')`\n\n    %x{\n      if (other == \"\" && self.$$class === Opal.String) return \#{self};\n      if (self == \"\" && other.$$class === Opal.String) return \#{other};\n      var out = self + other;\n      if (self.encoding === out.encoding && other.encoding === out.encoding) return out;\n      if (self.encoding.name === \"UTF-8\" || other.encoding.name === \"UTF-8\") return out;\n      return Opal.enc(out, self.encoding);\n    }\n  end\n\n  def <=>(other)\n    if other.respond_to? :to_str\n      other = other.to_str.to_s\n\n      `self > other ? 1 : (self < other ? -1 : 0)`\n    else\n      %x{\n        var cmp = \#{other <=> self};\n\n        if (cmp === nil) {\n          return nil;\n        }\n        else {\n          return cmp > 0 ? -1 : (cmp < 0 ? 1 : 0);\n        }\n      }\n    end\n  end\n\n  def ==(other)\n    %x{\n      if (other.$$is_string) {\n        return self.toString() === other.toString();\n      }\n      if ($respond_to(other, '$to_str')) {\n        return \#{other == self};\n      }\n      return false;\n    }\n  end\n\n  def =~(other)\n    %x{\n      if (other.$$is_string) {\n        \#{::Kernel.raise ::TypeError, 'type mismatch: String given'};\n      }\n\n      return \#{other =~ self};\n    }\n  end\n\n  def [](index, length = undefined)\n    %x{\n      var size = self.length, exclude, range;\n\n      if (index.$$is_range) {\n        exclude = index.excl;\n        range   = index;\n        length  = index.end === nil ? -1 : $coerce_to(index.end, \#{::Integer}, 'to_int');\n        index   = index.begin === nil ? 0 : $coerce_to(index.begin, \#{::Integer}, 'to_int');\n\n        if (Math.abs(index) > size) {\n          return nil;\n        }\n\n        if (index < 0) {\n          index += size;\n        }\n\n        if (length < 0) {\n          length += size;\n        }\n\n        if (!exclude || range.end === nil) {\n          length += 1;\n        }\n\n        length = length - index;\n\n        if (length < 0) {\n          length = 0;\n        }\n\n        return self.substr(index, length);\n      }\n\n\n      if (index.$$is_string) {\n        if (length != null) {\n          \#{::Kernel.raise ::TypeError}\n        }\n        return self.indexOf(index) !== -1 ? index : nil;\n      }\n\n\n      if (index.$$is_regexp) {\n        var match = self.match(index);\n\n        if (match === null) {\n          \#{$~ = nil}\n          return nil;\n        }\n\n        \#{$~ = ::MatchData.new(`index`, `match`)}\n\n        if (length == null) {\n          return match[0];\n        }\n\n        length = $coerce_to(length, \#{::Integer}, 'to_int');\n\n        if (length < 0 && -length < match.length) {\n          return match[length += match.length];\n        }\n\n        if (length >= 0 && length < match.length) {\n          return match[length];\n        }\n\n        return nil;\n      }\n\n\n      index = $coerce_to(index, \#{::Integer}, 'to_int');\n\n      if (index < 0) {\n        index += size;\n      }\n\n      if (length == null) {\n        if (index >= size || index < 0) {\n          return nil;\n        }\n        return self.substr(index, 1);\n      }\n\n      length = $coerce_to(length, \#{::Integer}, 'to_int');\n\n      if (length < 0) {\n        return nil;\n      }\n\n      if (index > size || index < 0) {\n        return nil;\n      }\n\n      return self.substr(index, length);\n    }\n  end\n\n  def b\n    `new String(\#{self})`.force_encoding('binary')\n  end\n\n  def capitalize\n    `self.charAt(0).toUpperCase() + self.substr(1).toLowerCase()`\n  end\n\n  def casecmp(other)\n    return nil unless other.respond_to?(:to_str)\n    other = `$coerce_to(other, \#{::String}, 'to_str')`.to_s\n    %x{\n      var ascii_only = /^[\\x00-\\x7F]*$/;\n      if (ascii_only.test(self) && ascii_only.test(other)) {\n        self = self.toLowerCase();\n        other = other.toLowerCase();\n      }\n    }\n    self <=> other\n  end\n\n  def casecmp?(other)\n    %x{\n      var cmp = \#{casecmp(other)};\n      if (cmp === nil) {\n        return nil;\n      } else {\n        return cmp === 0;\n      }\n    }\n  end\n\n  def center(width, padstr = ' ')\n    width  = `$coerce_to(\#{width}, \#{::Integer}, 'to_int')`\n    padstr = `$coerce_to(\#{padstr}, \#{::String}, 'to_str')`.to_s\n\n    if padstr.empty?\n      ::Kernel.raise ::ArgumentError, 'zero width padding'\n    end\n\n    return self if `width <= self.length`\n\n    %x{\n      var ljustified = \#{ljust ((width + `self.length`) / 2).ceil, padstr},\n          rjustified = \#{rjust ((width + `self.length`) / 2).floor, padstr};\n\n      return rjustified + ljustified.slice(self.length);\n    }\n  end\n\n  def chomp(separator = $/)\n    return self if `separator === nil || self.length