n=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/enumerable.rb"], :sourcesContent=>["# helpers: truthy, coerce_to, yield1, yieldX, deny_frozen_access\n\nmodule ::Enumerable\n  %x{\n    function comparableForPattern(value) {\n      if (value.length === 0) {\n        value = [nil];\n      }\n\n      if (value.length > 1) {\n        value = [value];\n      }\n\n      return value;\n    }\n  }\n\n  def all?(pattern = undefined, &block)\n    if `pattern !== undefined`\n      each do |*value|\n        comparable = `comparableForPattern(value)`\n\n        return false unless pattern.public_send(:===, *comparable)\n      end\n    elsif block_given?\n      each do |*value|\n        unless yield(*value)\n          return false\n        end\n      end\n    else\n      each do |*value|\n        unless ::Opal.destructure(value)\n          return false\n        end\n      end\n    end\n\n    true\n  end\n\n  def any?(pattern = undefined, &block)\n    if `pattern !== undefined`\n      each do |*value|\n        comparable = `comparableForPattern(value)`\n\n        return true if pattern.public_send(:===, *comparable)\n      end\n    elsif block_given?\n      each do |*value|\n        if yield(*value)\n          return true\n        end\n      end\n    else\n      each do |*value|\n        if ::Opal.destructure(value)\n          return true\n        end\n      end\n    end\n\n    false\n  end\n\n  def chunk(&block)\n    return to_enum(:chunk) { enumerator_size } unless block_given?\n\n    ::Enumerator.new do |yielder|\n      %x{\n        var previous = nil, accumulate = [];\n\n        function releaseAccumulate() {\n          if (accumulate.length > 0) {\n            \#{yielder.yield(`previous`, `accumulate`)}\n          }\n        }\n\n        self.$each.$$p = function(value) {\n          var key = $yield1(block, value);\n\n          if (key === nil) {\n            releaseAccumulate();\n            accumulate = [];\n            previous = nil;\n          } else {\n            if (previous === nil || previous === key) {\n              accumulate.push(value);\n            } else {\n              releaseAccumulate();\n              accumulate = [value];\n            }\n\n            previous = key;\n          }\n        }\n\n        self.$each();\n\n        releaseAccumulate();\n      }\n    end\n  end\n\n  def chunk_while(&block)\n    ::Kernel.raise ::ArgumentError, 'no block given' unless block_given?\n\n    slice_when { |before, after| !(yield before, after) }\n  end\n\n  def collect(&block)\n    return enum_for(:collect) { enumerator_size } unless block_given?\n\n    %x{\n      var result = [];\n\n      self.$each.$$p = function() {\n        var value = $yieldX(block, arguments);\n\n        result.push(value);\n      };\n\n      self.$each();\n\n      return result;\n    }\n  end\n\n  def collect_concat(&block)\n    return enum_for(:collect_concat) { enumerator_size } unless block_given?\n    map(&block).flatten(1)\n  end\n\n  def compact\n    to_a.compact\n  end\n\n  def count(object = undefined, &block)\n    result = 0\n\n    %x{\n      if (object != null && block !== nil) {\n        \#{warn('warning: given block not used')}\n      }\n    }\n\n    if `object != null`\n      block = ::Kernel.proc do |*args|\n        ::Opal.destructure(args) == object\n      end\n    elsif block.nil?\n      block = ::Kernel.proc { true }\n    end\n\n    each do |*args|\n      `result++` if `$yieldX(block, args)`\n    end\n\n    result\n  end\n\n  def cycle(n = nil, &block)\n    unless block_given?\n      return enum_for(:cycle, n) do\n        if n.nil?\n          respond_to?(:size) ? ::Float::INFINITY : nil\n        else\n          n = ::Opal.coerce_to!(n, ::Integer, :to_int)\n          n > 0 ? enumerator_size * n : 0\n        end\n      end\n    end\n\n    unless n.nil?\n      n = ::Opal.coerce_to! n, ::Integer, :to_int\n\n      return if `n <= 0`\n    end\n\n    %x{\n      var all = [], i, length, value;\n\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)},\n            value = $yield1(block, param);\n\n        all.push(param);\n      }\n\n      self.$each();\n\n      if (all.length === 0) {\n        return nil;\n      }\n\n      if (n === nil) {\n        while (true) {\n          for (i = 0, length = all.length; i < length; i++) {\n            value = $yield1(block, all[i]);\n          }\n        }\n      }\n      else {\n        while (n > 1) {\n          for (i = 0, length = all.length; i < length; i++) {\n            value = $yield1(block, all[i]);\n          }\n\n          n--;\n        }\n      }\n    }\n  end\n\n  def detect(ifnone = undefined, &block)\n    return enum_for :detect, ifnone unless block_given?\n\n    each do |*args|\n      value = ::Opal.destructure(args)\n      if yield(value)\n        return value\n      end\n    end\n\n    %x{\n      if (ifnone !== undefined) {\n        if (typeof(ifnone) === 'function') {\n          return ifnone();\n        } else {\n          return ifnone;\n        }\n      }\n    }\n\n    nil\n  end\n\n  def drop(number)\n    number = `$coerce_to(number, \#{::Integer}, 'to_int')`\n\n    if `number < 0`\n      ::Kernel.raise ::ArgumentError, 'attempt to drop negative size'\n    end\n\n    %x{\n      var result  = [],\n          current = 0;\n\n      self.$each.$$p = function() {\n        if (number <= current) {\n          result.push(\#{::Opal.destructure(`arguments`)});\n        }\n\n        current++;\n      };\n\n      self.$each()\n\n      return result;\n    }\n  end\n\n  def drop_while(&block)\n    return enum_for :drop_while unless block_given?\n\n    %x{\n      var result   = [],\n          dropping = true;\n\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)};\n\n        if (dropping) {\n          var value = $yield1(block, param);\n\n          if (!$truthy(value)) {\n            dropping = false;\n            result.push(param);\n          }\n        }\n        else {\n          result.push(param);\n        }\n      };\n\n      self.$each();\n\n      return result;\n    }\n  end\n\n  def each_cons(n, &block)\n    if `arguments.length != 1`\n      ::Kernel.raise ::ArgumentError, \"wrong number of arguments (\#{`arguments.length`} for 1)\"\n    end\n\n    n = ::Opal.try_convert n, ::Integer, :to_int\n\n    if `n <= 0`\n      ::Kernel.raise ::ArgumentError, 'invalid size'\n    end\n\n    unless block_given?\n      return enum_for(:each_cons, n) do\n        enum_size = enumerator_size\n        if enum_size.nil?\n          nil\n        elsif enum_size == 0 || enum_size < n\n          0\n        else\n          enum_size - n + 1\n        end\n      end\n    end\n\n    %x{\n      var buffer = [];\n\n      self.$each.$$p = function() {\n        var element = \#{::Opal.destructure(`arguments`)};\n        buffer.push(element);\n        if (buffer.length > n) {\n          buffer.shift();\n        }\n        if (buffer.length == n) {\n          $yield1(block, buffer.slice(0, n));\n        }\n      }\n\n      self.$each();\n\n      return self;\n    }\n  end\n\n  def each_entry(*data, &block)\n    unless block_given?\n      return to_enum(:each_entry, *data) { enumerator_size }\n    end\n\n    %x{\n      self.$each.$$p = function() {\n        var item = \#{::Opal.destructure(`arguments`)};\n\n        $yield1(block, item);\n      }\n\n      self.$each.apply(self, data);\n\n      return self;\n    }\n  end\n\n  def each_slice(n, &block)\n    n = `$coerce_to(\#{n}, \#{::Integer}, 'to_int')`\n\n    if `n <= 0`\n      ::Kernel.raise ::ArgumentError, 'invalid slice size'\n    end\n\n    return enum_for(:each_slice, n) { respond_to?(:size) ? (size / n).ceil : nil } unless block_given?\n\n    %x{\n      var slice = []\n\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)};\n\n        slice.push(param);\n\n        if (slice.length === n) {\n          $yield1(block, slice);\n          slice = [];\n        }\n      };\n\n      self.$each();\n\n      // our \"last\" group, if smaller than n then won't have been yielded\n      if (slice.length > 0) {\n        $yield1(block, slice);\n      }\n    }\n\n    self\n  end\n\n  def each_with_index(*args, &block)\n    return enum_for(:each_with_index, *args) { enumerator_size } unless block_given?\n\n    %x{\n      var index = 0;\n\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)};\n\n        block(param, index);\n\n        index++;\n      };\n\n      self.$each.apply(self, args);\n    }\n\n    self\n  end\n\n  def each_with_object(object, &block)\n    return enum_for(:each_with_object, object) { enumerator_size } unless block_given?\n\n    %x{\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)};\n\n        block(param, object);\n      };\n\n      self.$each();\n    }\n\n    object\n  end\n\n  def entries(*args)\n    %x{\n      var result = [];\n\n      self.$each.$$p = function() {\n        result.push(\#{::Opal.destructure(`arguments`)});\n      };\n\n      self.$each.apply(self, args);\n\n      return result;\n    }\n  end\n\n  def filter_map(&block)\n    return enum_for(:filter_map) { enumerator_size } unless block_given?\n\n    map(&block).select(&:itself)\n  end\n\n  def find_all(&block)\n    return enum_for(:find_all) { enumerator_size } unless block_given?\n\n    %x{\n      var result = [];\n\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)},\n            value = $yield1(block, param);\n\n        if ($truthy(value)) {\n          result.push(param);\n        }\n      };\n\n      self.$each();\n\n      return result;\n    }\n  end\n\n  def find_index(object = undefined, &block)\n    return enum_for :find_index if `object === undefined && block === nil`\n\n    %x{\n      if (object != null && block !== nil) {\n        \#{warn('warning: given block not used')}\n      }\n    }\n\n    index = 0\n\n    if `object != null`\n      each do |*value|\n        if ::Opal.destructure(value) == object\n          return index\n        end\n\n        `index += 1`\n      end\n    else\n      each do |*value|\n        if yield(*value)\n          return index\n        end\n\n        `index += 1`\n      end\n    end\n\n    nil\n  end\n\n  def first(number = undefined)\n    if `number === undefined`\n      each do |value|\n        return value\n      end\n    else\n      result = []\n      number = `$coerce_to(number, \#{::Integer}, 'to_int')`\n\n      if `number < 0`\n        ::Kernel.raise ::ArgumentError, 'attempt to take negative size'\n      end\n\n      if `number == 0`\n        return []\n      end\n\n      current = 0\n\n      each do |*args|\n        `result.push(\#{::Opal.destructure(args)})`\n\n        if `number <= ++current`\n          return result\n        end\n      end\n\n      result\n    end\n  end\n\n  def grep(pattern, &block)\n    result = []\n\n    each do |*value|\n      cmp = `comparableForPattern(value)`\n      next unless pattern.__send__(:===, *cmp)\n      if block_given?\n        value = [value] if value.length > 1\n        value = yield(*value)\n      elsif value.length <= 1\n        value = value[0]\n      end\n\n      result.push(value)\n    end\n\n    result\n  end\n\n  def grep_v(pattern, &block)\n    result = []\n\n    each do |*value|\n      cmp = `comparableForPattern(value)`\n      next if pattern.__send__(:===, *cmp)\n      if block_given?\n        value = [value] if value.length > 1\n        value = yield(*value)\n      elsif value.length <= 1\n        value = value[0]\n      end\n\n      result.push(value)\n    end\n\n    result\n  end\n\n  def group_by(&block)\n    return enum_for(:group_by) { enumerator_size } unless block_given?\n\n    hash = {}\n\n    %x{\n      var result;\n\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)},\n            value = $yield1(block, param);\n\n        \#{(hash[`value`] ||= []) << `param`};\n      }\n\n      self.$each();\n\n      if (result !== undefined) {\n        return result;\n      }\n    }\n\n    hash\n  end\n\n  def include?(obj)\n    each do |*args|\n      if ::Opal.destructure(args) == obj\n        return true\n      end\n    end\n\n    false\n  end\n\n  def inject(object = undefined, sym = undefined, &block)\n    %x{\n      var result = object;\n\n      if (block !== nil && sym === undefined) {\n        self.$each.$$p = function() {\n          var value = \#{::Opal.destructure(`arguments`)};\n\n          if (result === undefined) {\n            result = value;\n            return;\n          }\n\n          value = $yieldX(block, [result, value]);\n\n          result = value;\n        };\n      }\n      else {\n        if (sym === undefined) {\n          if (!\#{::Symbol === object}) {\n            \#{::Kernel.raise ::TypeError, \"\#{object.inspect} is not a Symbol\"};\n          }\n\n          sym    = object;\n          result = undefined;\n        }\n\n        self.$each.$$p = function() {\n          var value = \#{::Opal.destructure(`arguments`)};\n\n          if (result === undefined) {\n            result = value;\n            return;\n          }\n\n          result = \#{`result`.__send__ sym, `value`};\n        };\n      }\n\n      self.$each();\n\n      return result == undefined ? nil : result;\n    }\n  end\n\n  def lazy\n    ::Enumerator::Lazy.new(self, enumerator_size) do |enum, *args|\n      enum.yield(*args)\n    end\n  end\n\n  def enumerator_size\n    respond_to?(:size) ? size : nil\n  end\n\n  def max(n = undefined, &block)\n    %x{\n      if (n === undefined || n === nil) {\n        var result, value;\n\n        self.$each.$$p = function() {\n          var item = \#{::Opal.destructure(`arguments`)};\n\n          if (result === undefined) {\n            result = item;\n            return;\n          }\n\n          if (block !== nil) {\n            value = $yieldX(block, [item, result]);\n          } else {\n            value = \#{`item` <=> `result`};\n          }\n\n          if (value === nil) {\n            \#{::Kernel.raise ::ArgumentError, 'comparison failed'};\n          }\n\n          if (value > 0) {\n            result = item;\n          }\n        }\n\n        self.$each();\n\n        if (result === undefined) {\n          return nil;\n        } else {\n          return result;\n        }\n      }\n\n      n = $coerce_to(n, \#{::Integer}, 'to_int');\n    }\n\n    sort(&block).reverse.first(n)\n  end\n\n  def max_by(n = nil, &block)\n    return enum_for(:max_by, n) { enumerator_size } unless block\n\n    unless n.nil?\n      return sort_by(&block).reverse.take n\n    end\n\n    %x{\n      var result,\n          by;\n\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)},\n            value = $yield1(block, param);\n\n        if (result === undefined) {\n          result = param;\n          by     = value;\n          return;\n        }\n\n        if (\#{`value` <=> `by`} > 0) {\n          result = param\n          by     = value;\n        }\n      };\n\n      self.$each();\n\n      return result === undefined ? nil : result;\n    }\n  end\n\n  def min(n = nil, &block)\n    unless n.nil?\n      if block_given?\n        return sort { |a, b| yield a, b }.take n\n      else\n        return sort.take n\n      end\n    end\n\n    %x{\n      var result;\n\n      if (block !== nil) {\n        self.$each.$$p = function() {\n          var param = \#{::Opal.destructure(`arguments`)};\n\n          if (result === undefined) {\n            result = param;\n            return;\n          }\n\n          var value = block(param, result);\n\n          if (value === nil) {\n            \#{::Kernel.raise ::ArgumentError, 'comparison failed'};\n          }\n\n          if (value < 0) {\n            result = param;\n          }\n        };\n      }\n      else {\n        self.$each.$$p = function() {\n          var param = \#{::Opal.destructure(`arguments`)};\n\n          if (result === undefined) {\n            result = param;\n            return;\n          }\n\n          if (\#{::Opal.compare(`param`, `result`)} < 0) {\n            result = param;\n          }\n        };\n      }\n\n      self.$each();\n\n      return result === undefined ? nil : result;\n    }\n  end\n\n  def min_by(n = nil, &block)\n    return enum_for(:min_by, n) { enumerator_size } unless block\n\n    unless n.nil?\n      return sort_by(&block).take n\n    end\n\n    %x{\n      var result,\n          by;\n\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)},\n            value = $yield1(block, param);\n\n        if (result === undefined) {\n          result = param;\n          by     = value;\n          return;\n        }\n\n        if (\#{`value` <=> `by`} < 0) {\n          result = param\n          by     = value;\n        }\n      };\n\n      self.$each();\n\n      return result === undefined ? nil : result;\n    }\n  end\n\n  def minmax(&block)\n    block ||= ::Kernel.proc { |a, b| a <=> b }\n\n    %x{\n      var min = nil, max = nil, first_time = true;\n\n      self.$each.$$p = function() {\n        var element = \#{::Opal.destructure(`arguments`)};\n        if (first_time) {\n          min = max = element;\n          first_time = false;\n        } else {\n          var min_cmp = \#{block.call(`min`, `element`)};\n\n          if (min_cmp === nil) {\n            \#{::Kernel.raise ::ArgumentError, 'comparison failed'}\n          } else if (min_cmp > 0) {\n            min = element;\n          }\n\n          var max_cmp = \#{block.call(`max`, `element`)};\n\n          if (max_cmp === nil) {\n            \#{::Kernel.raise ::ArgumentError, 'comparison failed'}\n          } else if (max_cmp < 0) {\n            max = element;\n          }\n        }\n      }\n\n      self.$each();\n\n      return [min, max];\n    }\n  end\n\n  def minmax_by(&block)\n    return enum_for(:minmax_by) { enumerator_size } unless block\n\n    %x{\n      var min_result = nil,\n          max_result = nil,\n          min_by,\n          max_by;\n\n      self.$each.$$p = function() {\n        var param = \#{::Opal.destructure(`arguments`)},\n            value = $yield1(block, param);\n\n        if ((min_by === undefined) || \#{`value` <=> `min_by`} < 0) {\n          min_result = param;\n          min_by     = value;\n        }\n\n        if ((max_by === undefined) || \#{`value` <=> `max_by`} > 0) {\n          max_result = param;\n          max_by     = value;\n        }\n      };\n\n      self.$each();\n\n      return [min_result, max_result];\n    }\n  end\n\n  def none?(pattern = undefined, &block)\n    if `pattern !== undefined`\n      each do |*value|\n        comparable = `comparableForPattern(value)`\n\n        return false if pattern.public_send(:===, *comparable)\n      end\n    elsif block_given?\n      each do |*value|\n        if yield(*value)\n          return false\n        end\n      end\n    else\n      each do |*value|\n        item = ::Opal.destructure(value)\n\n        return false if item\n      end\n    end\n\n    true\n  end\n\n  def one?(pattern = undefined, &block)\n    count = 0\n\n    if `pattern !== undefined`\n      each do |*value|\n        comparable = `comparableForPattern(value)`\n\n        if pattern.public_send(:===, *comparable)\n          count += 1\n          return false if count > 1\n        end\n      end\n    elsif block_given?\n      each do |*value|\n        next unless yield(*value)\n        count += 1\n\n        return false if count > 1\n      end\n    else\n      each do |*value|\n        next unless ::Opal.destructure(value)\n        count += 1\n\n        return false if count > 1\n      end\n    end\n\n    count == 1\n  end\n\n  def partition(&block)\n    return enum_for(:partition) { enumerator_size } unless block_given?\n\n    %x{\n      var truthy = [], falsy = [], result;\n\n      self.$each.$$p = function() {\n 