AAM,SAAN,EAAc,UAAd;IACA,aAAM,QAAN,EAAa,QAAb;IACA,aAAM,QAAN,EAAa,UAAb;IACApP,OAAA,aAAM,MAAN,EAAW,SAAX;EAnwCFA,GAAO,IAAPA;AAFAD;"}}, {:offset=>{:line=>11165, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/enumerator/arithmetic_sequence.rb"], :sourcesContent=>["class ::Enumerator\n  class self::ArithmeticSequence < self\n    `Opal.prop(self.$$prototype, '$$is_arithmetic_seq', true)`\n\n    `var inf = Infinity`\n\n    # @private\n    def initialize(range, step = undefined, creation_method = :step)\n      @creation_method = creation_method\n      if range.is_a? ::Array\n        @step_arg1, @step_arg2, @topfx, @bypfx = *range\n        @receiver_num = step\n        @step = 1\n\n        @range = if @step_arg2\n                   @step = @step_arg2\n                   (@receiver_num..@step_arg1)\n                 elsif @step_arg1\n                   (@receiver_num..@step_arg1)\n                 else\n                   (@receiver_num..nil)\n                 end\n      else\n        @skipped_arg = true unless step\n        @range, @step = range, step || 1\n      end\n\n      @object = self\n\n      ::Kernel.raise ArgumentError, \"step can't be 0\" if @step == 0\n      unless @step.respond_to? :to_int\n        ::Kernel.raise ArgumentError, \"no implicit conversion of \#{@step.class} \" \\\n                                      'into Integer'\n      end\n    end\n\n    attr_reader :step\n\n    def begin\n      @range.begin\n    end\n\n    def end\n      @range.end\n    end\n\n    def exclude_end?\n      @range.exclude_end?\n    end\n\n    # @private\n    def _lesser_than_end?(val)\n      end_ = self.end || `inf`\n      if step > 0\n        exclude_end? ? val < end_ : val <= end_\n      else\n        exclude_end? ? val > end_ : val >= end_\n      end\n    end\n\n    # @private\n    def _greater_than_begin?(val)\n      begin_ = self.begin || -`inf`\n      if step > 0\n        val > begin_\n      else\n        val < begin_\n      end\n    end\n\n    def first(count = undefined)\n      iter = self.begin || -`inf`\n\n      return _lesser_than_end?(iter) ? iter : nil unless count\n\n      out = []\n\n      while _lesser_than_end?(iter) && count > 0\n        out << iter\n        iter += step\n        count -= 1\n      end\n\n      out\n    end\n\n    def each(&block)\n      return self unless block_given?\n\n      case self.begin\n      when nil\n        ::Kernel.raise TypeError, \"nil can't be coerced into Integer\"\n      end\n\n      iter = self.begin || -`inf`\n\n      while _lesser_than_end?(iter)\n        yield iter\n        iter += step\n      end\n      self\n    end\n\n    def last(count = undefined)\n      case self.end\n      when `inf`, -`inf`\n        ::Kernel.raise ::FloatDomainError, self.end\n      when nil\n        ::Kernel.raise ::RangeError, 'cannot get the last element of endless arithmetic sequence'\n      end\n\n      iter = self.end - ((self.end - self.begin) % step)\n      iter -= step unless _lesser_than_end?(iter)\n\n      return _greater_than_begin?(iter) ? iter : nil unless count\n\n      out = []\n\n      while _greater_than_begin?(iter) && count > 0\n        out << iter\n        iter -= step\n        count -= 1\n      end\n\n      out.reverse\n    end\n\n    def size\n      step_sign = step > 0 ? 1 : -1\n\n      if !_lesser_than_end?(self.begin)\n        0\n      elsif [-`inf`, `inf`].include?(step)\n        1\n      elsif [-`inf` * step_sign, nil].include?(self.begin) ||\n            [`inf` * step_sign, nil].include?(self.end)\n        `inf`\n      else\n        iter = self.end - ((self.end - self.begin) % step)\n        iter -= step unless _lesser_than_end?(iter)\n        ((iter - self.begin) / step).abs.to_i + 1\n      end\n    end\n\n    def ==(other)\n      self.class == other.class &&\n        self.begin == other.begin &&\n        self.end == other.end &&\n        step == other.step &&\n        exclude_end? == other.exclude_end?\n    end\n\n    def hash\n      [self.begin, self.end, step, exclude_end?].hash\n    end\n\n    def inspect\n      if @receiver_num\n        args = if @step_arg2\n                 \"(\#{@topfx}\#{@step_arg1.inspect}, \#{@bypfx}\#{@step_arg2.inspect})\"\n               elsif @step_arg1\n                 \"(\#{@topfx}\#{@step_arg1.inspect})\"\n               end\n\n        \"(\#{@receiver_num.inspect}.\#{@creation_method}\#{args})\"\n      else\n        args = unless @skipped_arg\n                 \"(\#{@step})\"\n               end\n        \"((\#{@range.inspect}).\#{@creation_method}\#{args})\"\n      end\n    end\n\n    alias === ==\n    alias eql? ==\n  end\nend\n"], :names=>["<top (required)>", "<class:Enumerator>", "<class:self::ArithmeticSequence>", "initialize", "range", "step", "creation_method", "@creation_method", "is_a?", "Array", "@step_arg1", "@step_arg2", "@topfx", "@bypfx", "@receiver_num", "@step", "1", "@range", "@skipped_arg", "$ret_or_1", "@object", "self", "0", "Kernel", "raise", "ArgumentError", "respond_to?", "class", "attr_reader", "begin", "end", "exclude_end?", "_lesser_than_end?", "val", "end_", ">", "<", "<=", ">=", "_greater_than_begin?", "begin_", "-@", "first", "count", "iter", "out", "<<", "+", "-", "each", "block_given?", "TypeError", "last", "FloatDomainError", "RangeError", "%", "reverse", "size", "step_sign", "-1", "include?", "*", "/", "abs", "to_i", "==", "other", "$ret_or_2", "$ret_or_3", "$ret_or_4", "hash", "inspect", "args"], :mappings=>"AAAAA,yDAAAA,gBAAAA;EAAAA;;EAAAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MACGA;MAEAA;;AAGDC,MAAAA,0BAAAA,sBAAeC,KAAD,EAAQC,IAAR,EAA0BC,eAAxCH;AAAAA,QAAAA;;;;QAAwC,+CAAkB;QACxDI,uBAAmBD;QACnB,IAAA,QAAGF,KAAKI,UAAAA,CAAOC,YAAPD,CAAR,CAAA;;UACE,KAAyC,UAAA,MAACJ,KAAD,CAAA,CAAzC,EAAAM,CAAAA,iBAAA,6BAAAA,CAAA,EAAYC,CAAAA,iBAAZ,6BAAYA,CAAZ,EAAwBC,CAAAA,aAAxB,6BAAwBA,CAAxB,EAAgCC,CAAAA,aAAhC,6BAAgCA,CAAhC;UACAC,oBAAgBT;UAChBU,YAAQC;UAERC,aAAS,CAAA,QAAGN,cAAH,CAAA,GAAA,CACER,CAAAY,CAAAA,YAAQJ,cAARI,GACC,gBAAAD,iBAAA,EAAeJ,cAAf,QADDP,CADF,IAGA,CAAA