;QACEA,OAAA,CAACjD,IAAIQ,OAAAA,CAAAA,CAAL,EAAaR,IAAIS,KAAAA,CAAAA,CAAjB,EAAuBT,IAAAhB,MAAAA,CAAAA,CAAvB,EAA6BgB,IAAAU,iBAAAA,CAAAA,CAA7B,CAA0CuC,MAAAA,CAAAA;MAD5CA,CAAAA;;AAIAC,MAAAA,uBAAAA,mBAAAA;AAAAA,QAAAA;;QACE,IAAA,QAAGzD,iBAAH,CAAA;;UACE0D,OAAO,CAAA,QAAG7D,cAAH,CAAA,GAAA,CACG4D,GAAD,GAAA,CAAI3D,UAAJ,CAAA,GAAA,CAAaF,cAAU6D,SAAAA,CAAAA,CAAvB,CAAA,GAAgCA,IAAhC,GAAA,CAAoC1D,UAApC,CAAA,GAAA,CAA6CF,cAAU4D,SAAAA,CAAAA,CAAvD,CAAA,GAAgEA,GADlE,IAEA,CAAA,QAAM7D,cAAN,CAAA,GAAA,CACG6D,GAAD,GAAA,CAAI3D,UAAJ,CAAA,GAAA,CAAaF,cAAU6D,SAAAA,CAAAA,CAAvB,CAAA,GAAgCA,GADlC,IAAA,GAAA,CAFA;UAMPA,OAACA,GAAD,GAAA,CAAIzD,iBAAayD,SAAAA,CAAAA,CAAjB,CAAA,GAA0BA,GAA1B,GAAA,CAA6BhE,oBAA7B,CAAA,GAAA,CAAgDiE,IAAhD,CAAA,GAAqDD;QAPvD;;UASEC,OAAO,CAAA,QAAOtD,gBAAP,CAAA,GAAA,CAAA,GAAA,IAAA,CACGqD,GAAD,GAAA,CAAIxD,SAAJ,CAAA,GAAUwD,GADZ,CAAA;UAGPA,OAACA,IAAD,GAAA,CAAKtD,UAAMsD,SAAAA,CAAAA,CAAX,CAAA,GAAoBA,IAApB,GAAA,CAAwBhE,oBAAxB,CAAA,GAAA,CAA2CiE,IAA3C,CAAA,GAAgDD;QAZlD;MADFA,CAAAA;MAiBA,aAAM,KAAN,EAAU,IAAV;MACArE,OAAA,aAAM,MAAN,EAAW,IAAX;IA7KFA,GAAMmB,IAANnB,EAAiCmB,IAAjCnB;EADFD,GAAM,IAANA,EAAAA,IAAAA;AAAAD;"}}, {:offset=>{:line=>11390, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/enumerator/chain.rb"], :sourcesContent=>["# helpers: deny_frozen_access\n\nclass ::Enumerator\n  class self::Chain < self\n    def initialize(*enums)\n      `$deny_frozen_access(self)`\n\n      @enums = enums\n      @iterated = []\n      @object = self\n    end\n\n    def each(*args, &block)\n      return to_enum(:each, *args) { size } unless block_given?\n\n      @enums.each do |enum|\n        @iterated << enum\n        enum.each(*args, &block)\n      end\n\n      self\n    end\n\n    def size(*args)\n      accum = 0\n      @enums.each do |enum|\n        size = enum.size(*args)\n        return size if [nil, ::Float::INFINITY].include? size\n        accum += size\n      end\n      accum\n    end\n\n    def rewind\n      @iterated.reverse_each do |enum|\n        enum.rewind if enum.respond_to? :rewind\n      end\n      @iterated = []\n      self\n    end\n\n    def inspect\n      \"#<Enumerator::Chain: \#{@enums.inspect}>\"\n    end\n  end\nend\n"], :names=>["<top (required)>", "<class:Enumerator>", "<class:self::Chain>", "initialize", "@enums", "enums", "@iterated", "@object", "self", "each", "block_given?", "to_enum", "args", "block in each", "block (2 levels) in each", "size", "enum$", "<<", "block", "to_proc", "accum", "0", "block in size", "block (2 levels) in size", "Float::INFINITY", "Float", "include?", "+", "rewind", "reverse_each", "block in rewind", "respond_to?", "block (2 levels) in rewind", "inspect"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;;IACEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;;AACEC,MAAAA,0BAAAA,sBAJJ,EAIIA;AAAAA,QAAAA;;;QAJJ;QAImB;QACZA;QAEDC,aAASC;QACTC,gBAAY;QACZH,OAAAI,CAAAA,cAAUC,IAAVD;MALFJ,CAAAA,IAAAA;;AAQAM,MAAAA,oBAAAA,gBAZJ,EAYIA;AAAAA,QAAAA;;QAAAA;;;QAZJ;QAYa;QACP,KAA6CC,eAA7C;UAAA,OAAOC,MAAAH,IAAAG,WAAAA,EAAA,CAAQ,MAAR,CAAA,QAAe,MAACC,IAAD,CAAf,CAAAD,EAAAE,aAAAA,EAAAC;;YAAwBA,OAAAN,IAAAO,MAAAA,CAAAA,CAAxBF,CAAAA,GAAAA,SAAAA,CAAAF;QAAP;QAEMF,MAANL,UAAMK,QAAAA,EAAAA,EAAAA,EAANI,aAAgBG,KAAhBH,EAAAC;AAAAA;;;UAAgB;UACdR,aAAUW,OAAAA,CAAGD,KAAHC;UACVH,OAAIL,MAAJO,KAAIP,QAAAA,EAAM,MAACG,IAAD,CAANH,EAAcS,KAADC,SAAAA,CAAAA,CAAbV,EAFNI,CAAAA,GAAAA,SAAAA,CAAMJ;QAKNA,OAAAD;MARFC,CAAAA,IAAAA;;AAWAM,MAAAA,oBAAAA,gBAvBJ,EAuBIA,GAAAA,MAAAA,IAAAA,8BAAAA;AAAAA,QAAAA;;;QAvBJ;QAuBa;QACPK,QAAQC;QACFZ,MAANL,UAAMK,QAAAA,EAAAA,EAAAA,EAANa,aAAgBN,KAAhBM,EAAAC;;;UAAgB;UACdR,OAAWA,MAAJC,KAAID,QAAAA,EAAM,MAACH,IAAD,CAANG;UACX,IAAA,QAAe,CAAC,GAAD,EAAMS,IAAAC,YAAAD,aAAN,CAAwBE,aAAAA,CAAUX,IAAVW,CAAvC,CAAA;YAAA,SAAA,QAAOX,IAAP;UAAA;UACAQ,OAAAH,CAAAA,QAAMO,SAANP,KAAMO,EAAGZ,IAAHY,CAANP,EAHFE,CAAAA,GAAAA,gBAAAA,CAAMb;QAKNM,OAAAK,MAPFL;UAAAA;UAAAA;QAAAA;MAAAA,CAAAA,IAAAA;;AAUAa,MAAAA,sBAAAA,kBAAAA;AAAAA,QAAAA;;;QACWC,MAATvB,aAASuB,gBAAAA,EAAAA,EAAAA,EAATC,aAA2Bd,KAA3Bc;;UAA2B;UACzB,IAAA,QAAed,KAAIe,gBAAAA,CAAa,QAAbA,CAAnB,CAAA;YAAAC,OAAAhB,KAAIY,QAAAA,CAAAA;UAAJ;YAnCRI,OAAA;UAmCQ,EADFF,CAASD;QAGTvB,gBAAY;QACZsB,OAAApB;MALFoB,CAAAA;MAQA1B,OAAA+B,uBAAAA,mBAAAA;AAAAA,QAAAA;;QACEA,OAACA,uBAAD,GAAA,CAAwB7B,UAAM6B,SAAAA,CAAAA,CAA9B,CAAA,GAAuCA;MADzCA,CAAAA;IAtCF/B,GAAMM,IAANN,EAAoBM,IAApBN;EADFD,GAAM,IAANA,EAAAA,IAAAA;AAFAD;"}}, {:offset=>{:line=>11486, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/enumerator/generator.rb"], :sourcesContent=>["# helpers: deny_frozen_access\n\nclass Enumerator\n  class Generator\n    include ::Enumerable\n\n    def initialize(&block)\n      `$deny_frozen_access(self)`\n\n      ::Kernel.raise ::LocalJumpError, 'no block given' unless block\n\n      @block = block\n    end\n\n    def each(*args, &block)\n      yielder = Yielder.new(&block)\n\n      %x{\n        try {\n          args.unshift(\#{yielder});\n\n          Opal.yieldX(\#{@block}, args);\n        }\n        catch (e) {\n          if (e && e.$thrower_type == \"breaker\") {\n            return e.$v;\n          }\n          else {\n            throw e;\n          }\n        }\n      }\n\n      self\n    end\n  end\nend\n"], :names=>["<top (required)>", "<class:Enumerator>", "<class:Generator>", "self", "include", "Enumerable", "initialize", "block", "Kernel", "raise", "LocalJumpError", "@block", "each", "yielder", "new", "Yielder", "to_proc"], :mappings=>"AAAAA,+CAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;AAAAA;;MACEC,IAAAC,SAAAA,CAAQC,iBAARD;;AAEAE,MAAAA,0BAAAA,sBAAAA;AAAAA,QAAAA;;QAAAA;;;QACGA;QAED,KAAA,QAAyDC,KAAzD,CAAA;UAAAC,OAAQC,OAAAA,CAAOC,qBAAf,EAAiCJ,gBAAzBG;QAAR;QAEAH,OAAAK,CAAAA,aAASJ,KAATI;MALFL,CAAAA;MAQAJ,OAAAU,oBAAAA,gBAdJ,EAcIA;AAAAA,QAAAA;;QAAAA;;;QAdJ;QAca;QACPC,UAAiBC,MAAPC,aAAOD,OAAAA,EAAAA,EAAAA,EAAMP,KAADS,SAAAA,CAAAA,CAALF;;AAGvBF;AACAA,uBAAyBC,OAAQD;;AAEjCA,sBAAwBD,UAAOC;AAC/BA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;QAEMA,OAAAT;MAnBFS,CAAAA,IAAAA;IAXFV,GAAAA,WAAAA,EAAAA,IAAAA;EADFD,GAAAA,WAAAA,EAAAA,IAAAA;AAFAD;"}}, {:offset=>{:line=>11545, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/enumerator/lazy.rb"], :sourcesContent=>["# helpers: truthy, coerce_to, yield1, yieldX, deny_frozen_access\n\nclass ::Enumerator\n  class self::Lazy < self\n    class self::StopLazyError < ::Exception; end\n\n    def self.for(object, *)\n      lazy = super\n      `lazy.enumerator = object`\n      lazy\n    end\n\n    def initialize(object, size = nil, &block)\n      `$deny_frozen_access(self)`\n\n      unless block_given?\n        ::Kernel.raise ::ArgumentError, 'tried to call lazy new without a block'\n      end\n\n      @enumerator = object\n\n      super size do |yielder, *each_args|\n        object.each(*each_args) do |*args|\n          %x{\n            args.unshift(\#{yielder});\n\n            $yieldX(block, args);\n          }\n        end\n      rescue StopLazyError\n        nil\n      end\n    end\n\n    def lazy\n      self\n    end\n\n    def collect(&block)\n      unless block\n        ::Kernel.raise ::ArgumentError, 'tried to call lazy map without a block'\n      end\n\n      Lazy.new(self, enumerator_size) do |enum, *args|\n        %x{\n          var value = $yieldX(block, args);\n\n          \#{enum.yield `value`};\n        }\n      end\n    end\n\n    def collect_concat(&block)\n      unless block\n        ::Kernel.raise ::ArgumentError, 'tried to call lazy map without a block'\n      end\n\n      Lazy.new(self, nil) do |enum, *args|\n        %x{\n          var value = $yieldX(block, args);\n\n          if (\#{`value`.respond_to? :force} && \#{`value`.respond_to? :each}) {\n            \#{`value`.each { |v| enum.yield v }}\n          }\n          else {\n            var array = \#{::Opal.try_convert `value`, ::Array, :to_ary};\n\n            if (array === nil) {\n              \#{enum.yield `value`};\n            }\n            else {\n              \#{`value`.each { |v| enum.yield v }};\n            }\n          }\n        }\n      end\n    end\n\n    def drop(n)\n      n = `$coerce_to(\#{n}, \#{::Integer}, 'to_int')`\n\n      if n < 0\n        ::Kernel.raise ::ArgumentError, 'attempt to drop negative size'\n      end\n\n      current_size = enumerator_size\n      set_size     = if ::Integer === current_size\n                       n < current_size ? n : current_size\n                     else\n                       current_size\n                     end\n\n      dropped = 0\n      Lazy.new(self, set_size) do |enum, *args|\n        if dropped < n\n          dropped += 1\n        else\n          enum.yield(*args)\n        end\n      end\n    end\n\n    def drop_while(&block)\n      unless block\n        ::Kernel.raise ::ArgumentError, 'tried to call lazy drop_while without a block'\n      end\n\n      succeeding = true\n      Lazy.new(self, nil) do |enum, *args|\n        if succeeding\n          %x{\n            var value = $yieldX(block, args);\n\n            if (!$truthy(value)) {\n              succeeding = false;\n\n              \#{enum.yield(*args)};\n            }\n          }\n        else\n          enum.yield(*args)\n        end\n      end\n    end\n\n    def enum_for(method = :each, *args, &block)\n      self.class.for(self, method, *args, &block)\n    end\n\n    def find_all(&block)\n      unless block\n        ::Kernel.raise ::ArgumentError, 'tried to call lazy select without a block'\n      end\n\n      Lazy.new(self, nil) do |enum, *args|\n        %x{\n          var value = $yieldX(block, args);\n\n          if ($truthy(value)) {\n            \#{enum.yield(*args)};\n          }\n        }\n      end\n    end\n\n    def grep(pattern, &block)\n      if block\n        Lazy.new(self, nil) do |enum, *args|\n          %x{\n            var param = \#{::Opal.destructure(args)},\n                value = \#{pattern === `param`};\n\n            if ($truthy(value)) {\n              value = $yield1(block, param);\n\n              \#{enum.yield `$yield1(block, param)`};\n            }\n          }\n        end\n      else\n        Lazy.new(self, nil) do |enum, *args|\n          %x{\n            var param = \#{::Opal.destructure(args)},\n                value = \#{pattern === `param`};\n\n            if ($truthy(value)) {\n              \#{enum.yield `param`};\n            }\n          }\n        end\n      end\n    end\n\n    def reject(&block)\n      unless block\n        ::Kernel.raise ::ArgumentError, 'tried to call lazy reject without a block'\n      end\n\n      Lazy.new(self, nil) do |enum, *args|\n        %x{\n          var value = $yieldX(block, args);\n\n          if (!$truthy(value)) {\n            \#{enum.yield(*args)};\n          }\n        }\n      end\n    end\n\n    def take(n)\n      n = `$coerce_to(\#{n}, \#{::Integer}, 'to_int')`\n\n      if n < 0\n        ::Kernel.raise ::ArgumentError, 'attempt to take negative size'\n      end\n\n      current_size = enumerator_size\n      set_size     = if ::Integer === current_size\n                       n < current_size ? n : current_size\n                     else\n                       current_size\n                     end\n\n      taken = 0\n      Lazy.new(self, set_size) do |enum, *args|\n        if taken < n\n          enum.yield(*args)\n          taken += 1\n        else\n          ::Kernel.raise StopLazyError\n        end\n      end\n    end\n\n    def take_while(&block)\n      unless block\n        ::Kernel.raise ::ArgumentError, 'tried to call lazy take_while without a block'\n      end\n\n      Lazy.new(self, nil) do |enum, *args|\n        %x{\n          var value = $yieldX(block, args);\n\n          if ($truthy(value)) {\n            \#{enum.yield(*args)};\n          }\n          else {\n            \#{::Kernel.raise StopLazyError};\n          }\n        }\n      end\n    end\n\n    def inspect\n      \"#<\#{self.class}: \#{@enumerator.inspect}>\"\n    end\n\n    alias force to_a\n    alias filter find_all\n    alias flat_map collect_concat\n    alias map collect\n    alias select find_all\n    alias to_enum enum_for\n  end\nend