AIC,CAA1BiI;;QAAuB;QAAG;QAAGC,OAAAnI,CAAEjF,MAAAA,CAAEkF,CAAFlF,EAA/BmN,CAAMrI;IADRmI,CAAAA,IAAAA;;AAIAC,IAAAA,oBAAAA,gBAAAA;AAAAA,MAAAA;;MAAAA;;;;AAEFA,iBAAmB,YAAA,EAAGA;;AAEtBA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA,aAAeA,CAACA,IAADA,CAAMG,QAAAA,CAAAA,CAAQH;AAC7BA;IAvBEA,CAAAA;;AA0BAI,IAAAA,qBAAAA,6BAAAA;AAAAA,MAAAA;;MAAAA;;;;AAEFA;;AAEAA,gDAAkD,YAAA,EAAGA;;AAErDA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;IArBEA,CAAAA;;AAwBAC,IAAAA,uBAAAA,mBA90EF,EA80EEA;AAAAA,MAAAA;;;MA90EF;MA80Ec;;AAEdA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;IApBEA,CAAAA,IAAAA;;AAuBAC,IAAAA,yBAAAA,qBAr2EF,EAq2EEA;AAAAA,MAAAA;;;MAr2EF;MAq2EgB;MACZC,MAAM;MAEFlJ,MAAJ4B,IAAI5B,QAAAA,EAAAA,EAAAA,EAAJmJ,cAAcC,IAAdD,EAAAE;;;QAAc;QACZ,IAAA,QAAGD,IAAIE,UAAAA,CAAOvH,YAAPuH,CAAP,CAAA;;UACEC,SAAYH,IAAII,KAAAA,CAAAA,CAAKH,2BAA6BD,IAAII,KAAAA,CAAAA,CAAKH,EAAIxO,cAAUwO;UACzEhC,QAAW+B,IAAIK,OAAAA,CAAAA,CAAOJ,0BAA4BD,IAAIK,OAAAA,CAAAA,CAAOJ,EAAIxO,cAAUwO;;AAGnFA;AACAA;AACAA,YAAc,OAAA,GAAKA;AACnBA;AACAA;;AAGAA;AACAA;AACAA;AACAA,cAAgBD,IAAIlH,iBAAAA,CAAAA,CAAcmH,IAAMD,IAAII,KAAAA,CAAAA,CAAKH;AACjDA;AACAA;AACAA;AACAA,YAAc,OAAA,GAAKA;AACnBA;AACAA;UAEQA,OAAKK,MAALrC,KAAKqC,QAAAA,EAAAA,CAAMH,MAANG,CAAAA,EAALL,cAAsBd,CAAtBc,EAAAM;;;YAAsB;YAAGA,OAAAT,GAAInN,OAAAA,CAAG/B,IAAAkD,IAAAA,CAAGqL,CAAHrL,CAAHnB,EAA7BsN,CAAAA,GAAAA,SAAAA,CAAKK;QAvBP;;UAyBEnB,IAAKc,iBAAmBxO,cAAUwO;UAClCA,OAAAH,GAAInN,OAAAA,CAAG/B,IAAAkD,IAAAA,CAAGqL,CAAHrL,CAAHnB;QA1BN,EADFoN,CAAAA,GAAAA,SAAAA,CAAInJ;MA+BJiJ,OAAAC;IAlCFD,CAAAA,IAAAA;;AAqCAW,IAAAA,mBAAAA,eA14EF,EA04EEA;AAAAA,MAAAA;;MAAAA;;;MA14EF;MA04EU;;AAEVA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA,oBACU,CAAA,QAAAvB,CAAAA,YAAAjN,KAAMC,eAAAA,CAAauO,CAAnB,EAAuBtO,YAAvB,EAAgC,QAA1BD,CAANgN,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CACAjN,KAAM8C,eAAAA,CAAa0L,CAAnB,EAAuBC,iBAAvB,EAAqC,SAArC,EAA+C,MAAzC3L,CADN,CAAA,CAED7D,MAAAA,CAAAA,CAAMuP;AACfA;;AAEAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;IA5CEA,CAAAA,IAAAA;IA+CAE,MAAI9P,IAAJ8P,gBAAAA,qBAAmBC,KAAnBD;AAAAA;;AAEFA;AACAA;AACAA;AACAA;IALEA,CAAAA;;AAQAE,IAAAA,kCAAAA,8BAAAA;AAAAA,MAAAA;;MAAAA;MACEA,OAAKpF,MAAL,OAAA5K,IAAA,EAAA,0EAAA,sBAAA,EAAA,EAAA,EAAA,MAAA,CAAK4K,UAAAA,EAAAA,EAAAA,EAALqF,cAAgBC,IAAhBD,EAAAE;;;QAAgB;QAAM,IAAA,QAAA9B,CAAAA,YAAC8B,cAAgBD,IAAKC,CAAtB9B,CAAA,CAAA;UAAA8B,OAAA;QAAA;UAA4BA,OAAAD,IAAK/N,OAAAA,CAAGgO,SAAHhO;QAAjC,EAAtB8N,CAAKrF;IADPoF,CAAAA;;AAIAI,IAAAA,oBAAAA,gBAr8EF,EAq8EEA;AAAAA,MAAAA;;;MAr8EF;MAq8EW;MACPA,OAAA1P,OAAQI,OAAAA,CAAOsP,iEAAPtP;IADVsP,CAAAA,IAAAA;IAIA,aAAM,QAAN,EAAa,MAAb;IACA,aAAM,QAAN,EAAa,QAAb;IACA,aAAM,SAAN,EAAc,SAAd;IACA,aAAM,KAAN,EAAU,SAAV;IACA,aAAM,MAAN,EAAW,UAAX;IACA,aAAM,SAAN,EAAc,SAAd;IACA,aAAM,MAAN,EAAW,QAAX;IACA,aAAM,OAAN,EAAY,IAAZ;IACA,aAAM,MAAN,EAAW,SAAX;IAEAhP,KAAMiP,UAAAA,CAAUrQ,IAAAsQ,iBAAAA,CAAAA,CAAhB,EAAiC,UAA3BD;IACNnQ,OAAAkB,KAAMiP,UAAAA,CAAUrQ,IAAhB,EAAsB,yBAAtB,EAAgD,gBAA1CqQ;EA/8ERnQ,GAAM,IAANA,EAAiBH,KAAjBG;AALAH;"}}, {:offset=>{:line=>15582, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/hash.rb"], :sourcesContent=>["# helpers: yield1, hash, hash_init, hash_get, hash_put, hash_delete, deny_frozen_access, freeze\n\nrequire 'corelib/enumerable'\n\n# ---\n# Internal properties:\n#\n# - $$map         [JS::Object<String => hash-bucket>] the hash table for ordinary keys\n# - $$smap        [JS::Object<String => hash-bucket>] the hash table for string keys\n# - $$keys        [Array<hash-bucket>] the list of all keys\n# - $$proc        [Proc,null,nil] the default proc used for missing keys\n# - hash-bucket   [JS::Object] an element of a linked list that holds hash values, keys are `{key:,key_hash:,value:,next:}`\nclass ::Hash\n  include ::Enumerable\n\n  # Mark all hash instances as valid hashes (used to check keyword args, etc)\n  `self.$$prototype.$$is_hash = true`\n\n  def self.[](*argv)\n    %x{\n      var hash, argc = argv.length, i;\n\n      if (argc === 1) {\n        hash = \#{::Opal.coerce_to?(argv[0], ::Hash, :to_hash)};\n        if (hash !== nil) {\n          return \#{allocate.merge!(`hash`)};\n        }\n\n        argv = \#{::Opal.coerce_to?(argv[0], ::Array, :to_ary)};\n        if (argv === nil) {\n          \#{::Kernel.raise ::ArgumentError, 'odd number of arguments for Hash'}\n        }\n\n        argc = argv.length;\n        hash = \#{allocate};\n\n        for (i = 0; i < argc; i++) {\n          if (!argv[i].$$is_array) continue;\n          switch(argv[i].length) {\n          case 1:\n            hash.$store(argv[i][0], nil);\n            break;\n          case 2:\n            hash.$store(argv[i][0], argv[i][1]);\n            break;\n          default:\n            \#{::Kernel.raise ::ArgumentError, \"invalid number of elements (\#{`argv[i].length`} for 1..2)\"}\n          }\n        }\n\n        return hash;\n      }\n\n      if (argc % 2 !== 0) {\n        \#{::Kernel.raise ::ArgumentError, 'odd number of arguments for Hash'}\n      }\n\n      hash = \#{allocate};\n\n      for (i = 0; i < argc; i += 2) {\n        hash.$store(argv[i], argv[i + 1]);\n      }\n\n      return hash;\n    }\n  end\n\n  def self.allocate\n    %x{\n      var hash = new self.$$constructor();\n\n      $hash_init(hash);\n\n      hash.$$none = nil;\n      hash.$$proc = nil;\n\n      return hash;\n    }\n  end\n\n  def self.try_convert(obj)\n    ::Opal.coerce_to?(obj, ::Hash, :to_hash)\n  end\n\n  def initialize(defaults = undefined, &block)\n    %x{\n      $deny_frozen_access(self);\n\n      if (defaults !== undefined && block !== nil) {\n        \#{::Kernel.raise ::ArgumentError, 'wrong number of arguments (1 for 0)'}\n      }\n      self.$$none = (defaults === undefined ? nil : defaults);\n      self.$$proc = block;\n\n      return self;\n    }\n  end\n\n  def ==(other)\n    %x{\n      if (self === other) {\n        return true;\n      }\n\n      if (!other.$$is_hash) {\n        return false;\n      }\n\n      if (self.$$keys.length !== other.$$keys.length) {\n        return false;\n      }\n\n      for (var i = 0, keys = self.$$keys, length = keys.length, key, value, other_value; i < length; i++) {\n        key = keys[i];\n\n        if (key.$$is_string) {\n          value = self.$$smap[key];\n          other_value = other.$$smap[key];\n        } else {\n          value = key.value;\n          other_value = $hash_get(other, key.key);\n        }\n\n        if (other_value === undefined || !value['$eql?'](other_value)) {\n          return false;\n        }\n      }\n\n      return true;\n    }\n  end\n\n  def >=(other)\n    other = ::Opal.coerce_to!(other, ::Hash, :to_hash)\n\n    %x{\n      if (self.$$keys.length < other.$$keys.length) {\n        return false\n      }\n    }\n\n    result = true\n\n    other.each do |other_key, other_val|\n      val = fetch(other_key, `null`)\n\n      %x{\n        if (val == null || val !== other_val) {\n          result = false;\n          return;\n        }\n      }\n    end\n\n    result\n  end\n\n  def >(other)\n    other = ::Opal.coerce_to!(other, ::Hash, :to_hash)\n\n    %x{\n      if (self.$$keys.length <= other.$$keys.length) {\n        return false\n      }\n    }\n\n    self >= other\n  end\n\n  def <(other)\n    other = ::Opal.coerce_to!(other, ::Hash, :to_hash)\n    other > self\n  end\n\n  def <=(other)\n    other = ::Opal.coerce_to!(other, ::Hash, :to_hash)\n    other >= self\n  end\n\n  def [](key)\n    %x{\n      var value = $hash_get(self, key);\n\n      if (value !== undefined) {\n        return value;\n      }\n\n      return self.$default(key);\n    }\n  end\n\n  def []=(key, value)\n    %x{\n      $deny_frozen_access(self);\n\n      $hash_put(self, key, value);\n      return value;\n    }\n  end\n\n  def assoc(object)\n    %x{\n      for (var i = 0, keys = self.$$keys, length = keys.length, key; i < length; i++) {\n        key = keys[i];\n\n        if (key.$$is_string) {\n          if (\#{`key` == object}) {\n            return [key, self.$$smap[key]];\n          }\n        } else {\n          if (\#{`key.key` == object}) {\n            return [key.key, key.value];\n          }\n        }\n      }\n\n      return nil;\n    }\n  end\n\n  def clear\n    %x{\n      $deny_frozen_access(self);\n\n      $hash_init(self);\n      return self;\n    }\n  end\n\n  def clone\n    %x{\n      var hash = new self.$$class();\n\n      $hash_init(hash);\n      Opal.hash_clone(self, hash);\n\n      return hash;\n    }\n  end\n\n  def compact\n    %x{\n      var hash = $hash();\n\n      for (var i = 0, keys = self.$$keys, length = keys.length, key, value, obj; i < length; i++) {\n        key = keys[i];\n\n        if (key.$$is_string) {\n          value = self.$$smap[key];\n        } else {\n          value = key.value;\n          key = key.key;\n        }\n\n        if (value !== nil) {\n          $hash_put(hash, key, value);\n        }\n      }\n\n      return hash;\n    }\n  end\n\n  def compact!\n    %x{\n      $deny_frozen_access(self);\n\n      var changes_were_made = false;\n\n      for (var i = 0, keys = self.$$keys, length = keys.length, key, value, obj; i < length; i++) {\n        key = keys[i];\n\n        if (key.$$is_string) {\n          value = self.$$smap[key];\n        } else {\n          value = key.value;\n          key = key.key;\n        }\n\n        if (value === nil) {\n          if ($hash_delete(self, key) !== undefined) {\n            changes_were_made = true;\n            length--;\n            i--;\n          }\n        }\n      }\n\n      return changes_were_made ? self : nil;\n    }\n  end\n\n  def compare_by_identity\n    %x{\n      $deny_frozen_access(self);\n\n      var i, ii, key, keys = self.$$keys, identity_hash;\n\n      if (self.$$by_identity) return self;\n      if (self.$$keys.length === 0) {\n        self.$$by_identity = true\n        return self;\n      }\n\n      identity_hash = \#{ {}.compare_by_identity };\n      for(i = 0, ii = keys.length; i < ii; i++) {\n        key = keys[i];\n        if (!key.$$is_string) key = key.key;\n        $hash_put(identity_hash, key, $hash_get(self, key));\n      }\n\n      self.$$by_identity = true;\n      self.$$map = identity_hash.$$map;\n      self.$$smap = identity_hash.$$smap;\n      return self;\n    }\n  end\n\n  def compare_by_identity?\n    `self.$$by_identity === true`\n  end\n\n  def default(key = undefined)\n    %x{\n      if (key !== undefined && self.$$proc !== nil && self.$$proc !== undefined) {\n        return self.$$proc.$call(self, key);\n      }\n      if (self.$$none === undefined) {\n        return nil;\n      }\n      return self.$$none;\n    }\n  end\n\n  def default=(object)\n    %x{\n      $deny_frozen_access(self);\n\n      self.$$proc = nil;\n      self.$$none = object;\n\n      return object;\n    }\n  end\n\n  def default_proc\n    %x{\n      if (self.$$proc !== undefined) {\n        return self.$$proc;\n      }\n      return nil;\n    }\n  end\n\n  def default_proc=(default_proc)\n    %x{\n      $deny_frozen_access(self);\n\n      var proc = default_proc;\n\n      if (proc !== nil) {\n        proc = \#{::Opal.coerce_to!(`proc`, ::Proc, :to_proc)};\n\n        if (\#{`proc`.lambda?} && \#{`proc`.arity.abs} !== 2) {\n          \#{::Kernel.raise ::TypeError, 'default_proc takes two arguments'};\n        }\n      }\n\n      self.$$none = nil;\n      self.$$proc = proc;\n\n      return default_proc;\n    }\n  end\n\n  def delete(key, &block)\n    %x{\n      $deny_frozen_access(self);\n      var value = $hash_delete(self, key);\n\n      if (value !== undefined) {\n        return value;\n      }\n\n      if (block !== nil) {\n        return \#{yield key};\n      }\n\n      return nil;\n    }\n  end\n\n  def delete_if(&block)\n    return enum_for(:delete_if) { size } unless block\n\n    %x{\n      $deny_frozen_access(self);\n\n      for (var i = 0, keys = self.$$keys, length = keys.length, key, value, obj; i < length; i++) 