AA;;AAyBAG,IAAAA,iCAAAA,wCAAAA;AAAAA,MAAAA;;MAAAA;;;MACE,KAAA,QAAoDpF,KAApD,CAAA;QAAA,OAAOC,MAAA3D,IAAA2D,YAAAA,EAAAA,CAAS,mBAATA,CAAAA,EAAAoF,cAAAA,EAAAC;;UAA+BA,OAAAhJ,IAAA8D,MAAAA,CAAAA,CAA/BiF,CAAAA,GAAAA,SAAAA,CAAApF;MAAP;;AAGJmF;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;;AAEAA;AACAA;;AAEAA;AACAA;IAtBEA,CAAAA;;AAyBAG,IAAAA,sBAAAA,kBAAAA;AAAAA,MAAAA;;;AAEFA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;IAfEA,CAAAA;IAkBA,aAAM,KAAN,EAAU,OAAV;IACA,aAAM,WAAN,EAAgB,MAAhB;IACA,aAAM,MAAN,EAAW,IAAX;IACA,aAAM,QAAN,EAAa,QAAb;IACA,aAAM,SAAN,EAAc,SAAd;IACA,aAAM,UAAN,EAAe,UAAf;IACA,aAAM,SAAN,EAAc,SAAd;IACA,aAAM,KAAN,EAAU,OAAV;IACA,aAAM,MAAN,EAAW,UAAX;IACA,aAAM,SAAN,EAAc,UAAd;IACA,aAAM,MAAN,EAAW,QAAX;IACA,aAAM,OAAN,EAAY,KAAZ;IACA,aAAM,MAAN,EAAW,SAAX;IACA,aAAM,QAAN,EAAa,QAAb;IACA,aAAM,QAAN,EAAa,YAAb;IACA/I,OAAA,aAAM,WAAN,EAAgB,SAAhB;EAhtCFA,GAAM,IAANA,EAAAA,IAAAA;AAZAH;"}}, {:offset=>{:line=>17081, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/number.rb"], :sourcesContent=>["require 'corelib/numeric'\n\nclass ::Number < ::Numeric\n  ::Opal.bridge(`Number`, self)\n  `Opal.prop(self.$$prototype, '$$is_number', true)`\n  `self.$$is_number_class = true`\n\n  class << self\n    def allocate\n      ::Kernel.raise ::TypeError, \"allocator undefined for \#{name}\"\n    end\n\n    undef :new\n  end\n\n  def coerce(other)\n    %x{\n      if (other === nil) {\n        \#{::Kernel.raise ::TypeError, \"can't convert \#{other.class} into Float\"};\n      }\n      else if (other.$$is_string) {\n        return [\#{::Kernel.Float(other)}, self];\n      }\n      else if (\#{other.respond_to?(:to_f)}) {\n        return [\#{::Opal.coerce_to!(other, ::Float, :to_f)}, self];\n      }\n      else if (other.$$is_number) {\n        return [other, self];\n      }\n      else {\n        \#{::Kernel.raise ::TypeError, \"can't convert \#{other.class} into Float\"};\n      }\n    }\n  end\n\n  def __id__\n    `(self * 2) + 1`\n  end\n\n  def +(other)\n    %x{\n      if (other.$$is_number) {\n        return self + other;\n      }\n      else {\n        return \#{__coerced__ :+, other};\n      }\n    }\n  end\n\n  def -(other)\n    %x{\n      if (other.$$is_number) {\n        return self - other;\n      }\n      else {\n        return \#{__coerced__ :-, other};\n      }\n    }\n  end\n\n  def *(other)\n    %x{\n      if (other.$$is_number) {\n        return self * other;\n      }\n      else {\n        return \#{__coerced__ :*, other};\n      }\n    }\n  end\n\n  def /(other)\n    %x{\n      if (other.$$is_number) {\n        return self / other;\n      }\n      else {\n        return \#{__coerced__ :/, other};\n      }\n    }\n  end\n\n  def %(other)\n    %x{\n      if (other.$$is_number) {\n        if (other == -Infinity) {\n          return other;\n        }\n        else if (other == 0) {\n          \#{::Kernel.raise ::ZeroDivisionError, 'divided by 0'};\n        }\n        else if (other < 0 || self < 0) {\n          return (self % other + other) % other;\n        }\n        else {\n          return self % other;\n        }\n      }\n      else {\n        return \#{__coerced__ :%, other};\n      }\n    }\n  end\n\n  def &(other)\n    %x{\n      if (other.$$is_number) {\n        return self & other;\n      }\n      else {\n        return \#{__coerced__ :&, other};\n      }\n    }\n  end\n\n  def |(other)\n    %x{\n      if (other.$$is_number) {\n        return self | other;\n      }\n      else {\n        return \#{__coerced__ :|, other};\n      }\n    }\n  end\n\n  def ^(other)\n    %x{\n      if (other.$$is_number) {\n        return self ^ other;\n      }\n      else {\n        return \#{__coerced__ :^, other};\n      }\n    }\n  end\n\n  def <(other)\n    %x{\n      if (other.$$is_number) {\n        return self < other;\n      }\n      else {\n        return \#{__coerced__ :<, other};\n      }\n    }\n  end\n\n  def <=(other)\n    %x{\n      if (other.$$is_number) {\n        return self <= other;\n      }\n      else {\n        return \#{__coerced__ :<=, other};\n      }\n    }\n  end\n\n  def >(other)\n    %x{\n      if (other.$$is_number) {\n        return self > other;\n      }\n      else {\n        return \#{__coerced__ :>, other};\n      }\n    }\n  end\n\n  def >=(other)\n    %x{\n      if (other.$$is_number) {\n        return self >= other;\n      }\n      else {\n        return \#{__coerced__ :>=, other};\n      }\n    }\n  end\n\n  # Compute the result of the spaceship operator inside its own function so it\n  # can be optimized despite a try/finally construct.\n  %x{\n    var spaceship_operator = function(self, other) {\n      if (other.$$is_number) {\n        if (isNaN(self) || isNaN(other)) {\n          return nil;\n        }\n\n        if (self > other) {\n          return 1;\n        } else if (self < other) {\n          return -1;\n        } else {\n          return 0;\n        }\n      }\n      else {\n        return \#{__coerced__ :<=>, `other`};\n      }\n    }\n  }\n\n  def <=>(other)\n    `spaceship_operator(self, other)`\n  rescue ::ArgumentError\n    nil\n  end\n\n  def <<(count)\n    count = ::Opal.coerce_to! count, ::Integer, :to_int\n\n    `\#{count} > 0 ? self << \#{count} : self >> -\#{count}`\n  end\n\n  def >>(count)\n    count = ::Opal.coerce_to! count, ::Integer, :to_int\n\n    `\#{count} > 0 ? self >> \#{count} : self << -\#{count}`\n  end\n\n  def [](bit)\n    bit = ::Opal.coerce_to! bit, ::Integer, :to_int\n\n    %x{\n      if (\#{bit} < 0) {\n        return 0;\n      }\n      if (\#{bit} >= 32) {\n        return \#{ self } < 0 ? 1 : 0;\n      }\n      return (self >> \#{bit}) & 1;\n    }\n  end\n\n  def +@\n    `+self`\n  end\n\n  def -@\n    `-self`\n  end\n\n  def ~\n    `~self`\n  end\n\n  def **(other)\n    if ::Integer === other\n      if !(::Integer === self) || other > 0\n        `Math.pow(self, other)`\n      else\n        ::Rational.new(self, 1)**other\n      end\n    elsif self < 0 && (::Float === other || ::Rational === other)\n      ::Complex.new(self, 0)**other.to_f\n    elsif `other.$$is_number != null`\n      `Math.pow(self, other)`\n    else\n      __coerced__ :**, other\n    end\n  end\n\n  def ==(other)\n    %x{\n      if (other.$$is_number) {\n        return self.valueOf() === other.valueOf();\n      }\n      else if (\#{other.respond_to? :==}) {\n        return \#{other == self};\n      }\n      else {\n        return false;\n      }\n    }\n  end\n\n  alias === ==\n\n  def abs\n    `Math.abs(self)`\n  end\n\n  def abs2\n    `Math.abs(self * self)`\n  end\n\n  def allbits?(mask)\n    mask = ::Opal.coerce_to! mask, ::Integer, :to_int\n    `(self & mask) == mask`\n  end\n\n  def anybits?(mask)\n    mask = ::Opal.coerce_to! mask, ::Integer, :to_int\n    `(self & mask) !== 0`\n  end\n\n  def angle\n    return self if nan?\n\n    %x{\n      if (self == 0) {\n        if (1 / self > 0) {\n          return 0;\n        }\n        else {\n          return Math.PI;\n        }\n      }\n      else if (self < 0) {\n        return Math.PI;\n      }\n      else {\n        return 0;\n      }\n    }\n  end\n\n  def bit_length\n    unless ::Integer === self\n      ::Kernel.raise ::NoMethodError.new(\"undefined method `bit_length` for \#{self}:Float\", 'bit_length')\n    end\n\n    %x{\n      if (self === 0 || self === -1) {\n        return 0;\n      }\n\n      var result = 0,\n          value  = self < 0 ? ~self : self;\n\n      while (value != 0) {\n        result   += 1;\n        value  >>>= 1;\n      }\n\n      return result;\n    }\n  end\n\n  def ceil(ndigits = 0)\n    %x{\n      var f = \#{to_f};\n\n      if (f % 1 === 0 && ndigits >= 0) {\n        return f;\n      }\n\n      var factor = Math.pow(10, ndigits),\n          result = Math.ceil(f * factor) / factor;\n\n      if (f % 1 === 0) {\n        result = Math.round(result);\n      }\n\n      return result;\n    }\n  end\n\n  def chr(encoding = undefined)\n    `Opal.enc(String.fromCharCode(self), encoding || \"BINARY\")`\n  end\n\n  def denominator\n    if nan? || infinite?\n      1\n    else\n      super\n    end\n  end\n\n  def downto(stop, &block)\n    unless block_given?\n      return enum_for(:downto, stop) do\n        ::Kernel.raise ::ArgumentError, \"comparison of \#{self.class} with \#{stop.class} failed\" unless ::Numeric === stop\n        stop > self ? 0 : self - stop + 1\n      end\n    end\n\n    %x{\n      if (!stop.$$is_number) {\n        \#{::Kernel.raise ::ArgumentError, \"comparison of \#{self.class} with \#{stop.class} failed\"}\n      }\n      for (var i = self; i >= stop; i--) {\n        block(i);\n      }\n    }\n\n    self\n  end\n\n  def equal?(other)\n    self == other || `isNaN(self) && isNaN(other)`\n  end\n\n  def even?\n    `self % 2 === 0`\n  end\n\n  def floor(ndigits = 0)\n    %x{\n      var f = \#{to_f};\n\n      if (f % 1 === 0 && ndigits >= 0) {\n        return f;\n      }\n\n      var factor = Math.pow(10, ndigits),\n          result = Math.floor(f * factor) / factor;\n\n      if (f % 1 === 0) {\n        result = Math.round(result);\n      }\n\n      return result;\n    }\n  end\n\n  def gcd(other)\n    unless ::Integer === other\n      ::Kernel.raise ::TypeError, 'not an integer'\n    end\n\n    %x{\n      var min = Math.abs(self),\n          max = Math.abs(other);\n\n      while (min > 0) {\n        var tmp = min;\n\n        min = max % min;\n        max = tmp;\n      }\n\n      return max;\n    }\n  end\n\n  def gcdlcm(other)\n    [gcd(other), lcm(other)]\n  end\n\n  def integer?\n    `self % 1 === 0`\n  end\n\n  def is_a?(klass)\n    return true if klass == ::Integer && ::Integer === self\n    return true if klass == ::Integer && ::Integer === self\n    return true if klass == ::Float && ::Float === self\n\n    super\n  end\n\n  def instance_of?(klass)\n    return true if klass == ::Integer && ::Integer === self\n    return true if klass == ::Integer && ::Integer === self\n    return true if klass == ::Float && ::Float === self\n\n    super\n  end\n\n  def lcm(other)\n    unless ::Integer === other\n      ::Kernel.raise ::TypeError, 'not an integer'\n    end\n\n    %x{\n      if (self == 0 || other == 0) {\n        return 0;\n      }\n      else {\n        return Math.abs(self * other / \#{gcd(other)});\n      }\n    }\n  end\n\n  def next\n    `self + 1`\n  end\n\n  def nobits?(mask)\n    mask = ::Opal.coerce_to! mask, ::Integer, :to_int\n    `(self & mask) == 0`\n  end\n\n  def nonzero?\n    `self == 0 ? nil : self`\n  end\n\n  def numerator\n    if nan? || infinite?\n      self\n    else\n      super\n    end\n  end\n\n  def odd?\n    `self % 2 !== 0`\n  end\n\n  def ord\n    self\n  end\n\n  def pow(b, m = undefined)\n    %x{\n      if (self == 0) {\n        \#{::Kernel.raise ::ZeroDivisionError, 'divided by 0'}\n      }\n\n      if (m === undefined) {\n        return \#{self**b};\n      } else {\n        if (!(\#{::Integer === b})) {\n          \#{::Kernel.raise ::TypeError, 'Integer#pow() 2nd argument not allowed unless a 1st argument is integer'}\n        }\n\n        if (b < 0) {\n          \#{::Kernel.raise ::TypeError, 'Integer#pow() 1st argument cannot be negative when 2nd argument specified'}\n        }\n\n        if (!(\#{::Integer === m})) {\n          \#{::Kernel.raise ::TypeError, 'Integer#pow() 2nd argument not allowed unless all arguments are integers'}\n        }\n\n        if (m === 0) {\n          \#{::Kernel.raise ::ZeroDivisionError, 'divided by 0'}\n        }\n\n        return \#{(self**b) % m}\n      }\n    }\n  end\n\n  def pred\n    `self - 1`\n  end\n\n  def quo(other)\n    if ::Integer === self\n      super\n    else\n      self / other\n    end\n  end\n\n  def rationalize(eps = undefined)\n    %x{\n      if (arguments.length > 1) {\n        \#{::Kernel.raise ::ArgumentError, \"wrong number of arguments (\#{`arguments.length`} for 0..1)\"};\n      }\n    }\n\n    if ::Integer === self\n      ::Rational.new(self, 1)\n    elsif infinite?\n      ::Kernel.raise ::FloatDomainError, 'Infinity'\n    elsif nan?\n      ::Kernel.raise ::FloatDomainError, 'NaN'\n    elsif `eps == null`\n      f, n  = ::Math.frexp self\n      f     = ::Math.ldexp(f, ::Float::MANT_DIG).to_i\n      n    -= ::Float::MANT_DIG\n\n      ::Rational.new(2 * f, 1 << (1 - n)).rationalize(::Rational.new(1, 1 << (1 - n)))\n    else\n      to_r.rationalize(eps)\n    end\n  end\n\n  def remainder(y)\n    self - y * (self / y).truncate\n  end\n\n  def round(ndigits = undefined)\n    if ::Integer === self\n      if `ndigits == null`\n        return self\n      end\n\n      if ::Float === ndigits && ndigits.infinite?\n        ::Kernel.raise ::RangeError, 'Infinity'\n      end\n\n      ndigits = ::Opal.coerce_to!(ndigits, ::Integer, :to_int)\n\n      if ndigits < ::Integer::MIN\n        ::Kernel.raise ::RangeError, 'out of bounds'\n      end\n\n      if `ndigits >= 0`\n        return self\n      end\n\n      ndigits = -ndigits\n\n      %x{\n        if (0.415241 * ndigits - 0.125 > \#{size}) {\n          return 0;\n        }\n\n        var f = Math.pow(10, ndigits),\n            x = Math.floor((Math.abs(self) + f / 2) / f) * f;\n\n        return self < 0 ? -x : x;\n      }\n    else\n      if nan? && `ndigits == null`\n        ::Kernel.raise ::FloatDomainError, 'NaN'\n      end\n\n      ndigits = ::Opal.coerce_to!(`ndigits || 0`, ::Integer, :to_int)\n\n      if ndigits <= 0\n        if nan?\n          ::Kernel.raise ::RangeError, 'NaN'\n        elsif infinite?\n          ::Kernel.raise ::FloatDomainError, 'Infinity'\n        end\n      elsif ndigits == 0\n        return `Math.round(self)`\n      elsif nan? || infinite?\n        return self\n      end\n\n      _, exp = ::Math.frexp(self)\n\n      if ndigits >= (::Float::DIG + 2) - (exp > 0 ? exp / 4 : exp / 3 - 1)\n        return self\n      end\n\n      if ndigits < -(exp > 0 ? exp / 3 + 1 : exp / 4)\n        return 0\n      end\n\n      `Math.round(self * Math.pow(10, ndigits)) / Math.pow(10, ndigits)`\n    end\n  end\n\n  def times(&block)\n    return enum_for(:times) { self } unless block\n\n    %x{\n      for (var i = 0; i < self; i++) {\n        block(i);\n      }\n    }\n\n    self\n  end\n\n  def to_f\n    self\n  end\n\n  def to_i\n    `self < 0 ? Math.ceil(self) : Math.floor(self)`\n  end\n\n  def to_r\n    if ::Integer === self\n      ::Rational.new(self, 1)\n    else\n      f, e  = ::Math.frexp(self)\n      f     = ::Math.ldexp(f, ::Float::MANT_DIG).to_i\n      e    -= ::Float::MANT_DIG\n\n      (f * (::Float::RADIX**e)).to_r\n    end\n  end\n\n  def to_s(base = 10)\n    base = ::Opal.coerce_to! base, ::Integer, :to_int\n\n    if base < 2 || base > 36\n      ::Kernel.raise ::ArgumentError, \"invalid radix \#{base}\"\n    end\n\n    # Don't lose the negative zero\n    if self == 0 && `1/self === -Infinity`\n      return '-0.0'\n    end\n\n    `self.toString(base)`\n  end\n\n  def truncate(ndigits = 0)\n    %x{\n      var f = \#{to_f};\n\n      if (f % 1 === 0 && ndigits >= 0) {\n        return f;\n      }\n\n      var factor = Math.pow(10, ndigits),\n          result = parseInt(f * factor, 10) / factor;\n\n      if (f % 1 === 0) {\n        result = Math.round(result);\n      }\n\n      return result;\n    }\n  end\n\n  def digits(base = 10)\n    if self < 0\n      ::Kernel.raise ::Math::DomainError, 'out of domain'\n    end\n\n    base = ::Opal.coerce_to! base, ::Integer, :to_int\n\n    if base < 2\n      ::Kernel.raise ::ArgumentError, \"invalid radix \#{base}\"\n    end\n\n    %x{\n      if (self != parseInt(self)) \#{::Kernel.raise ::NoMethodError, \"undefined method `digits' for \#{inspect}\"}\n\n      var value = self, result = [];\n\n      if (self == 0) {\n        return [0];\n      }\n\n      while (value != 0) {\n        result.push(value % base);\n        value = parseInt(value / base, 10);\n      }\n\n      return result;\n    }\n  end\n\n  def divmod(other)\n    if nan? || other.nan?\n      ::Kernel.raise ::FloatDomainError, 'NaN'\n    elsif infinite?\n      ::Kernel.raise ::FloatDomainError, 'Infinity'\n    else\n      super\n    end\n  end\n\n  def upto(stop, &block)\n    unless block_given?\n      return enum_for(:upto, stop) do\n        ::Kernel.raise ::ArgumentError, \"comparison of \#{self.class} with \#{stop.class} failed\" unless ::Numeric === stop\n        stop < self ? 0 : stop - self + 1\n      end\n    end\n\n    %x{\n      if (!stop.$$is_number) {\n        \#{::Kernel.raise ::ArgumentError, \"comparison of \#{self.class} with \#{stop.class} failed\"}\n      }\n      for (var i = self; i <= stop; i++) {\n        block(i);\n      }\n    }\n\n    self\n  end\n\n  def zero?\n    `self == 0`\n  end\n\n  # Since bitwise operations are 32 bit, declare it to be so.\n  def size\n    4\n  end\n\n  def nan?\n    `isNaN(self)`\n  end\n\n  def finite?\n    `self != Infinity && self != -Infinity && !isNaN(self)`\n  end\n\n  def infinite?\n    %x{\n      if (self == Infinity) {\n        return +1;\n      }\n      else if (self == -Infinity) {\n        return -1;\n      }\n      else {\n        return nil;\n      }\n    }\n  end\n\n  def positive?\n    `self != 0 && (self == Infinity || 1 / self > 0)`\n  end\n\n  def negative?\n    `self == -Infinity || 1 / self < 0`\n  end\n\n  %x{\n    function numberToUint8Array(num) {\n      var uint8array = new Uint8Array(8);\n      new DataView(uint8array.buffer).setFloat64(0, num, true);\n      return uint8array;\n    }\n\n    function uint8ArrayToNumber(arr) {\n      return new DataView(arr.buffer).getFloat64(0, true);\n    }\n\n    function incrementNumberBit(num) {\n      var arr = numberToUint8Array(num);\n      for (var i = 0; i < arr.length; i++) {\n        if (arr[i] === 0xff) {\n          arr[i] = 0;\n        } else {\n          arr[i]++;\n          break;\n        }\n      }\n      return uint8ArrayToNumber(arr);\n    }\n\n    function decrementNumberBit(num) {\n      var arr = numberToUint8Array(num);\n      for (var i = 0; i < arr.length; i++) {\n        if (arr[i] === 0) {\n          arr[i] = 0xff;\n        } else {\n          arr[i]--;\n          break;\n        }\n      }\n      return uint8ArrayToNumber(arr);\n    }\n  }\n\n  def next_float\n    return ::Float::INFINITY if self == ::Float::INFINITY\n    return ::Float::NAN if nan?\n\n    if self >= 0\n      # Math.abs() is needed to handle -0.0\n      `incrementNumberBit(Math.abs(self))`\n    else\n      `decrementNumberBit(self)`\n    end\n  end\n\n  def prev_float\n    return -::Float::INFINITY if self == -::Float::INFINITY\n    return ::Float::NAN if nan?\n\n    if self > 0\n      `decrementNumberBit(self)`\n    else\n      `-incrementNumberBit(Math.abs(self))`\n    end\n  end\n\n  alias arg angle\n  alias eql? ==\n  alias fdiv /\n  alias inspect to_s\n  alias kind_of? is_a?\n  alias magnitude abs\n  alias modulo %\n  alias object_id __id__\n  alias phase angle\n  alias succ next\n  alias to_int to_i\nend\n\n::Fixnum = ::Number\n\nclass ::Integer < ::Numeric\n  `self.$$is_number_class = true`\n  `self.$$is_integer_class = true`\n\n  class << self\n    def allocate\n      ::Kernel.raise ::TypeError, \"allocator undefined for \#{name}\"\n    end\n\n    undef :new\n\n    def sqrt(n)\n      n = ::Opal.coerce_to!(n, ::Integer, :to_int)\n      %x{\n        if (n < 0) {\n          \#{::Kernel.raise ::Math::DomainError, 'Numerical argument is out of domain - \"isqrt\"'}\n        }\n\n        return parseInt(Math.sqrt(n), 10);\n      }\n    end\n\n    def try_convert(object)\n      Opal.coerce_to?(object, self, :to_int)\n    end\n  end\n\n  self::MAX = `Math.pow(2, 30) - 1`\n  self::MIN = `-Math.pow(2, 30)`\nend\n\nclass ::Float < ::Numeric\n  `self.$$is_number_class = true`\n\n  class << self\n    def allocate\n      ::Kernel.raise ::TypeError, \"allocator undefined for \#{name}\"\n    end\n\n    undef :new\n\n    def ===(other)\n      `!!other.$$is_number`\n    end\n  end\n\n  self::INFINITY = `Infinity`\n  self::MAX      = `Number.MAX_VALUE`\n  self::MIN      = `Number.MIN_VALUE`\n  self::NAN      = `NaN`\n\n