A,IAAQhH,OAAL9B,IAAK8B,EAAGc,CAAHd,CAAR;QAEE8G,OAACA,kCAADA;MAFF;QAIEA,OAACA,wBAADA;MAJF;IAJFA,CAAAA;;AAYAG,IAAAA,0BAAAA,sBAAAA;AAAAA,MAAAA;;;MACE,IAAA,MAA6B/I,IAA7B,EAAsC6I,IAAAhI,YAAAgI,aAADrG,OAAAA,CAAAA,CAArC,CAAA;QAAA,OAAQqG,IAAAhI,YAAAgI,aAADrG,OAAAA,CAAAA;MAAP;MACA,IAAA,QAAuBxC,IAAAyD,SAAAA,CAAAA,CAAvB,CAAA;QAAA,OAAOqF,IAAAjI,YAAAiI;MAAP;MAEA,IAAQjH,OAAL7B,IAAK6B,EAAEe,CAAFf,CAAR;QACEkH,OAACA,wBAADA;MADF;QAGEA,OAACA,mCAADA;MAHF;IAJFA,CAAAA;IAWA,aAAM,KAAN,EAAU,OAAV;IACA,aAAM,MAAN,EAAW,IAAX;IACA,aAAM,MAAN,EAAW,GAAX;IACA,aAAM,SAAN,EAAc,MAAd;IACA,aAAM,UAAN,EAAe,OAAf;IACA,aAAM,WAAN,EAAgB,KAAhB;IACA,aAAM,QAAN,EAAa,GAAb;IACA,aAAM,WAAN,EAAgB,QAAhB;IACA,aAAM,OAAN,EAAY,OAAZ;IACA,aAAM,MAAN,EAAW,MAAX;IACA7I,OAAA,aAAM,QAAN,EAAa,MAAb;EA52BFA,GAAM,IAANA,EAAiBsE,cAAjBtE;EA+2BA,WAAA,IAAA,YAAW8I,aAAX;EAEAC;EAAAA;;IAAAA;;;IACGA;IACAA;IAED;MAAA;;;;AACE5I,MAAAA,wBAAAA,oBAAAA;AAAAA,QAAAA;;QACEA,OAAAC,OAAQC,OAAAA,CAAOC,gBAAf,EAA6BH,0BAAD,GAAA,CAA2BL,IAAAS,MAAAA,CAAAA,CAA3B,CAApBF;MADVF,CAAAA;;MAIA,sBAAM,KAAN;;AAEA6I,MAAAA,oBAAAA,gBAAS7C,CAAT6C;AAAAA;;QACE7C,IAAIlG,KAAMY,eAAAA,CAAYsF,CAAlB,EAAqBlE,cAArB,EAAgC,QAA1BpB;;AAEhBmI;AACAA,UAAY5I,OAAQC,OAAAA,CAAO2H,IAAAhC,WAAAgC,gBAAf,EAAoCgB,iDAA5B3I;AACpB2I;;AAEAA;AACAA;MARIA,CAAAA;MAWA,OAAAC,2BAAAA,uBAAgBC,MAAhBD;AAAAA,QAAAA;;QACEA,OAAAhJ,UAAIkJ,eAAAA,CAAYD,MAAhB,EAAwBpJ,IAAxB,EAA8B,QAA1BqJ;MADNF,CAAAA;IAlBF,4BAASnJ,IAAT;IAuBA,WAAAA,IAAA,SAAaiJ,mBAAb;IACAA,OAAA,WAAAjJ,IAAA,SAAaiJ,gBAAb;EA5BFA,GAAM,IAANA,EAAkBzE,cAAlByE;EA+BAlJ,OAAAuJ;EAAAA;;IAAAA;;;IACGA;IAED;;;;AACEjJ,MAAAA,wBAAAA,oBAAAA;AAAAA,QAAAA;;QACEA,OAAAC,OAAQC,OAAAA,CAAOC,gBAAf,EAA6BH,0BAAD,GAAA,CAA2BL,IAAAS,MAAAA,CAAAA,CAA3B,CAApBF;MADVF,CAAAA;;MAIA,sBAAM,KAAN;MAEA,OAAAsC,mBAAAA,sBAAQhC,KAARgC;AAAAA;QACEA,OAACA,mBAADA;MADFA,CAAAA;IAPF,4BAAS3C,IAAT;IAYA,WAAAA,IAAA,cAAkBsJ,QAAlB;IACA,WAAAtJ,IAAA,SAAkBsJ,gBAAlB;IACA,WAAAtJ,IAAA,SAAkBsJ,gBAAlB;IACA,WAAAtJ,IAAA,SAAkBsJ,GAAlB;IAEA,WAAAtJ,IAAA,SAAiBuJ,EAAjB;IACA,WAAAvJ,IAAA,cAAiBwJ,EAAjB;IACA,WAAAxJ,IAAA,WAAiByG,CAAjB;IAEA6C,OAAA,WAAAtJ,IAAA,aAAiBsJ,uDAAjB;EAxBFA,GAAM,IAANA,EAAgB9E,cAAhB8E;AAl5BAvJ;"}}, {:offset=>{:line=>18238, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/range.rb"], :sourcesContent=>["require 'corelib/enumerable'\n\nclass ::Range\n  include ::Enumerable\n\n  `self.$$prototype.$$is_range = true`\n\n  attr_reader :begin, :end\n\n  def initialize(first, last, exclude = false)\n    ::Kernel.raise ::NameError, \"'initialize' called twice\" if @begin\n    ::Kernel.raise ::ArgumentError, 'bad value for range' unless first <=> last || first.nil? || last.nil?\n\n    @begin = first\n    @end   = last\n    @excl  = exclude\n  end\n\n  def ===(value)\n    include? value\n  end\n\n  %x{\n    function is_infinite(self) {\n      if (self.begin === nil || self.end === nil ||\n          self.begin === -Infinity || self.end === Infinity ||\n          self.begin === Infinity || self.end === -Infinity) return true;\n      return false;\n    }\n  }\n\n  def count(&block)\n    if !block_given? && `is_infinite(self)`\n      return ::Float::INFINITY\n    end\n    super\n  end\n\n  def to_a\n    ::Kernel.raise ::TypeError, 'cannot convert endless range to an array' if `is_infinite(self)`\n    super\n  end\n\n  def cover?(value)\n    beg_cmp = (@begin.nil? && -1) || (@begin <=> value) || false\n    end_cmp = (@end.nil? && -1) || (value <=> @end) || false\n    if @excl\n      end_cmp && end_cmp < 0\n    else\n      end_cmp && end_cmp <= 0\n    end && beg_cmp && beg_cmp <= 0\n  end\n\n  def each(&block)\n    return enum_for(:each) { size } unless block_given?\n\n    %x{\n      var i, limit;\n\n      if (\#{@begin}.$$is_number && \#{@end}.$$is_number) {\n        if (\#{@begin} % 1 !== 0 || \#{@end} % 1 !== 0) {\n          \#{::Kernel.raise ::TypeError, \"can't iterate from Float\"}\n        }\n\n        for (i = \#{@begin}, limit = \#{@end} + \#{@excl ? 0 : 1}; i < limit; i++) {\n          block(i);\n        }\n\n        return self;\n      }\n\n      if (\#{@begin}.$$is_string && \#{@end}.$$is_string) {\n        \#{@begin.upto(@end, @excl, &block)}\n        return self;\n      }\n    }\n\n    current = @begin\n    last    = @end\n\n    unless current.respond_to?(:succ)\n      ::Kernel.raise ::TypeError, \"can't iterate from \#{current.class}\"\n    end\n\n    while @end.nil? || (current <=> last) < 0\n      yield current\n\n      current = current.succ\n    end\n\n    yield current if !@excl && current == last\n\n    self\n  end\n\n  def eql?(other)\n    return false unless ::Range === other\n\n    @excl === other.exclude_end? &&\n      @begin.eql?(other.begin) &&\n      @end.eql?(other.end)\n  end\n\n  def exclude_end?\n    @excl\n  end\n\n  def first(n = undefined)\n    ::Kernel.raise ::RangeError, 'cannot get the minimum of beginless range' if @begin.nil?\n    return @begin if `n == null`\n    super\n  end\n\n  def last(n = undefined)\n    ::Kernel.raise ::RangeError, 'cannot get the maximum of endless range' if @end.nil?\n    return @end if `n == null`\n    to_a.last(n)\n  end\n\n  # FIXME: currently hardcoded to assume range holds numerics\n  def max\n    if @end.nil?\n      ::Kernel.raise ::RangeError, 'cannot get the maximum of endless range'\n    elsif block_given?\n      super\n    elsif !@begin.nil? && (@begin > @end ||\n                           @excl && @begin == @end)\n      nil\n    else\n      `\#{@excl} ? \#{@end} - 1 : \#{@end}`\n    end\n  end\n\n  def min\n    if @begin.nil?\n      ::Kernel.raise ::RangeError, 'cannot get the minimum of beginless range'\n    elsif block_given?\n      super\n    elsif !@end.nil? && (@begin > @end ||\n                         @excl && @begin == @end)\n      nil\n    else\n      @begin\n    end\n  end\n\n  def size\n    infinity = ::Float::INFINITY\n\n    return 0 if (@begin == infinity && !@end.nil?) || (@end == -infinity && !@begin.nil?)\n    return infinity if `is_infinite(self)`\n    return nil unless ::Numeric === @begin && ::Numeric === @end\n\n    range_begin = @begin\n    range_end   = @end\n    range_end  -= 1 if @excl\n\n    return 0 if range_end < range_begin\n\n    `Math.abs(range_end - range_begin) + 1`.to_i\n  end\n\n  def step(n = undefined)\n    %x{\n      function coerceStepSize() {\n        if (n == null) {\n          n = 1;\n        }\n        else if (!n.$$is_number) {\n          n = \#{::Opal.coerce_to!(n, ::Integer, :to_int)}\n        }\n\n        if (n < 0) {\n          \#{::Kernel.raise ::ArgumentError, \"step can't be negative\"}\n        } else if (n === 0) {\n          \#{::Kernel.raise ::ArgumentError, \"step can't be 0\"}\n        }\n      }\n\n      function enumeratorSize() {\n        if (!\#{@begin.respond_to?(:succ)}) {\n          return nil;\n        }\n\n        if (\#{@begin}.$$is_string && \#{@end}.$$is_string) {\n          return nil;\n        }\n\n        if (n % 1 === 0) {\n          return \#{(size / n).ceil};\n        } else {\n          // n is a float\n          var begin = self.begin, end = self.end,\n              abs = Math.abs, floor = Math.floor,\n              err = (abs(begin) + abs(end) + abs(end - begin)) / abs(n) * \#{::Float::EPSILON},\n              size;\n\n          if (err > 0.5) {\n            err = 0.5;\n          }\n\n          if (self.excl) {\n            size = floor((end - begin) / n - err);\n            if (size * n + begin < end) {\n              size++;\n            }\n          } else {\n            size = floor((end - begin) / n + err) + 1\n          }\n\n          return size;\n        }\n      }\n    }\n\n    unless block_given?\n      if (@begin.is_a?(Numeric) || @begin.nil?) &&\n         (@end.is_a?(Numeric) || @end.nil?) &&\n         !(@begin.nil? && @end.nil?)\n\n        return ::Enumerator::ArithmeticSequence.new(self, n, :step)\n      else\n        return enum_for(:step, n) do\n          %x{\n            coerceStepSize();\n            return enumeratorSize();\n          }\n        end\n      end\n    end\n\n    `coerceStepSize()`\n\n    if `self.begin.$$is_number && self.end