e {\n        if (self.$$is_lambda) {\n          result = self.apply(null, args);\n        }\n        else {\n          result = Opal.yieldX(self, args);\n        }\n      }\n\n      return result;\n    }\n  end\n\n  def >>(other)\n    ::Kernel.proc do |*args, &block|\n      out = call(*args, &block)\n      other.call(out)\n    end\n  end\n\n  def <<(other)\n    ::Kernel.proc do |*args, &block|\n      out = other.call(*args, &block)\n      call(out)\n    end\n  end\n\n  def to_proc\n    self\n  end\n\n  def lambda?\n    # This method should tell the user if the proc tricks are unavailable,\n    # (see Proc#lambda? on ruby docs to find out more).\n    `!!self.$$is_lambda`\n  end\n\n  def arity\n    %x{\n      if (self.$$is_curried) {\n        return -1;\n      } else if (self.$$arity != null) {\n        return self.$$arity;\n      } else {\n        return self.length;\n      }\n    }\n  end\n\n  def source_location\n    `if (self.$$is_curried) { return nil; }`\n    `self.$$source_location` || nil\n  end\n\n  def binding\n    `if (self.$$is_curried) { \#{::Kernel.raise ::ArgumentError, \"Can't create Binding\"} }`\n\n    if defined? ::Binding\n      ::Binding.new(nil, [], `self.$$s`, source_location)\n    end\n  end\n\n  def parameters(lambda: undefined)\n    %x{\n      if (self.$$is_curried) {\n        return \#{[[:rest]]};\n      } else if (self.$$parameters) {\n        if (lambda == null ? self.$$is_lambda : lambda) {\n          return self.$$parameters;\n        } else {\n          var result = [], i, length;\n\n          for (i = 0, length = self.$$parameters.length; i < length; i++) {\n            var parameter = self.$$parameters[i];\n\n            if (parameter[0] === 'req') {\n              // required arguments always have name\n              parameter = ['opt', parameter[1]];\n            }\n\n            result.push(parameter);\n          }\n\n          return result;\n        }\n      } else {\n        return [];\n      }\n    }\n  end\n\n  def curry(arity = undefined)\n    %x{\n      if (arity === undefined) {\n        arity = self.length;\n      }\n      else {\n        arity = \#{::Opal.coerce_to!(arity, ::Integer, :to_int)};\n        if (self.$$is_lambda && arity !== self.length) {\n          \#{::Kernel.raise ::ArgumentError, \"wrong number of arguments (\#{`arity`} for \#{`self.length`})\"}\n        }\n      }\n\n      function curried () {\n        var args = $slice(arguments),\n            length = args.length,\n            result;\n\n        if (length > arity && self.$$is_lambda && !self.$$is_curried) {\n          \#{::Kernel.raise ::ArgumentError, \"wrong number of arguments (\#{`length`} for \#{`arity`})\"}\n        }\n\n        if (length >= arity) {\n          return self.$call.apply(self, args);\n        }\n\n        result = function () {\n          return curried.apply(null,\n            args.concat($slice(arguments)));\n        }\n        result.$$is_lambda = self.$$is_lambda;\n        result.$$is_curried = true;\n\n        return result;\n      };\n\n      curried.$$is_lambda = self.$$is_lambda;\n      curried.$$is_curried = true;\n      return curried;\n    }\n  end\n\n  def dup\n    %x{\n      var original_proc = self.$$original_proc || self,\n          proc = function () {\n            return original_proc.apply(this, arguments);\n          };\n\n      for (var prop in self) {\n        if (self.hasOwnProperty(prop)) {\n          proc[prop] = self[prop];\n        }\n      }\n\n      return proc;\n    }\n  end\n\n  alias === call\n  alias clone dup\n  alias yield call\n  alias [] call\nend\n"], :names=>["<top (required)>", "<class:Proc>", "new", "self", "block", "Kernel", "raise", "ArgumentError", "call", ">>", "other", "proc", "block in >>", "block (2 levels) in >>", "out", "args", "to_proc", "<<", "block in <<", "block (2 levels) in <<", "lambda?", "arity", "source_location", "$ret_or_1", "binding", "Binding", "parameters", "$kwargs", "curry", "Opal", "coerce_to!", "Integer", "dup"], :mappings=>