thod}.$$arity;\n      proc.$$parameters = \#{@method}.$$parameters;\n      return proc;\n    }\n  end\n\n  def inspect\n    \"#<\#{self.class}: \#{@receiver.class}#\#{@name} (defined in \#{@owner} in \#{source_location.join(':')})>\"\n  end\n\n  alias [] call\n  alias === call\nend\n\nclass ::UnboundMethod\n  attr_reader :source, :owner, :name\n\n  def initialize(source, owner, method, name)\n    @source = source\n    @owner  = owner\n    @method = method\n    @name   = name\n  end\n\n  def arity\n    @method.arity\n  end\n\n  def parameters\n    `\#{@method}.$$parameters`\n  end\n\n  def source_location\n    `\#{@method}.$$source_location` || ['(eval)', 0]\n  end\n\n  def comments\n    `\#{@method}.$$comments` || []\n  end\n\n  def bind(object)\n    %x{\n      if (\#{@owner}.$$is_module || Opal.is_a(\#{object}, \#{@owner})) {\n        return \#{::Method.new(object, @owner, @method, @name)};\n      }\n      else {\n        \#{::Kernel.raise ::TypeError, \"can't bind singleton method to a different class (expected \#{object}.kind_of?(\#{@owner} to be true)\"};\n      }\n    }\n  end\n\n  def bind_call(object, *args, &block)\n    bind(object).call(*args, &block)\n  end\n\n  def inspect\n    \"#<\#{self.class}: \#{@source}#\#{@name} (defined in \#{@owner} in \#{source_location.join(':')})>\"\n  end\nend\n"], :names=>["<top (required)>", "<class:Method>", "self", "attr_reader", "initialize", "receiver", "owner", "method", "name", "@receiver", "@owner", "@name", "@method", "arity", "parameters", "source_location", "$ret_or_1", "0", "comments", "call", "curry", ">>", "other", "<<", "unbind", "UnboundMethod", "new", "class", "to_proc", "inspect", "join", "<class:UnboundMethod>", "source", "@source", "bind", "object", "Method", "Kernel", "raise", "TypeError", "bind_call", "args", "block"], :mappings=>"AAAAA,iCAAAA,gBAAAA;EAAAA;;;EAAAC;EAAAA;;IAAAA;;AAAAA;;IACEC,IAAAC,aAAAA,CAAY,OAAZ,EAAoB,UAApB,EAA+B,MAA/BA;;AAEAC,IAAAA,0BAAAA,sBAAeC,QAAD,EAAWC,KAAX,EAAkBC,MAAlB,EAA0BC,IAAx