MF,oBAANE;EACnBC,mBAAmBC,CAAAA,cAAK,EAALA;EAGnBC,cAAKL;EACLM,cAAK;EAEL,WAAA,IAAA,UAAS,EAAT;EACA,WAAA,IAAA,UAASC,OAAQC,KAAAA,CAAAA,CAAjB;EACA,WAAA,IAAA,SAAS,YAAA,EAAT;EAEAC,iBAAW;EACXC,eAAW;EACXV,OAAAW,CAAAA,cAAWC,CAAXD;AAjBAX;"}}, {:offset=>{:line=>19105, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/io.rb"], :sourcesContent=>["class ::IO\n  self::SEEK_SET = 0\n  self::SEEK_CUR = 1\n  self::SEEK_END = 2\n  self::SEEK_DATA = 3\n  self::SEEK_HOLE = 4\n\n  self::READABLE = 1\n  self::WRITABLE = 4\n\n  attr_reader :eof\n\n  attr_accessor :read_proc,  :sync, :tty, :write_proc\n\n  def initialize(fd, flags = 'r')\n    @fd = fd\n    @flags = flags\n    @eof = false\n\n    if flags.include?('r') && !flags.match?(/[wa+]/)\n      @closed = :write\n    elsif flags.match?(/[wa]/) && !flags.match?(/[r+]/)\n      @closed = :read\n    end\n  end\n\n  def fileno\n    @fd\n  end\n\n  def tty?\n    `self.tty == true`\n  end\n\n  def write(string)\n    `self.write_proc(string)`\n    string.size\n  end\n\n  def flush\n    # noop\n  end\n\n  def <<(string)\n    write(string)\n    self\n  end\n\n  def print(*args)\n    %x{\n      for (var i = 0, ii = args.length; i < ii; i++) {\n        args[i] = \#{::Kernel.String(`args[i]`)}\n      }\n      self.$write(args.join(\#{$,}));\n    }\n    nil\n  end\n\n  def puts(*args)\n    %x{\n      var line\n      if (args.length === 0) {\n        \#{write \"\\n\"};\n        return nil;\n      } else {\n        for (var i = 0, ii = args.length; i < ii; i++) {\n          if (args[i].$$is_array){\n            var ary = \#{`args[i]`.flatten}\n            if (ary.length > 0) \#{puts(*`ary`)}\n          } else {\n            if (args[i].$$is_string) {\n              line = args[i].valueOf();\n            } else {\n              line = \#{::Kernel.String(`args[i]`)};\n            }\n            if (!line.endsWith(\"\\n\")) line += \"\\n\"\n            \#{write `line`}\n          }\n        }\n      }\n    }\n    nil\n  end\n\n  # Reading\n\n  def getc\n    @read_buffer ||= ''\n    parts = ''\n\n    # Will execure at most twice - one time reading from a buffer\n    # second time executing read proc\n    begin\n      @read_buffer += parts\n      if @read_buffer != ''\n        ret = @read_buffer[0]\n        @read_buffer = @read_buffer[1..-1]\n        return ret\n      end\n    end while parts = sysread_noraise(1)\n\n    nil\n  end\n\n  def getbyte\n    getc&.ord\n  end\n\n  def readbyte\n    readchar.ord\n  end\n\n  def readchar\n    getc || ::Kernel.raise(::EOFError, 'end of file reached')\n  end\n\n  def readline(*args)\n    gets(*args) || ::Kernel.raise(::EOFError, 'end of file reached')\n  end\n\n  def gets(sep = false, limit = nil, opts = {})\n    if `sep.$$is_number` && !limit\n      sep, limit, opts = false, sep, limit\n    end\n    if `sep.$$is_hash` && !limit && opts == {}\n      sep, limit, opts = false, nil, sep\n    elsif `limit.$$is_hash` && opts == {}\n      sep, limit, opts = sep, nil, limit\n    end\n\n    orig_sep = sep\n\n    sep = $/ if sep == false\n    sep = /\\r?\\n\\r?\\n/ if sep == ''\n    sep ||= ''\n    sep = sep.to_str unless orig_sep == ''\n\n    # Try to deduce length of a regexp\n    seplen = orig_sep == '' ? 2 : sep.length\n\n    sep = / / if sep == ' ' # WTF is this, String#split(\" \") matches all whitespaces???\n\n    @read_buffer ||= ''\n    data = ''\n    ret = nil\n\n    begin\n      @read_buffer += data\n      if sep != '' && (`sep.$$is_regexp` ? @read_buffer.match?(sep) : @read_buffer.include?(sep))\n        orig_buffer = @read_buffer\n        ret, @read_buffer = @read_buffer.split(sep, 2)\n        ret += orig_buffer[ret.length, seplen] if ret != orig_buffer\n        break\n      end\n    end while data = sysread_noraise(sep == '' ? 65_536 : 1)\n\n    unless ret\n      ret, @read_buffer = (@read_buffer || ''), ''\n      ret = nil if ret == ''\n    end\n\n    if ret\n      if limit\n        ret = ret[0...limit]\n        @read_buffer = ret[limit..-1] + @read_buffer\n      end\n      ret = ret.sub(/\\r?\\n\\z/, '') if opts[:chomp]\n      ret = ret.sub(/\\A[\\r\\n]+/, '') if orig_sep == ''\n    end\n\n    $_ = ret if orig_sep == false\n    ret\n  end\n\n  # This method is to be overloaded, or read_proc can be changed\n  def sysread(integer)\n    `self.read_proc(integer)` || begin\n      @eof = true\n      ::Kernel.raise ::EOFError, 'end of file reached'\n    end\n  end\n\n  # @private\n  def sysread_noraise(integer)\n    sysread(integer)\n  rescue ::EOFError\n    nil\n  end\n\n  def readpartial(integer)\n    @read_buffer ||= ''\n    part = sysread(integer)\n    ret, @read_buffer = @read_buffer + (part || ''), ''\n    ret = nil if ret == ''\n    ret\n  end\n\n  def read(integer = nil)\n    @read_buffer ||= ''\n    parts = ''\n    ret = nil\n\n    begin\n      @read_buffer += parts\n      if integer && @read_buffer.length > integer\n        ret, @read_buffer = @read_buffer[0...integer], @read_buffer[integer..-1]\n        return ret\n      end\n    end while parts = sysread_noraise(integer || 65_536)\n\n    ret, @read_buffer = @read_buffer, ''\n    ret\n  end\n\n  # Eaches\n\n  def readlines(separator = $/)\n    each_line(separator).to_a\n  end\n\n  def each(sep = $/, *args, &block)\n    return enum_for :each, sep, *args unless block_given?\n\n    while (s = gets(sep, *args))\n      yield(s)\n    end\n\n    self\n  end\n\n  def each_byte(&block)\n    return enum_for :each_byte unless block_given?\n\n    while (s = getbyte)\n      yield(s)\n    end\n\n    self\n  end\n\n  def each_char(&block)\n    return enum_for :each_char unless block_given?\n\n    while (s = getc)\n      yield(s)\n    end\n\n    self\n  end\n\n  # Closedness\n\n  def close\n    @closed = :both\n  end\n\n  def close_read\n    if @closed == :write\n      @closed = :both\n    else\n      @closed = :read\n    end\n  end\n\n  def close_write\n    if @closed == :read\n      @closed = :both\n    else\n      @closed = :write\n    end\n  end\n\n  def closed?\n    @closed == :both\n  end\n\n  def closed_read?\n    @closed == :read || @closed == :both\n  end\n\n  def closed_write?\n    @closed == :write || @closed == :both\n  end\n\n  # @private\n  def check_writable\n    if closed_write?\n      ::Kernel.raise ::IOError, 'not opened for writing'\n    end\n  end\n\n  # @private\n  def check_readable\n    if closed_read?\n      ::Kernel.raise ::IOError, 'not opened for reading'\n    end\n  end\n\n  alias each_line each\n  alias eof? eof\nend\n\n::STDIN  = $stdin  = ::IO.new(0, 'r')\n::STDOUT = $stdout = ::IO.new(1, 'w')\n::STDERR = $stderr = ::IO.new(2, 'w')\n\n`var console = Opal.global.console`\n::STDOUT.write_proc = `typeof(process) === 'object' && typeof(process.stdout) === 'object' ? function(s){process.stdout.write(s)} : function(s){console.log(s)}`\n::STDERR.write_proc = `typeof(process) === 'object' && typeof(process.stderr) === 'object' ? function(s){process.stderr.write(s)} : function(s){console.warn(s)}`\n\n::STDIN.read_proc = `function(s) { var p = prompt(); if (p !== null) return p + \"\\n\"; return nil; }`\n"], :names=>["<top (required)>", "<class:IO>", "self", "0", "1", "2", "3", "4", "attr_reader", "attr_accessor", "initialize", "fd", "flags", "@fd", "@flags", "@eof", "include?", "match?", "@closed", "fileno", "tty?", "write", "string", "size", "flush", "<<", "print", "Kernel", "String", "$,", "puts", "flatten", "getc", "@read_buffer", "$ret_or_1", "parts", "+", "ret", "[]", "-1", "sysread_noraise", "getbyte", "readbyte", "readchar", "ord", "raise", "EOFError", "readline", "gets", "args", "sep", "limit", "opts", "orig_sep", "$/", "to_str", "seplen", "length", "data", "orig_buffer", "split", "65536", "sub", "$_", "sysread", "integer", "readpartial", "part", "read", ">", "readlines", "separator", "each_line", "to_a", "each", "block_given?", "enum_for", "s", "each_byte", "each_char", "close", "close_read", "close_write", "closed?", "==", "closed_read?", "closed_write?", "check_writable", "IOError", "check_readable", "$s