05B-\\u005E\\u0060\\u007B-\\u007F'\n  self::CONST_NAME_REGEXP = Regexp.new(\"\#{self::REGEXP_START}(::)?[A-Z][^\#{self::FORBIDDEN_CONST_NAME_CHARS}]*\#{self::REGEXP_END}\")\nend\n"], :names=>["<top (required)>", "<module:Opal>", "self", "Regexp", "new", "self::FORBIDDEN_STARTING_IDENTIFIER_CHARS", "self::FORBIDDEN_ENDING_IDENTIFIER_CHARS", "self::REGEXP_START", "self::FORBIDDEN_CONST_NAME_CHARS", "self::REGEXP_END"], :mappings=>"AAAAA,sCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;;IACE,WAAAC,IAAA,kBAA6CD,GAA7C;IACA,WAAAC,IAAA,gBAA2CD,GAA3C;IASA,WAAAC,IAAA,yCAA4CD,qEAA5C;IAYA,WAAAC,IAAA,uCAA4CD,2FAA5C;IACA,WAAAC,IAAA,8BAAiCC,YAAMC,KAAAA,CAAMH,IAAD,GAAA,CAAKI,IAAAH,IAAAG,wCAAL,CAAA,GAA+CJ,MAA/C,GAAA,CAAqDK,IAAAJ,IAAAI,sCAArD,CAAA,GAA6FL,GAAlGG,CAAvC;IAIA,WAAAF,IAAA,gCAAmCD,2FAAnC;IACAA,OAAA,WAAAC,IAAA,uBAA0BC,YAAMC,KAAAA,CAAK,EAAA,GAAA,CAAGG,IAAAL,IAAAK,iBAAH,CAAA,GAAsBN,cAAtB,GAAA,CAAoCO,IAAAN,IAAAM,+BAApC,CAAA,GAAqEP,IAArE,GAAA,CAAyEQ,IAAAP,IAAAO,eAAzE,CAALL,CAAhC;EA7BFH,GAAAA,WAAAA;AAFAD;"}}, {:offset=>{:line=>19561, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["opal/mini.rb"], :sourcesContent=>["::Object.require 'opal/base'\n\n::Object.require 'corelib/nil'\n::Object.require 'corelib/boolean'\n::Object.require 'corelib/string'\n::Object.require 'corelib/comparable'\n::Object.require 'corelib/enumerable'\n::Object.require 'corelib/enumerator'\n::Object.require 'corelib/array'\n::Object.require 'corelib/hash'\n::Object.require 'corelib/number'\n::Object.require 'corelib/range'\n::Object.require 'corelib/proc'\n::Object.require 'corelib/method'\n::Object.require 'corelib/regexp'\n::Object.require 'corelib/variables'\n::Object.require 'corelib/io'\n::Object.require 'opal/regexp_anchors'\n"], :names=>["<top (required)>", "Object", "require"], :mappings=>"AAAAA,4BAAAA,gBAAAA;EAAAA;;;EAAAC,OAAQC,SAAAA,CAASF,WAATE;EAERD,OAAQC,SAAAA,CAASF,aAATE;EACRD,OAAQC,SAAAA,CAASF,iBAATE;EACRD,OAAQC,SAAAA,CAASF,gBAATE;EACRD,OAAQC,SAAAA,CAASF,oBAATE;EACRD,OAAQC,SAAAA,CA