) { str = ' ' + str; }\n                }\n              }\n            }\n            if (format_string.charAt(i) === format_string.charAt(i).toUpperCase() && arg !== Infinity && arg !== -Infinity && !isNaN(arg)) {\n              str = str.toUpperCase();\n            }\n            str = str.replace(/([eE][-+]?)([0-9])$/, '$10$2');\n            break format_sequence;\n\n          case 'a':\n          case 'A':\n            // Not implemented because there are no specs for this field type.\n            \#{::Kernel.raise ::NotImplementedError, '`A` and `a` format field types are not implemented in Opal yet'}\n            // raise\n\n          case 'c':\n            arg = GET_ARG();\n            if (\#{`arg`.respond_to?(:to_ary)}) { arg = \#{`arg`.to_ary}[0]; }\n            if (\#{`arg`.respond_to?(:to_str)}) {\n              str = \#{`arg`.to_str};\n            } else {\n              str = String.fromCharCode($coerce_to(arg, \#{::Integer}, 'to_int'));\n            }\n            if (str.length !== 1) {\n              \#{::Kernel.raise ::ArgumentError, '%c requires a character'}\n            }\n            if (flags&FMINUS) {\n              while (str.length < width) { str = str + ' '; }\n            } else {\n              while (str.length < width) { str = ' ' + str; }\n            }\n            break format_sequence;\n\n          case 'p':\n            str = \#{`GET_ARG()`.inspect};\n            if (precision !== -1) { str = str.slice(0, precision); }\n            if (flags&FMINUS) {\n              while (str.length < width) { str = str + ' '; }\n            } else {\n              while (str.length < width) { str = ' ' + str; }\n            }\n            break format_sequence;\n\n          case 's':\n            str = \#{`GET_ARG()`.to_s};\n            if (precision !== -1) { str = str.slice(0, precision); }\n            if (flags&FMINUS) {\n              while (str.length < width) { str = str + ' '; }\n            } else {\n              while (str.length < width) { str = ' ' + str; }\n            }\n            break format_sequence;\n\n          default:\n            \#{::Kernel.raise ::ArgumentError, \"malformed format string - %\#{`format_string.charAt(i)`}\"}\n          }\n        }\n\n        if (str === undefined) {\n          \#{::Kernel.raise ::ArgumentError, 'malformed format string - %'}\n        }\n\n        result += format_string.slice(begin_slice, end_slice) + str;\n        begin_slice = i + 1;\n      }\n\n      if (\#{$DEBUG} && pos_arg_num >= 0 && seq_arg_num < args.length) {\n        \#{::Kernel.raise ::ArgumentError, 'too many arguments for format string'}\n      }\n\n      return result + format_string.slice(begin_slice);\n    }\n  end\n\n  alias sprintf format\nend\n"], :names=>["<top (required)>", "<module:Kernel>", "format", "format_string", "args", "length", "1", "[]", "0", "respond_to?", "ary", "Opal", "coerce_to?", "Array", "nil?", "to_a", "Kernel", "raise", "ArgumentError", "to_int", "fetch", "Integer", "Float", "NotImplementedError", "to_ary", "to_str", "inspect", "to_s", "$DEBUG"], :mappings=>"AAAAA,wCAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;;;;AACEC,IAAAA,sBAAAA,kBAAWC,aAAD,EAHZ,EAGED;AAAAA,MAAAA;AAAAA;;;MAHF;MAG4B;MACxB,IAAG,CAAA,MAAAE,IAAIC,QAAAA,CAAAA,CAAJ,EAAeC,CAAf,CAAA,IAAA,CAAA,QAAoBF,IAAIG,OAAAA,CAACC,CAADD,CAAGE,gBAAAA,CAAa,QAAbA,CAA3B,CAAA,CAAA,CAAH;;QACEC,MAAMC,KAAMC,eAAAA,CAAYR,IAAIG,OAAAA,CAACC,CAADD,CAAtB,EAA2BM,YAA3B,EAAoC,QAA9BD;QACZ,KAAA,QAAuBF,GAAGI,SAAAA,CAAAA,CAA1B,CAAA;UAAAV,OAAOM,GAAGK,MAAAA,CAAAA;QAAV;MAFF;;AAMJb;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA,4BAA8Bc,OAAQC,OAAAA,CAAOC,oBAAf,EAAgChB,kBAAxBe,CAA2Cf;AACjFA,4BAA8Bc,OAAQC,OAAAA,CAAOC,oBAAf,EAAgChB,sBAAxBe,CAA+Cf;AACrFA;;AAEAA;AACAA,4BAA8Bc,OAAQC,OAAAA,CAAOC,oBAAf,EAAgChB,mBAAxBe,CAA4Cf;AAClFA,4BAA8Bc,OAAQC,OAAAA,C