CA,OAADA,CAASkB,OAAAA,CAAQlB,kBAARkB,CAA6BlB;;AAEnEA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA,cAAgBc,OAAQC,OAAAA,CAAOC,oBAAf,EAAgChB,uBAAxBe;AACxBf;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA,kBAAoBc,OAAQK,SAAAA,CAAUnB,SAAVmB,CAAsBnB;AAClDA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA,kBAAoBc,OAAQK,SAAAA,CAAUnB,SAAVmB,CAAsBnB;AAClDA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA,kBAAoBc,OAAQM,OAAAA,CAAQpB,SAARoB,CAAoBpB;AAChDA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA,YAAcc,OAAQC,OAAAA,CAAOM,0BAAf,EAAsCrB,gEAA9Be;AACtBf;;AAEAA;AACAA;AACAA,gBAAkBA,CAACA,GAADA,CAAKO,gBAAAA,CAAa,QAAbA,CAAsBP,UAAYA,CAACA,GAADA,CAAKsB,QAAAA,CAAAA,CAAQtB;AACtEA,gBAAkBA,CAACA,GAADA,CAAKO,gBAAAA,CAAa,QAAbA,CAAsBP;AAC7CA,oBAAsBA,CAACA,GAADA,CAAKuB,QAAAA,CAAAA,CAAQvB;AACnCA;AACAA,wDAA0DmB,cAAUnB;AACpEA;AACAA;AACAA,cAAgBc,OAAQC,OAAAA,CAAOC,oBAAf,EAAgChB,yBAAxBe;AACxBf;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA,kBAAoBA,CAACA,SAADA,CAAWwB,SAAAA,CAAAA,CAASxB;AACxCA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA,kBAAoBA,CAACA,SAADA,CAAWyB,MAAAA,CAAAA,CAAMzB;AACrCA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA,YAAcc,OAAQC,OAAAA,CAAOC,oBAAf,EAAiChB,6BAAD,GAAA,CAA+BA,uBAA/B,CAAxBe;AACtBf;AACAA;;AAEAA;AACAA,UAAYc,OAAQC,OAAAA,CAAOC,oBAAf,EAAgChB,6BAAxBe;AACpBf;;AAEAA;AACAA;AACAA;;AAEAA,UAAY0B,YAAO1B;AACnBA,QAAUc,OAAQC,OAAAA,CAAOC,oBAAf,EAAgChB,sCAAxBe;AAClBf;;AAEAA;AACAA;IA7hBEA,CAAAA,IAAAA;IAgiBAD,OAAA,aAAM,SAAN,EAAc,QAAd;EAjiBFA,GAAO,IAAPA;AAFAD;"}}, {:offset=>{:line=>20148, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/string/encoding.rb"], :sourcesContent=>["require 'corelib/string'\n\nclass ::Encoding\n  def self.register(name, options = {}, &block)\n    names = [name] + (options[:aliases] || [])\n    ascii = options[:ascii] || false\n    dummy = options[:dummy] || false\n\n    if options[:inherits]\n      encoding = options[:inherits].clone\n      encoding.initialize(name, names, ascii, dummy)\n    else\n      encoding = new(name, names, ascii, dummy)\n    end\n    encoding.instance_eval(&block) if block_given?\n\n    register = `Opal.encodings`\n    names.each do |encoding_name|\n      const_set encoding_name.tr('-', '_'), encoding\n      register.JS[encoding_name] = encoding\n    end\n  end\n\n  def self.find(name)\n    return default_external if name == :default_external\n    `return Opal.find_encoding(name)`\n  end\n\n  singleton_class.attr_accessor :default_external\n\n  attr_reader :name, :names\n\n  def initialize(name, names, ascii, dummy)\n    @name  = name\n    @names = names\n    @ascii = ascii\n    @dummy = dummy\n  end\n\n  def ascii_compatible?\n    @ascii\n  end\n\n  def dummy?\n    @dummy\n  end\n\n  def binary?\n    false\n  end\n\n  def to_s\n    @name\n  end\n\n  def inspect\n    \"#<Encoding:\#{@name}\#{' (dummy)' if @dummy}>\"\n  end\n\n  # methods to implement per encoding\n  def charsize(string)\n    %x{\n      var len = 0;\n      for (var i = 0, length = string.length; i < length; i++) {\n        var charcode = string.charCodeAt(i);\n        if (!(charcode >= 0xD800 && charcode <= 0xDBFF)) {\n          len++;\n        }\n      }\n      return len;\n    }\n  end\n\n  def each_char(string, &block)\n    %x{\n      var low_surrogate = \"\";\n      for (var i = 0, length = string.length; i < length; i++) {\n        var charcode = string.charCodeAt(i);\n        var chr = string.charAt(i);\n        if (charcode >= 0xDC00 && charcode <= 0xDFFF) {\n          low_surrogate = chr;\n          continue;\n        }\n        else if (charcode >= 0xD800 && charcode <= 0xDBFF) {\n          chr = low_surrogate + chr;\n        }\n        if (string.encoding.name != \"UTF-8\") {\n          chr = new String(chr);\n          chr.encoding = string.encoding;\n        }\n        Opal.yield1(block, chr);\n      }\n    }\n  end\n\n  def each_byte(*)\n    ::Kernel.raise ::NotImplementedError\n  end\n\n  def bytesize(*)\n    ::Kernel.raise ::NotImplementedError\n  end\n\n  class ::EncodingError < ::StandardError; end\n  class ::CompatibilityError < ::EncodingError; end\nend\n\n::Encoding.register 'UTF-8', aliases: ['CP65001'], ascii: true do\n  def each_byte(string, &block)\n    %x{\n      // Taken from: https://github.com/feross/buffer/blob/f52dffd9df0445b93c0c9065c2f8f0f46b2c729a/index.js#L1954-L2032\n      var units = Infinity;\n      var codePoint;\n      var length = string.length;\n      var leadSurrogate = null;\n\n      for (var i = 0; i < length; ++i) {\n        codePoint = string.charCodeAt(i);\n\n        // is surrogate component\n        if (codePoint > 0xD7FF && codePoint < 0xE000) {\n          // last char was a lead\n          if (!leadSurrogate) {\n            // no lead yet\n            if (codePoint > 0xDBFF) {\n              // unexpected trail\n              if ((units -= 3) > -1) {\n                \#{yield `0xEF`};\n                \#{yield `0xBF`};\n                \#{yield `0xBD`};\n              }\n              continue;\n            } else if (i + 1 === length) {\n              // unpaired lead\n              if ((units -= 3) > -1) {\n                \#{yield `0xEF`};\n                \#{yield `0xBF`};\n                \#{yield `0xBD`};\n              }\n              continue;\n            }\n\n            // valid lead\n            leadSurrogate = codePoint;\n\n            continue;\n          }\n\n          // 2 leads in a row\n          if (codePoint < 0xDC00) {\n            if ((units -= 3) > -1) {\n              \#{yield `0xEF`};\n              \#{yield `0xBF`};\n              \#{yield `0xBD`};\n            }\n            leadSurrogate = codePoint;\n            continue;\n          }\n\n          // valid surrogate pair\n          codePoint = (leadSurrogate - 0xD800 << 10 | codePoint - 0xDC00) + 0x10000;\n        } else if (leadSurrogate) {\n          // valid bmp char, but last char was a lead\n          if ((units -= 3) > -1) {\n            \#{yield `0xEF`};\n            \#{yield `0xBF`};\n            \#{yield `0xBD`};\n          }\n        }\n\n        leadSurrogate = null;\n\n        // encode utf8\n        if (codePoint < 0x80) {\n          if ((units -= 1) < 0) break;\n          \#{yield `codePoint`};\n        } else if (codePoint < 0x800) {\n          if ((units -= 2) < 0) break;\n          \#{yield `codePoint >> 0x6 | 0xC0`};\n          \#{yield `codePoint & 0x3F | 0x80`};\n        } else if (codePoint < 0x10000) {\n          if ((units -= 3) < 0) break;\n          \#{yield `codePoint >> 0xC | 0xE0`};\n          \#{yield `codePoint >> 0x6 & 0x3F | 0x80`};\n          \#{yield `codePoint & 0x3F | 0x80`};\n        } else if (codePoint < 0x110000) {\n          if ((units -= 4) < 0) break;\n          \#{yield `codePoint >> 0x12 | 0xF0`};\n          \#{yield `codePoint >> 0xC & 0x3F | 0x80`};\n          \#{yield `codePoint >> 0x6 & 0x3F | 0x80`};\n          \#{yield `codePoint & 0x3F | 0x80`};\n        } else {\n          // Invalid code point\n        }\n      }\n    }\n  end\n\n  def bytesize(string)\n    string.bytes.length\n  end\nend\n\n::Encoding.register 'UTF-16LE' do\n  def each_byte(string, &block)\n    %x{\n      for (var i = 0, length = string.length; i < length; i++) {\n        var code = string.charCodeAt(i);\n\n        \#{yield `code & 0xff`};\n        \#{yield `code >> 8`};\n      }\n    }\n  end\n\n  def bytesize(string)\n    `string.length * 2`\n  end\nend\n\n::Encoding.register 'UTF-16BE', inherits: ::Encoding::UTF_16LE do\n  def each_byte(string, &block)\n    %x{\n      for (var i = 0, length = string.length; i < length; i++) {\n        var code = string.charCodeAt(i);\n\n        \#{yield `code >> 8`};\n        \#{yield `code & 0xff`};\n      }\n    }\n  end\nend\n\n::Encoding.register 'UTF-32LE' do\n  def each_byte(string, &block)\n    %x{\n      for (var i = 0, length = string.length; i < length; i++) {\n        var code = string.charCodeAt(i);\n\n        \#{yield `code & 0xff`};\n        \#{yield `code >> 8`};\n        \#{yield 0};\n        \#{yield 0};\n      }\n    }\n  end\n\n  def bytesize(string)\n    `string.length * 4`\n  end\nend\n\n::Encoding.register 'UTF-32BE', inherits: ::Encoding::UTF_32LE do\n  def each_byte(string, &block)\n    %x{\n      for (var i = 0, length = string.length; i < length; i++) {\n        var code = string.charCodeAt(i);\n\n        \#{yield 0};\n        \#{yield 0};\n        \#{yield `code >> 8`};\n        \#{yield `code & 0xff`};\n      }\n    }\n  end\nend\n\n::Encoding.register 'ASCII-8BIT', aliases: ['BINARY'], ascii: true do\n  def each_char(string, &block)\n    %x{\n      for (var i = 0, length = string.length; i < length; i++) {\n        var chr = new String(string.charAt(i));\n        chr.encoding = string.encoding;\n        \#{yield `chr`};\n      }\n    }\n  end\n\n  def charsize(string)\n    `string.length`\n  end\n\n  def each_byte(string, &block)\n    %x{\n      for (var i = 0, length = string.length; i < length; i++) {\n        var code = string.charCodeAt(i);\n        \#{yield `code & 0xff`};\n      }\n    }\n  end\n\n  def bytesize(string)\n    `string.length`\n  end\n\n  def binary?\n    true\n  end\nend\n\n::Encoding.register 'ISO-8859-1', aliases: ['ISO8859-1'], ascii: true, inherits: ::Encoding::ASCII_8BIT\n::Encoding.register 'US-ASCII', aliases: ['ASCII'], ascii: true, inherits: ::Encoding::ASCII_8BIT\n\nclass ::String\n  attr_reader :encoding\n  attr_reader :internal_encoding\n  `Opal.prop(String.prototype, 'bytes', nil)`\n  `Opal.prop(String.prototype, 'encoding', \#{::Encoding::UTF_8})`\n  `Opal.prop(String.prototype, 'internal_encoding', \#{::Encoding::UTF_8})`\n\n  def b\n    dup.force_encoding('binary')\n  end\n\n  def bytesize\n    @internal_encoding.bytesize(self)\n  end\n\n  def each_byte(&block)\n    return enum_for(:each_byte) { bytesize } unless block_given?\n\n    @internal_encoding.each_byte(self, &block)\n\n    self\n  end\n\n  def bytes\n    # REMIND: required when running in strict mode, otherwise the following error will be thrown:\n    # Cannot create property 'bytes' on string 'abc'\n    %x{\n      if (typeof self === 'string') {\n        return \#{`new String(self)`.each_byte.to_a};\n      }\n    }\n\n    @bytes ||= each_byte.to_a\n    @bytes.dup\n  end\n\n  def each_char(&block)\n    return enum_for(:each_char) { length } unless block_given?\n\n    @encoding.each_char(self, &block)\n\n    self\n  end\n\n  def chars(&block)\n    return each_char.to_a unless block\n\n    each_char(&block)\n  end\n\n  def each_codepoint(&block)\n    return enum_for :each_codepoint unless block_given?\n    %x{\n      for (var i = 0, length = self.length; i < length; i++) {\n        \#{yield `self.codePointAt(i)`};\n      }\n    }\n    self\n  end\n\n  def codepoints(&block)\n    # If a block is given, which is a depr