AAvC;QAAA,OAAOhB,IAAAmE,UAAAA,CAAS,gBAATA;MAAP;;AAEJS;AACAA,QAAU,mBAAOA,mBAAP,CAA4BA;AACtCA;AACAA;MACIA,OAAA5E;IAPF4E,CAAAA;;AAUAC,IAAAA,0BAAAA,sBAAAA;AAAAA,MAAAA;;MAAAA;;;MAEE,IAAiC7D,eAAjC;QAAA,OAAO4D,MAAA5E,IAAA4E,kBAAAA,EAAAA,EAAAA,EAAgB1D,KAADC,SAAAA,CAAAA,CAAfyD;MAAP;MACAC,OAAA7E,IAAA4E,gBAAAA,CAAAA,CAAcN,MAAAA,CAAAA;IAHhBO,CAAAA;;AAMAC,IAAAA,sBAAAA,kBAAWlE,QAAXkE;AAAAA,MAAAA;;MACEA,OAACA,wBAADA;IADFA,CAAAA;;AAIAb,IAAAA,8BAAAA,0BAAmBrD,QAAnBqD;AAAAA,MAAAA;;;AAEFA;;AAEAA;;AAEAA,iBAAmBc,KAAMC,eAAAA,CAAYpE,QAAlB,EAA4BqE,aAA5B,EAAsC,MAAhCD,CAAuCf;AAChEA,iBAAmBb,eAAU1B,MAAAA,CAAMd,QAANc,CAAgBuC;;AAE7CA;;AAEAA;;AAEAA;AACAA;IAdEA,CAAAA;;AAiBAiB,IAAAA,uBAAAA,mBAAYC,GAAZD;AAAAA,MAAAA;;;MACEE,eAAepF,IAAAuD,OAAAA,CAAAA;MACf4B,MAAMJ,KAAMC,eAAAA,CAAYG,GAAlB,EAAuBE,cAAvB,EAAkC,QAA5BL;MACZ,IAAA,QAA8BM,OAApBF,YAAY5B,QAAAA,CAAAA,CAAQ8B,EAAEH,GAAFG,CAA9B,CAAA;QAAA,OAAA;MAAA;MAEAJ,OAAAE,YAAY3E,OAAAA,CAAC0E,GAAD1E;IALdyE,CAAAA;;AAQAK,IAAAA,+BAAAA,2BAAoBC,KAApBD;AAAAA;MACEA,OAAEA,IAAF,GACJA,yCADI,GAEJA,2DAFI,GAGJA;IAJEA,CAAAA;IAQA1B,OAAA4B,+BAAAA,YACE,IADFA,CAAAA;EAvGF5B,GAAM,IAANA,EAAAA,IAAAA;EA4GA9D,OAAU2F,MAAAA,CAAoB5B,IA3Z9BV,cA2Z8BU,UAApB4B,CAAAA,EAAAA,MAAVtC,eAAUsC,qBAAAA,EAAAA,EAAAA,CAAAA,EAAAA;AA3ZV3F;"}}, {:offset=>{:line=>20671, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/math.rb"], :sourcesContent=>["# helpers: type_error\n\nmodule ::Math\n  self::E  = `Math.E`\n  self::PI = `Math.PI`\n\n  self::DomainError = ::Class.new(::StandardError)\n\n  def self.checked(method, *args)\n    %x{\n      if (isNaN(args[0]) || (args.length == 2 && isNaN(args[1]))) {\n        return NaN;\n      }\n\n      var result = Math[method].apply(null, args);\n\n      if (isNaN(result)) {\n        \#{::Kernel.raise DomainError, \"Numerical argument is out of domain - \\\"\#{method}\\\"\"};\n      }\n\n      return result;\n    }\n  end\n\n  def self.float!(value)\n    ::Kernel.Float(value)\n  rescue ::ArgumentError\n    ::Kernel.raise `$type_error(value, \#{::Float})`\n  end\n\n  def self.integer!(value)\n    ::Kernel.Integer(value)\n  rescue ::ArgumentError\n    ::Kernel.raise `$type_error(value, \#{::Integer})`\n  end\n\n  module_function\n\n  unless defined?(`Math.erf`)\n    %x{\n      Opal.prop(Math, 'erf', function(x) {\n        var A1 =  0.254829592,\n            A2 = -0.284496736,\n            A3 =  1.421413741,\n            A4 = -1.453152027,\n            A5 =  1.061405429,\n            P  =  0.3275911;\n\n        var sign = 1;\n\n        if (x < 0) {\n            sign = -1;\n        }\n\n        x = Math.abs(x);\n\n        var t = 1.0 / (1.0 + P * x);\n        var y = 1.0 - (((((A5 * t + A4) * t) + A3) * t + A2) * t + A1) * t * Math.exp(-x * x);\n\n        return sign * y;\n      });\n    }\n  end\n\n  unless defined?(`Math.erfc`)\n    %x{\n      Opal.prop(Math, 'erfc', function(x) {\n        var z = Math.abs(x),\n            t = 1.0 / (0.5 * z + 1.0);\n\n        var A1 = t * 0.17087277 + -0.82215223,\n            A2 = t * A1 + 1.48851587,\n            A3 = t * A2 + -1.13520398,\n            A4 = t * A3 + 0.27886807,\n            A5 = t * A4 + -0.18628806,\n            A6 = t * A5 + 0.09678418,\n            A7 = t * A6 + 0.37409196,\n            A8 = t * A7 + 1.00002368,\n            A9 = t * A8,\n            A10 = -z * z - 1.26551223 + A9;\n\n        var a = t * Math.exp(A10);\n\n        if (x < 0.0) {\n          return 2.0 - a;\n        }\n        else {\n          return a;\n        }\n      });\n    }\n  end\n\n  # Single argument equivalent functions\n  %i[\n    acos acosh asin asinh atan atanh cbrt\n    cos cosh erf erfc exp sin sinh sqrt tanh\n  ].each do |method|\n    define_method method do |x|\n      ::Math.checked method, ::Math.float!(x)\n    end\n  end\n\n  def atan2(y, x)\n    ::Math.checked :atan2, ::Math.float!(y), ::Math.float!(x)\n  end\n\n  def hypot(x, y)\n    ::Math.checked :hypot, ::Math.float!(x), ::Math.float!(y)\n  end\n\n  def frexp(x)\n    x = Math.float!(x)\n\n    %x{\n      if (isNaN(x)) {\n        return [NaN, 0];\n      }\n\n      var ex   = Math.floor(Math.log(Math.abs(x)) / Math.log(2)) + 1,\n          frac = x / Math.pow(2, ex);\n\n      return [frac, ex];\n    }\n  end\n\n  def gamma(n)\n    n = Math.float!(n)\n\n    %x{\n      var i, t, x, value, result, twoN, threeN, fourN, fiveN;\n\n      var G = 4.7421875;\n\n      var P = [\n         0.99999999999999709182,\n         57.156235665862923517,\n        -59.597960355475491248,\n         14.136097974741747174,\n        -0.49191381609762019978,\n         0.33994649984811888699e-4,\n         0.46523628927048575665e-4,\n        -0.98374475304879564677e-4,\n         0.15808870322491248884e-3,\n        -0.21026444172410488319e-3,\n         0.21743961811521264320e-3,\n        -0.16431810653676389022e-3,\n         0.84418223983852743293e-4,\n        -0.26190838401581408670e-4,\n         0.36899182659531622704e-5\n      ];\n\n\n      if (isNaN(n)) {\n        return NaN;\n      }\n\n      if (n === 0 && 1 / n < 0) {\n        return -Infinity;\n      }\n\n      if (n === -1 || n === -Infinity) {\n        \#{::Kernel.raise DomainError, 'Numerical argument is out of domain - \"gamma\"'};\n      }\n\n      if (\#{Integer === n}) {\n        if (n <= 0) {\n          return isFinite(n) ? Infinity : NaN;\n        }\n\n        if (n > 171) {\n          return Infinity;\n        }\n\n        value  = n - 2;\n        result = n - 1;\n\n        while (value > 1) {\n          result *= value;\n          value--;\n        }\n\n        if (result == 0) {\n          result = 1;\n        }\n\n        return result;\n      }\n\n      if (n < 0.5) {\n        return Math.PI / (Math.sin(Math.PI * n) * \#{::Math.gamma(1 - n)});\n      }\n\n      if (n >= 171.35) {\n        return Infinity;\n      }\n\n      if (n > 85.0) {\n        twoN   = n * n;\n        threeN = twoN * n;\n        fourN  = threeN * n;\n        fiveN  = fourN * n;\n\n        return Math.sqrt(2 * Math.PI / n) * Math.pow((n / Math.E), n) *\n          (1 + 1 / (12 * n) + 1 / (288 * twoN) - 139 / (51840 * threeN) -\n          571 / (2488320 * fourN) + 163879 / (209018880 * fiveN) +\n          5246819 / (75246796800 * fiveN * n));\n      }\n\n      n -= 1;\n      x  = P[0];\n\n      for (i = 1; i < P.length; ++i) {\n        x += P[i] / (n + i);\n      }\n\n      t = n + G + 0.5;\n\n      return Math.sqrt(2 * Math.PI) * Math.pow(t, n + 0.5) * Math.exp(-t) * x;\n    }\n  end\n\n  def ldexp(mantissa, exponent)\n    mantissa = Math.float!(mantissa)\n    exponent = Math.integer!(exponent)\n\n    %x{\n      if (isNaN(exponent)) {\n        \#{::Kernel.raise ::RangeError, 'float NaN out of range of integer'};\n      }\n\n      return mantissa * Math.pow(2, exponent);\n    }\n  end\n\n  def lgamma(n)\n    %x{\n      if (n == -1) {\n        return [Infinity, 1];\n      }\n      else {\n        return [Math.log(Math.abs(\#{::Math.gamma(n)})), \#{::Math.gamma(n)} < 0 ? -1 : 1];\n      }\n    }\n  end\n\n  def log(x, base = undefined)\n    if ::String === x\n      ::Kernel.raise `$type_error(x, \#{::Float})`\n    end\n\n    if `base == null`\n      ::Math.checked :log, ::Math.float!(x)\n    else\n      if ::String === base\n        ::Kernel.raise `$type_error(base, \#{::Float})`\n      end\n\n      ::Math.checked(:log, ::Math.float!(x)) / ::Math.checked(:log, ::Math.float!(base))\n    end\n  end\n\n  def log10(x)\n    if ::String === x\n      ::Kernel.raise `$type_error(x, \#{::Float})`\n    end\n\n    ::Math.checked :log10, ::Math.float!(x)\n  end\n\n  def log2(x)\n    if ::String === x\n      ::Kernel.raise `$type_error(x, \#{::Float})`\n    end\n\n    ::Math.checked :log2, ::Math.float!(x)\n  end\n\n  def tan(x)\n    x = ::Math.float!(x)\n\n    if x.infinite?\n      return ::Float::NAN\n    end\n\n    ::Math.checked :tan, ::Math.float!(x)\n  end\nend\n"], :names=>["<top (required)>", "<module:Math>", "self", "Class", "new", "StandardError", "checked", "method", "Kernel", "raise", "DomainError", "float!", "value", "Float", "ArgumentError", "integer!", "Integer", "module_function", "each", "block in <module:Math>", "block (2 levels) in <module:Math>", "define_method", "x", "block (3 levels) in <module:Math>", "Math", "atan2", "y", "hypot", "frexp", "gamma", "n", "===", "-", "1", "ldexp", "mantissa", "exponent", "RangeError", "lgamma", "log", "base", "String", "/", "log10", "log2", "tan", "infinite?", "Float::NAN"], :mappings=>"AAAAA,+BAAAA,gBAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;;IACE,WAAAC,IAAA,OAAYD,MAAZ;IACA,WAAAC,IAAA,QAAYD,OAAZ;IAEA,WAAAC,IAAA,iBAAoBC,MAAOC,KAAAA,CAAKC,oBAALD,CAA3B;IAEAE,MAAIJ,IAAJI,cAAAA,mBAAiBC,MAAD,EARlB,EAQED;AAAAA,MAAAA;;;MARF;MAQ2B;;AAE3BA;AACAA;AACAA;;AAEAA;;AAEAA;AACAA,QAAUE,OAAQC,OAAAA,CAAOC,iBAAf,EAA6BJ,0CAAD,GAAA,CAA2CC,MAA3C,CAAA,GAAkDD,IAAtEG,CAA0EH;AAC5FA;;AAEAA;AACAA;IAbEA,CAAAA,IAAAA;IAgBAK,MAAIT,IAAJS,aAAAA,4BAAgBC,KAAhBD;AAAAA;MACE;QAAAA,OAAAH,OAAQK,OAAAA,CAAOD,KAAPC;MAAR;QACF,sBAAO,CAAAC,oBAAA,CAAP;UAAA;YACEH,OAAAH,OAAQC,OAAAA,CAAQE,mBAAqBE,YAAQF,CAArCF;UADV;QAAA,CADE;MAAA;IADFE,CAAAA;IAMAI,MAAIb,IAAJa,eAAAA,8BAAkBH,KAAlBG;AAAAA;MACE;QAAAA,OAAAP,OAAQQ,SAAAA,CAASJ,KAATI;MAAR;QACF,sBAAO,CAAAF,oBAAA,CAAP;UAAA;YACEC,OAAAP,OAAQC,OAAAA,CAAQM,mBAAqBC,cAAUD,CAAvCN;UADV;QAAA,CADE;MAAA;IADFM,CAAAA;IAMAb,IAAAe,iBAAAA,CAAAA;IAEA,KAAA,QAAO,QAAUhB,QAAV,kBAAP,CAAA;;AAEFA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;;AAEAA;AACAA;AACAA;;AAEAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;IAvBE;IA0BA,KAAA,QAAO,QAAUA,SAAV,kBAAP,CAAA;;AAEFA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;IA1BE;IAiCCiB,MAHD,CACE,MADF,EACO,OADP,EACa,MADb,EACkB,OADlB,EACwB,MADxB,EAC6B,OAD7B,EACmC,MADnC,EAEE,KAFF,EAEM,MAFN,EAEW,KAFX,EAEe,MAFf,EAEoB,KAFpB,EAEwB,KAFxB,EAE4B,MAF5B,EAEiC,MAFjC,EAEsC,MAFtC,CAGCA,QAAAA,EAAAA,EAAAA,EAHDC,iBAGWZ,MAHXY,EAAAC;;;MAGW;MACTA,OAAAC,MAAAnB,IAAAmB,iBAAAA,EAAAA,CAAcd,MAAdc,CAAAA,EAAAD,aAAyBE,CAAzBF;;QAAyB;QACvBG,OAAAC,WAAMlB,SAAAA,CAASC,MAAf,EAAuBiB,WAAMb,WAAAA,CAAQW,CAARX,CAAvBL,EADRc,CAAAC,EAJFF,CAAAA