WAAAA,CAAQW,CAARX,CAArBL,CAAiCoC,EAAElB,WAAMlB,SAAAA,CAAS,KAAf,EAAqBkB,WAAMb,WAAAA,CAAQ6B,IAAR7B,CAArBL,CAARoC;MAPzC;IALFH,CAAAA,IAAAA;;AAgBAI,IAAAA,qBAAAA,iBAAUrB,CAAVqB;AAAAA;;MACE,IAAA,QAAGF,aAAH,EAAgBnB,CAAhB,CAAA;QACEd,OAAQC,OAAAA,CAAQkC,eAAiB9B,YAAQ8B,CAAjClC;MADV;MAIAkC,OAAAnB,WAAMlB,SAAAA,CAAS,OAAf,EAAuBkB,WAAMb,WAAAA,CAAQW,CAARX,CAAvBL;IALRqC,CAAAA;;AAQAC,IAAAA,oBAAAA,gBAAStB,CAATsB;AAAAA;;MACE,IAAA,QAAGH,aAAH,EAAgBnB,CAAhB,CAAA;QACEd,OAAQC,OAAAA,CAAQmC,eAAiB/B,YAAQ+B,CAAjCnC;MADV;MAIAmC,OAAApB,WAAMlB,SAAAA,CAAS,MAAf,EAAsBkB,WAAMb,WAAAA,CAAQW,CAARX,CAAtBL;IALRsC,CAAAA;IAQA3C,OAAA4C,mBAAAA,eAAQvB,CAARuB;AAAAA;;MACEvB,IAAIE,WAAMb,WAAAA,CAAQW,CAARX;MAEV,IAAA,QAAGW,CAACwB,cAAAA,CAAAA,CAAJ,CAAA;QACE,OAAOC,IAAAlC,YAAAkC;MADT;MAIAF,OAAArB,WAAMlB,SAAAA,CAAS,KAAf,EAAqBkB,WAAMb,WAAAA,CAAQW,CAARX,CAArBL;IAPRuC,CAAAA;EApRF5C,GAAO,IAAPA;AAFAD;"}}, {:offset=>{:line=>20986, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/complex/base.rb"], :sourcesContent=>["module ::Kernel\n  def Complex(real, imag = nil)\n    if imag\n      Complex.new(real, imag)\n    else\n      Complex.new(real, 0)\n    end\n  end\nend\n\nclass ::String\n  def to_c\n    Complex.from_string(self)\n  end\nend\n"], :names=>["<top (required)>", "<module:Kernel>", "Complex", "real", "imag", "new", "0", "<class:String>", "to_c", "from_string", "self"], :mappings=>"AAAAA,uCAAAA,gBAAAA;EAAAA;;;EAAAC;EAAAA;;IAAAA;;IACEA,OAAAC,uBAAAA,mBAAYC,IAAD,EAAOC,IAAlBF;AAAAA;;MAAkB,yBAAO;MACvB,IAAA,QAAGE,IAAH,CAAA;QACEF,OAAAA,aAAOG,KAAAA,CAAKF,IAAZ,EAAkBC,IAAXC;MADT;QAGEH,OAAAA,aAAOG,KAAAA,CAAKF,IAAZ,EAAkBG,CAAXD;MAHT;IADFH,CAAAA,IAAAA;EADFD,GAAO,IAAPA;EAUAD,OAAAO;EAAAA;;IAAAA;;IACEA,OAAAC,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAAAN,aAAOO,aAAAA,CAAaC,IAAbD;IADTD,CAAAA;EADFD,GAAM,IAANA,EAAAA,IAAAA;AAVAP;"}}, {:offset=>{:line=>21019, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/complex.rb"], :sourcesContent=>["require 'corelib/numeric'\nrequire 'corelib/complex/base'\n\nclass ::Complex < ::Numeric\n  def self.rect(real, imag = 0)\n    unless ::Numeric === real && real.real? && ::Numeric === imag && imag.real?\n      ::Kernel.raise ::TypeError, 'not a real'\n    end\n\n    new(real, imag)\n  end\n\n  def self.polar(r, theta = 0)\n    unless ::Numeric === r && r.real? && ::Numeric === theta && theta.real?\n      ::Kernel.raise ::TypeError, 'not a real'\n    end\n\n    new(r * ::Math.cos(theta), r * ::Math.sin(theta))\n  end\n\n  attr_reader :real, :imag\n\n  def initialize(real, imag = 0)\n    @real = real\n    @imag = imag\n    freeze\n  end\n\n  def coerce(other)\n    if ::Complex === other\n      [other, self]\n    elsif ::Numeric === other && other.real?\n      [::Complex.new(other, 0), self]\n    else\n      ::Kernel.raise ::TypeError, \"\#{other.class} can't be coerced into Complex\"\n    end\n  end\n\n  def ==(other)\n    if ::Complex === other\n      @real == other.real && @imag == other.imag\n    elsif ::Numeric === other && other.real?\n      @real == other && @imag == 0\n    else\n      other == self\n    end\n  end\n\n  def -@\n    ::Kernel.Complex(-@real, -@imag)\n  end\n\n  def +(other)\n    if ::Complex === other\n      ::Kernel.Complex(@real + other.real, @imag + other.imag)\n    elsif ::Numeric === other && other.real?\n      ::Kernel.Complex(@real + other, @imag)\n    else\n      __coerced__ :+, other\n    end\n  end\n\n  def -(other)\n    if ::Complex === other\n      ::Kernel.Complex(@real - other.real, @imag - other.imag)\n    elsif ::Numeric === other && other.real?\n      ::Kernel.Complex(@real - other, @imag)\n    else\n      __coerced__ :-, other\n    end\n  end\n\n  def *(other)\n    if ::Complex === other\n      ::Kernel.Complex(@real * other.real - @imag * other.imag,\n        @real * other.imag + @imag * other.real,\n      )\n    elsif ::Numeric === other && other.real?\n      ::Kernel.Complex(@real * other, @imag * other)\n    else\n      __coerced__ :*, other\n    end\n  end\n\n  def /(other)\n    if ::Complex === other\n      if (::Number === @real && @real.nan?) || (::Number === @imag && @imag.nan?) ||\n         (::Number === other.real && other.real.nan?) || (::Number === other.imag && other.imag.nan?)\n        ::Complex.new(::Float::NAN, ::Float::NAN)\n      else\n        self * other.conj / other.abs2\n      end\n    elsif ::Numeric === other && other.real?\n      ::Kernel.Complex(@real.quo(other), @imag.quo(other))\n    else\n      __coerced__ :/, other\n    end\n  end\n\n  def **(other)\n    if other == 0\n      return ::Complex.new(1, 0)\n    end\n\n    if ::Complex === other\n      r, theta = polar\n      ore      = other.real\n      oim      = other.imag\n      nr       = ::Math.exp(ore * ::Math.log(r) - oim * theta)\n      ntheta   = theta * ore + oim * ::Math.log(r)\n\n      ::Complex.polar(nr, ntheta)\n    elsif ::Integer === other\n      if other > 0\n        x = self\n        z = x\n        n = other - 1\n\n        while n != 0\n          div, mod = n.divmod(2)\n          while mod == 0\n            x = ::Kernel.Complex(x.real * x.real - x.imag * x.imag, 2 * x.real * x.imag)\n            n = div\n            div, mod = n.divmod(2)\n          end\n\n          z *= x\n          n -= 1\n        end\n\n        z\n      else\n        (::Rational.new(1, 1) / self)**-other\n      end\n    elsif ::Float === other || ::Rational === other\n      r, theta = polar\n\n      ::Complex.polar(r**other, theta * other)\n    else\n      __coerced__ :**, other\n    end\n  end\n\n  def abs\n    ::Math.hypot(@real, @imag)\n  end\n\n  def abs2\n    @real * @real + @imag * @imag\n  end\n\n  def angle\n    ::Math.atan2(@imag, @real)\n  end\n\n  def conj\n    ::Kernel.Complex(@real, -@imag)\n  end\n\n  def denominator\n    @real.denominator.lcm(@imag.denominator)\n  end\n\n  def eql?(other)\n    Complex === other && @real.class == @imag.class && self == other\n  end\n\n  def fdiv(other)\n    unless ::Numeric === other\n      ::Kernel.raise ::TypeError, \"\#{other.class} can't be coerced into Complex\"\n    end\n\n    self / other\n  end\n\n  def finite?\n    @real.finite? && @imag.finite?\n  end\n\n  def hash\n    \"Complex:\#{@real}:\#{@imag}\"\n  end\n\n  def infinite?\n    @real.infinite? || @imag.infinite?\n  end\n\n  def inspect\n    \"(\#{self})\"\n  end\n\n  def numerator\n    d = denominator\n\n    ::Kernel.Complex(@real.numerator * (d / @real.denominator),\n      @imag.numerator * (d / @imag.denominator),\n    )\n  end\n\n  def polar\n    [abs, arg]\n  end\n\n  def rationalize(eps = undefined)\n    %x{\n      if (arguments.length > 1) {\n        \#{::Kernel.raise ::ArgumentError, \"wrong number of arguments (\#{`arguments.length`} for 0..1)\"};\n      }\n    }\n\n    if @imag != 0\n      ::Kernel.raise ::RangeError, \"can't convert \#{self} into Rational\"\n    end\n\n    real.rationalize(eps)\n  end\n\n  def real?\n    false\n  end\n\n  def rect\n    [@real, @imag]\n  end\n\n  def to_f\n    unless @imag == 0\n      ::Kernel.raise ::RangeError, \"can't convert \#{self} into Float\"\n    end\n\n    @real.to_f\n  end\n\n  def to_i\n    unless @imag == 0\n      ::Kernel.raise ::RangeError, \"can't convert \#{self} into Integer\"\n    end\n\n    @real.to_i\n  end\n\n  def to_r\n    unless @imag == 0\n      ::Kernel.raise ::RangeError, \"can't convert \#{self} into Rational\"\n    end\n\n    @real.to_r\n  end\n\n  def to_s\n    result = @real.inspect\n\n    result +=\n      if (::Number === @imag && @imag.nan?) || @imag.positive? || @imag.zero?\n        '+'\n      else\n        '-'\n      end\n\n    result += @imag.abs.inspect\n\n    if ::Number === @imag && (@imag.nan? || @imag.infinite?)\n      result += '*'\n    end\n\n    result + 'i'\n  end\n\n  I = new(0, 1)\n\n  def self.from_string(str)\n    %x{\n      var re = /[+-]?[\\d_]+(\\.[\\d_]+)?(e\\d+)?/,\n          match = str.match(re),\n          real, imag, denominator;\n\n      function isFloat() {\n        return re.test(str);\n      }\n\n      function cutFloat() {\n        var match =