AvB,CAAA,CAAH;QACEa,SAAOtD,SAAPsD,MAAOtD,EAAGqD,GAAHrD;MADT;MAIAqD,OAAOrD,SAAPsD,MAAOtD,EAAEqD,GAAFrD;IAhBTqD,CAAAA;IAmBA,6BAAIrF,IAAAY,KAAAA,CAAIN,CAAJ,EAAOsC,CAAPhC,CAAJ;IAEA6E,MAAIzF,IAAJyF,kBAAAA,uBAAqBC,GAArBD;AAAAA;;AAEFA;AACAA;AACAA;;AAEAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;;AAEAA;AACAA;AACAA,qBAAuBhF,OAAQmD,UAAAA,CAAW6B,SAAnB,EAAgCA,WAAxB7B,CAAsC6B;AACrEA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;;AAEAA;AACAA;AACAA;AACAA,iBAAmBhF,OAAQkB,SAAAA,CAASrB,CAAjB,EAAoBsC,CAAZjB,CAAe8D;AAC1CA;AACAA;AACAA;AACAA,iBAAmBhF,OAAQkB,SAAAA,CAASrB,CAAjB,EAAoBqF,EAAZhE,CAAgB8D;AAC3CA;AACAA;AACAA;AACAA,iBAAmBhF,OAAQkB,SAAAA,CAASrB,CAAjB,EAAoBsC,CAAZjB,CAAe8D;AAC1CA;AACAA;AACAA,eAAiBhF,OAAQkB,SAAAA,CAASrB,CAAjB,EAAoBA,CAAZqB,CAAe8D;AACxCA;;AAEAA;AACAA;AACAA;AACAA;AACAA,iBAAmBhF,OAAQkB,SAAAA,CAASrB,CAAjB,EAAqBmF,IAAb9D,CAAoB8D;AAC/CA;AACAA;AACAA,iBAAmBhF,OAAQkB,SAAAA,CAAU8D,IAAlB,EAAyBnF,CAAjBqB,CAAoB8D;AAC/CA;AACAA;AACAA;AACAA,eAAiBhF,OAAQkB,SAAAA,CAAU8D,IAAlB,EAA0BA,IAAlB9D,CAAyB8D;AAClDA;AACAA;IA3EEA,CAAAA;IA8EA;;MACE,OAAA,aAAM,aAAN,EAAkB,MAAlB;IADF,4BAASzF,IAAT;IAIA,aAAM,KAAN,EAAU,OAAV;IACA,aAAM,WAAN,EAAgB,MAAhB;IACA,aAAM,QAAN,EAAa,GAAb;IACA,aAAM,WAAN,EAAgB,MAAhB;IACA,aAAM,WAAN,EAAgB,KAAhB;IACA,aAAM,OAAN,EAAY,KAAZ;IACA,aAAM,KAAN,EAAU,GAAV;IACA,aAAM,aAAN,EAAkB,MAAlB;;IAEA,sBAAM,WAAN;;IACA,sBAAM,WAAN;;;IACA,sBAAM,MAAN;IA3WFE,OAAA;EAGAA,GAAM,IAANA,EAAkBK,cAAlBL;AAHAH;"}}, {:offset=>{:line=>21464, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/rational/base.rb"], :sourcesContent=>["module ::Kernel\n  def Rational(numerator, denominator = 1)\n    ::Rational.convert(numerator, denominator)\n  end\nend\n\nclass ::String\n  def to_r\n    ::Rational.from_string(self)\n  end\nend\n"], :names=>["<top (required)>", "<module:Kernel>", "Rational", "numerator", "denominator", "1", "convert", "<class:String>", "to_r", "from_string", "self"], :mappings=>"AAAAA,wCAAAA,gBAAAA;EAAAA;;;EAAAC;EAAAA;;;IACEA,OAAAC,wBAAAA,oBAAaC,SAAD,EAAYC,WAAxBF;AAAAA;;MAAwB,uCAAcG;MACpCH,OAAAA,eAAUI,SAAAA,CAASH,SAAnB,EAA8BC,WAApBE;IADZJ,CAAAA,IAAAA;EADFD,GAAO,IAAPA;EAMAD,OAAAO;EAAAA;;;IACEA,OAAAC,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAAAN,eAAUO,aAAAA,CAAaC,IAAbD;IADZD,CAAAA;EADFD,GAAM,IAANA,EAAAA,IAAAA;AANAP;"}}, {:offset=>{:line=>21491, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/rational.rb"], :sourcesContent=>["require 'corelib/numeric'\nrequire 'corelib/rational/base'\n\nclass ::Rational < ::Numeric\n  def self.reduce(num, den)\n    num = num.to_i\n    den = den.to_i\n\n    if den == 0\n      ::Kernel.raise ::ZeroDivisionError, 'divided by 0'\n    elsif den < 0\n      num = -num\n      den = -den\n    elsif den == 1\n      return new(num, den)\n    end\n\n    gcd = num.gcd(den)\n\n    new(num / gcd, den / gcd)\n  end\n\n  def self.convert(num, den)\n    if num.nil? || den.nil?\n      ::Kernel.raise ::TypeError, 'cannot convert nil into Rational'\n    end\n\n    if ::Integer === num && ::Integer === den\n      return reduce(num, den)\n    end\n\n    if ::Float === num || ::String === num || ::Complex === num\n      num = num.to_r\n    end\n\n    if ::Float === den || ::String === den || ::Complex === den\n      den = den.to_r\n    end\n\n    if den.equal?(1) && !(::Integer === num)\n      ::Opal.coerce_to!(num, ::Rational, :to_r)\n    elsif ::Numeric === num && ::Numeric === den\n      num / den\n    else\n      reduce(num, den)\n    end\n  end\n\n  def initialize(num, den)\n    @num = num\n    @den = den\n    freeze\n  end\n\n  def numerator\n    @num\n  end\n\n  def denominator\n    @den\n  end\n\n  def coerce(other)\n    case other\n    when ::Rational\n      [other, self]\n\n    when ::Integer\n      [other.to_r, self]\n\n    when ::Float\n      [other, to_f]\n    end\n  end\n\n  def ==(other)\n    case other\n    when ::Rational\n      @num == other.numerator && @den == other.denominator\n\n    when ::Integer\n      @num == other && @den == 1\n\n    when ::Float\n      to_f == other\n\n    else\n      other == self\n    end\n  end\n\n  def <=>(other)\n    case other\n    when ::Rational\n      @num * other.denominator - @den * other.numerator <=> 0\n\n    when ::Integer\n      @num - @den * other <=> 0\n\n    when ::Float\n      to_f <=> other\n\n    else\n      __coerced__ :<=>, other\n    end\n  end\n\n  def +(other)\n    case other\n    when ::Rational\n      num = @num * other.denominator + @den * other.numerator\n      den = @den * other.denominator\n\n      ::Kernel.Rational(num, den)\n\n    when ::Integer\n      ::Kernel.Rational(@num + other * @den, @den)\n\n    when ::Float\n      to_f + other\n\n    else\n      __coerced__ :+, other\n    end\n  end\n\n  def -(other)\n    case other\n    when ::Rational\n      num = @num * other.denominator - @den * other.numerator\n      den = @den * other.denominator\n\n      ::Kernel.Rational(num, den)\n\n    when ::Integer\n      ::Kernel.Rational(@num - other * @den, @den)\n\n    when ::Float\n      to_f - other\n\n    else\n      __coerced__ :-, other\n    end\n  end\n\n  def *(other)\n    case other\n    when ::Rational\n      num = @num * other.numerator\n      den = @den * other.denominator\n\n      ::Kernel.Rational(num, den)\n\n    when ::Integer\n      ::Kernel.Rational(@num * other, @den)\n\n    when ::Float\n      to_f * other\n\n    else\n      __coerced__ :*, other\n    end\n  end\n\n  def /(other)\n    case other\n    when ::Rational\n      num = @num * other.denominator\n      den = @den * other.numerator\n\n      ::Kernel.Rational(num, den)\n\n    when ::Integer\n      if other == 0\n        to_f / 0.0\n      else\n        ::Kernel.Rational(@num, @den * other)\n      end\n\n    when ::Float\n      to_f / other\n\n    else\n      __coerced__ :/, other\n    end\n  end\n\n  def **(other)\n    case other\n    when ::Integer\n      if self == 0 && other < 0\n        ::Float::INFINITY\n      elsif other > 0\n        ::Kernel.Rational(@num**other, @den**other)\n      elsif other < 0\n        ::Kernel.Rational(@den**-other, @num**-other)\n      else\n        ::Kernel.Rational(1, 1)\n      end\n\n    when ::Float\n      to_f**other\n\n    when ::Rational\n      if other == 0\n        ::Kernel.Rational(1, 1)\n      elsif other.denominator == 1\n        if other < 0\n          ::Kernel.Rational(@den**other.numerator.abs, @num**other.numerator.abs)\n        else\n          ::Kernel.Rational(@num**other.numerator, @den**other.numerator)\n        end\n      elsif self == 0 && other < 0\n        ::Kernel.raise ::ZeroDivisionError, 'divided by 0'\n      else\n        to_f**other\n      end\n\n    else\n      __coerced__ :**, other\n    end\n  end\n\n  def abs\n    ::Kernel.Rational(@num.abs, @den.abs)\n  end\n\n  def ceil(precision = 0)\n    if precision == 0\n      (-(-@num / @den)).ceil\n    else\n      with_precision(:ceil, precision)\n    end\n  end\n\n  def floor(precision = 0)\n    if precision == 0\n      (-(-@num / @den)).floor\n    else\n      with_precision(:floor, precision)\n    end\n  end\n\n  def hash\n    \"Rational:\#{@num}:\#{@den}\"\n  end\n\n  def inspect\n    \"(\#{self})\"\n  end\n\n  def rationalize(eps = undefined)\n    %x{\n      if (arguments.length > 1) {\n        \#{::Kernel.raise ::ArgumentError, \"wrong number of arguments (\#{`arguments.length`} for 0..1)\"};\n      }\n\n      if (eps == null) {\n        return self;\n      }\n\n      var e = \#{eps.abs},\n          a = \#{self - `e`},\n          b = \#{self + `e`};\n\n      var p0 = 0,\n          p1 = 1,\n          q0 = 1,\n          q1 = 0,\n          p2, q2;\n\n      var c, k, t;\n\n      while (true) {\n        c = \#{`a`.ceil};\n\n        if (\#{`c` <= `b`}) {\n          break;\n        }\n\n        k  = c - 1;\n        p2 = k * p1 + p0;\n        q2 = k * q1 + q0;\n        t  = \#{1 / (`b` - `k`)};\n        b  = \#{1 / (`a` - `k`)};\n        a  = t;\n\n        p0 = p1;\n        q0 = q1;\n        p1 = p2;\n        q1 = q2;\