;AACAA,aAAiB1C,WAAFH,CAAEG,EAAO4B,UAAHc,CAAGd,EAAGc,CAAHd,CAAP5B,CAAc0C;AAC/BA,aAAiB1C,WAAFH,CAAEG,EAAO4B,UAAHc,CAAGd,EAAGc,CAAHd,CAAP5B,CAAc0C;AAC/BA;;AAEAA;AACAA;AACAA;AACAA;AACAA;;AAEAA,aAAelD,OAAQqB,UAAAA,CAAW6B,WAAnB,EAAkCA,WAA1B7B,CAAwC6B;AAC/DA;IA3CEA,CAAAA,IAAAA;;AA8CAI,IAAAA,qBAAAA,iBAAUT,SAAVS;AAAAA,MAAAA;;;MAAU,mCAAYvD;MACpB,KAAA,MAAgD8C,SAAhD,EAA6D9C,CAA7D,CAAA;QAAA,OAAOP,IAAAsD,gBAAAA,CAAe,OAAf,EAAuBD,SAAvBC;MAAP;MACA,IAAA,MAAYtB,QAAZ,EAAoBzB,CAApB,CAAA;QAAA,OAAOA;MAAP;MACA,IAAA,MAAe0B,QAAf,EAAuBpB,CAAvB,CAAA;QAAA,OAAOmB;MAAP;MAEA5B,MAAmB2C,SAAJF,UAATb,QAAImB,KAAAA,CAAAA,CAAKN,EAAEkB,CAAFlB,CAAIE,EAAEd,QAAFc;MACnB1C,MAAWwC,UAALZ,QAAKY,EAAEkB,CAAFlB;MAEXmB,SAAchD,WAAJZ,GAAIY,EAAEX,GAAFW,CAAMiD,UAAAA,CAAAA;MAEpB,IAAA,QAAQtD,OAALqB,QAAKrB,EAAEJ,CAAFI,CAAR,CAAA;QACEmD,OAACE,MAADpD,OAAAA,CAAAA;MADF;QAGEkD,OAAAE;MAHF;IAVFF,CAAAA,IAAAA;;AAiBAtB,IAAAA,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAAKxB,WAALgB,QAAKhB,EAAEiB,QAAFjB;IADPwB,CAAAA;;AAIAlC,IAAAA,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAAAN,IAAAiE,UAAAA,CAAAA;IADF3D,CAAAA;;AAIAkB,IAAAA,oBAAAA,YAAAA;;AAIA0C,IAAAA,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAAA,EAAA,GAAA,CAAGlC,QAAH,CAAA,GAAQkC,GAAR,GAAA,CAAWjC,QAAX;IADFiC,CAAAA;;AAIAD,IAAAA,wBAAAA,oBAAaZ,SAAbY;AAAAA,MAAAA;;;MAAa,mCAAY1D;MACvB,IAAA,MAAG8C,SAAH,EAAgB9C,CAAhB,CAAA;QACE,IAAA,QAAKI,OAALqB,QAAKrB,EAAEJ,CAAFI,CAAL,CAAA;UAAWsD,OAAAjE,IAAAoD,MAAAA,CAAAA;QAAX;UAAkBa,OAAAjE,IAAAuD,OAAAA,CAAAA;QAAlB;MADF;QAGEU,OAAAjE,IAAAsD,gBAAAA,CAAe,UAAf,EAA0BD,SAA1BC;MAHF;IADFW,CAAAA,IAAAA;;AAQAX,IAAAA,8BAAAA,0BAAmBa,MAAD,EAASd,SAA3BC;AAAAA,MAAAA;;;MACE,KAAA,QAAoDlC,cAApD,EAAkEiC,SAAlE,CAAA;QAAA7C,OAAQC,OAAAA,CAAOU,gBAAf,EAA4BmC,gBAApB7C;MAAR;MAEA2D,IAAIC,CAAAA,EAAAA,CAAErB,OAAAA,CAAEK,SAAFL;MACNsB,IAASzB,UAAL7C,IAAK6C,EAAEuB,CAAFvB;MAET,IAAA,QAAalC,OAAV0C,SAAU1C,EAAEE,CAAFF,CAAb,CAAA;QACE2C,OAAgBtC,WAAfsD,CAACC,MAAAA,CAAMJ,MAANI,CAAcvD,EAAEoD,CAAFpD,CAAIV,MAAAA,CAAAA;MADtB;QAGEgD,OAAA9C,OAAQqB,UAAAA,CAAUyC,CAACC,MAAAA,CAAMJ,MAANI,CAAnB,EAAkCH,CAA1BvC;MAHV;IANFyB,CAAAA;IAaAkB,MAAIxE,IAAJwE,kBAAAA,uBAAqBC,MAArBD;AAAAA;;AAEFA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;;AAEAA;AACAA;AACAA,mBAAqBhE,OAAQqB,UAAAA,CAAW2C,SAAnB,EAAgCA,WAAxB3C,CAAsC2C;AACnEA;AACAA,mBAAqBhE,OAAQqB,UAAAA,CAAW2C,SAAnB,EAA+B3D,CAAvBgB,CAA0B2C;AACvDA;AACAA;AACAA,iBAAmBhE,OAAQqB,UAAAA,CAAW2C,SAAnB,EAA+B3D,CAAvBgB,CAA0B2C;AACrDA;AACAA;AACAA,eAAiBhE,OAAQqB,UAAAA,CAAUtB,CAAlB,EAAqBM,CAAbgB,CAAgB2C;AACzCA;AACAA;IArCEA,CAAAA;IAwCA,aAAM,QAAN,EAAa,GAAb;IACAtE,OAAA,aAAM,KAAN,EAAU,GAAV;EArYFA,GAAM,IAANA,EAAmB4B,cAAnB5B;AAHAH;"}}, {:offset=>{:line=>21928, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/time.rb"], :sourcesContent=>["# helpers: slice, deny_frozen_access\n\nrequire 'corelib/comparable'\n\nclass ::Time < `Date`\n  include ::Comparable\n\n  %x{\n    var days_of_week = \#{%w[Sunday Monday Tuesday Wednesday Thursday Friday Saturday Sunday]},\n        short_days   = \#{%w[Sun Mon Tue Wed Thu Fri Sat]},\n        short_months = \#{%w[Jan Feb Mar Apr May Jun Jul Aug Sep Oct Nov Dec]},\n        long_months  = \#{%w[January February March April May June July August September October November December]};\n  }\n\n  def self.at(seconds, frac = undefined)\n    %x{\n      var result;\n\n      if (\#{::Time === seconds}) {\n        if (frac !== undefined) {\n          \#{::Kernel.raise ::TypeError, \"can't convert Time into an exact number\"}\n        }\n        result = new Date(seconds.getTime());\n        result.timezone = seconds.timezone;\n        return result;\n      }\n\n      if (!seconds.$$is_number) {\n        seconds = \#{::Opal.coerce_to!(seconds, ::Integer, :to_int)};\n      }\n\n      if (frac === undefined) {\n        return new Date(seconds * 1000);\n      }\n\n      if (!frac.$$is_number) {\n        frac = \#{::Opal.coerce_to!(frac, ::Integer, :to_int)};\n      }\n\n      return new Date(seconds * 1000 + (frac / 1000));\n    }\n  end\n\n  %x{\n    function time_params(year, month, day, hour, min, sec) {\n      if (year.$$is_string) {\n        year = parseInt(year, 10);\n      } else {\n        year = \#{::Opal.coerce_to!(`year`, ::Integer, :to_int)};\n      }\n\n      if (month === nil) {\n        month = 1;\n      } else if (!month.$$is_number) {\n        if (\#{`month`.respond_to?(:to_str)}) {\n          month = \#{`month`.to_str};\n          switch (month.toLowerCase()) {\n          case 'jan': month =  1; break;\n          case 'feb': month =  2; break;\n          case 'mar': month =  3; break;\n          case 'apr': month =  4; break;\n          case 'may': month =  5; break;\n          case 'jun': month =  6; break;\n          case 'jul': month =  7; break;\n          case 'aug': month =  8; break;\n          case 'sep': month =  9; break;\n          case 'oct': month = 10; break;\n          case 'nov': month = 11; break;\n          case 'dec': month = 12; break;\n          default: month = \#{`month`.to_i};\n          }\n        } else {\n          month = \#{::Opal.coerce_to!(`month`, ::Integer, :to_int)};\n        }\n      }\n\n      if (month < 1 || month > 12) {\n        \#{::Kernel.raise ::ArgumentError, \"month out of range: \#{`month`}\"}\n      }\n      month = month - 1;\n\n      if (day === nil) {\n        day = 1;\n      } else if (day.$$is_string) {\n        day = parseInt(day, 10);\n      } else {\n        day = \#{::Opal.coerce_to!(`day`, ::Integer, :to_int)};\n      }\n\n      if (day < 1 || day > 31) {\n        \#{::Kernel.raise ::ArgumentError, \"day out of range: \#{`day`}\"}\n      }\n\n      if (hour === nil) {\n        hour = 0;\n      } else if (hour.$$is_string) {\n        hour = parseInt(hour, 10);\n      } else {\n        hour = \#{::Opal.coerce_to!(`hour`, ::Integer, :to_int)};\n      }\n\n      if (hour < 0 || hour > 24) {\n        \#{::Kernel.raise ::ArgumentError, \"hour out of range: \#{`hour`}\"}\n      }\n\n      if (min === nil) {\n        min = 0;\n      } else if (min.$$is_string) {\n        min = parseInt(min, 10);\n      } else {\n        min = \#{::Opal.coerce_to!(`min`, ::Integer, :to_int)};\n      }\n\n      if (min < 0 || min > 59) {\n        \#{::Kernel.raise ::ArgumentError, \"min out of range: \#{`min`}\"}\n      }\n\n      if (sec === nil) {\n        sec = 0;\n      } else if (!sec.$$is_number) {\n        if (sec.$$is_string) {\n          sec = parseInt(sec, 10);\n        } else {\n          sec = \#{::Opal.coerce_to!(`sec`, ::Integer, :to_int)};\n        }\n      }\n\n      if (sec < 0 || sec > 60) {\n        \#{::Kernel.raise ::ArgumentError, \"sec out of range: \#{`sec`}\"}\n      }\n\n      return [year, month, day, hour, min, sec];\n    }\n  }\n\n  def self.new(year = undefined, month = nil, day = nil, hour = nil, min = nil, sec = nil, utc_offset = nil)\n    %x{\n      var args, result, timezone, utc_date;\n\n      if (year === undefined) {\n        return new Date();\n      }\n\n      args  = time_params(year, month, day, hour, min, sec);\n      year  = args[0];\n      month = args[1];\n      day   = args[2];\n      hour  = args[3];\n      min   = args[4];\n      sec   = args[5];\n\n      if (utc_offset === nil) {\n        result = new Date(year, month, day, hour, min, 0, sec * 1000);\n        if (year < 100) {\n          result.setFullYear(year);\n        }\n        return result;\n      }\n\n      timezone = \#{_parse_offset(utc_offset)};\n      utc_date = new Date(Date.UTC(year, month, day, hour, min, 0, sec * 1000));\n      if (year < 100) {\n        utc_date.setUTCFullYear(year);\n      }\n\n      result = new Date(utc_date.getTime() - timezone * 3600000);\n      result.timezone = timezone;\n\n      return result;\n    }\n  end\n\n  # @private\n  def self._parse_offset(utc_offset)\n    %x{\n      var timezone;\n      if (utc_offset.$$is_string) {\n        if (utc_offset == 'UTC') {\n          timezone = 0;\n        }\n        else if(/^[+-]\\d\\d:[0-5]\\d$/.test(utc_offset)) {\n          var sign, hours, minutes;\n          sign = utc_offset[0];\n    