,KAAAA,CAAKpB,IAAAqB,MAAAA,CAAAA,CAAX,EAAiB0B,CAAjB,EAAoBA,CAAd3B;MACdqF,aAAaD,KAAKtB,MAAAA,CAAAA;MAClBwB,eAAe9D;MACfvB,OAAOrB,IAAIqB,MAAAA,CAAAA;MACX,IAAG,CAAA,QAAWsF,OAAXF,UAAWE,EAAG7B,CAAH6B,CAAX,CAAA,IAAA,CAAA,OAAmBF,UAAnB,EAAiC7D,CAAjC,CAAA,CAAA,CAAH;QAEEgE,SAAoBtE,UAAXmE,UAAWnE,EAAES,CAAFT;MAFtB;;QAKEsE,SAAwBtE,UAAJA,UAAXmE,UAAWnE,EAAEuE,CAAFvE,CAAIA,EAAES,CAAFT;QACxB,IAAA,MAAesE,MAAf,EAAyBE,EAAzB,CAAA;UAAAF,SAAS/D;QAAT;MANF;MASAkE,OAAwB7C,WAAV9B,SAALpC,IAAA6D,MAAAA,CAAAA,CAAKzB,EAAEwE,MAAFxE,CAAU8B,EAAE,GAAFA,CAAO8C,MAAAA,CAAAA;MAE/B,IAAA,QAAQL,OAALI,IAAKJ,EAAG/D,CAAH+D,CAAR,CAAA;QAEE,OAAOnG,WAAMY,KAAAA,CAAekB,UAAVtC,IAAIqB,MAAAA,CAAAA,CAAMiB,EAAES,CAAFT,CAArB,EAA0B2E,EAA1B,EAA8BC,EAAxB9F,CAA2B6E,aAAAA,CAAAA;MAF1C,OAGA,IAAA,MAAMc,IAAN,EAAcI,EAAd,CAAA;;QAEEC,QAAQ5G,WAAMY,KAAAA,CAAKpB,IAAIqB,MAAAA,CAAAA,CAAf,EAAsB4F,EAAtB,EAA0BC,EAApB9F;QACdiG,aAAaD,KAAKlC,MAAAA,CAAAA;QAClB,IAAG,CAAA,QAAWyB,OAAXU,UAAWV,EAAG9B,CAAH8B,CAAX,CAAA,IAAA,CAAA,OAAmBU,UAAnB,EAAiCzE,CAAjC,CAAA,CAAA,CAAH;;UACEmE,OAAOhE;UACP1B,OAAKe,SAALf,IAAKe,EAAGW,CAAHX;QAFP;MAJF;MAUA6D,OAAA,CAACc,IAAD,EAAO1F,IAAP;IA7BF4E,CAAAA;IAgCA;;;MACE,aAAM,QAAN,EAAa,OAAb;MACA,OAAA,aAAM,KAAN,EAAU,IAAV;IAFF,4BAASjG,IAAT;IAKA,aAAM,OAAN,EAAY,SAAZ;IACA,aAAM,MAAN,EAAW,OAAX;IACA,aAAM,QAAN,EAAa,OAAb;IACA,aAAM,QAAN,EAAa,YAAb;IACA,aAAM,MAAN,EAAW,KAAX;IACA,aAAM,OAAN,EAAY,KAAZ;IACA,aAAM,MAAN,EAAW,SAAX;IACA,aAAM,QAAN,EAAa,MAAb;IACA,aAAM,SAAN,EAAc,MAAd;IACA,aAAM,KAAN,EAAU,QAAV;IACA,aAAM,MAAN,EAAW,MAAX;IACAE,OAAA,aAAM,YAAN,EAAiB,YAAjB;EA7wBFA,GAAM,IAANA,EAAgBH,IAAhBG;AAJAH;"}}, {:offset=>{:line=>22790, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/struct.rb"], :sourcesContent=>["require 'corelib/enumerable'\n\nclass ::Struct\n  include ::Enumerable\n\n  def self.new(const_name, *args, keyword_init: false, &block)\n    if const_name\n      if const_name.class == ::String && const_name[0].upcase != const_name[0]\n        # Fast track so that we skip needlessly going thru exceptions\n        # in most cases.\n        args.unshift(const_name)\n        const_name = nil\n      else\n        begin\n          const_name = ::Opal.const_name!(const_name)\n        rescue ::TypeError, ::NameError\n          args.unshift(const_name)\n          const_name = nil\n        end\n      end\n    end\n\n    args.map do |arg|\n      ::Opal.coerce_to!(arg, ::String, :to_str)\n    end\n\n    klass = ::Class.new(self) do\n      args.each { |arg| define_struct_attribute(arg) }\n\n      class << self\n        def new(*args)\n          instance = allocate\n          `\#{instance}.$$data = {}`\n          instance.initialize(*args)\n          instance\n        end\n\n        alias_method :[], :new\n      end\n    end\n\n    klass.module_eval(&block) if block\n    `klass.$$keyword_init = keyword_init`\n\n    if const_name\n      ::Struct.const_set(const_name, klass)\n    end\n\n    klass\n  end\n\n  def self.define_struct_attribute(name)\n    if self == ::Struct\n      ::Kernel.raise ::ArgumentError, 'you cannot define attributes to the Struct class'\n    end\n\n    members << name\n\n    define_method name do\n      `self.$$data[name]`\n    end\n\n    define_method \"\#{name}=\" do |value|\n      `self.$$data[name] = value`\n    end\n  end\n\n  def self.members\n    if self == ::Struct\n      ::Kernel.raise ::ArgumentError, 'the Struct class has no members'\n    end\n\n    @members ||= []\n  end\n\n  def self.inherited(klass)\n    members = @members\n\n    klass.instance_eval do\n      @members = members\n    end\n  end\n\n  def initialize(*args)\n    if `\#{self.class}.$$keyword_init`\n      kwargs = args.last || {}\n\n      if args.length > 1 || `(args.length === 1 && !kwargs.$$is_hash)`\n        ::Kernel.raise ::ArgumentError, \"wrong number of arguments (given \#{args.length}, expected 0)\"\n      end\n\n      extra = kwargs.keys - self.class.members\n      if extra.any?\n        ::Kernel.raise ::ArgumentError, \"unknown keywords: \#{extra.join(', ')}\"\n      end\n\n      self.class.members.each do |name|\n        self[name] = kwargs[name]\n      end\n    else\n      if args.length > self.class.members.length\n        ::Kernel.raise ::ArgumentError, 'struct size differs'\n      end\n\n      self.class.members.each_with_index do |name, index|\n        self[name] = args[index]\n      end\n    end\n  end\n\n  def initialize_copy(from)\n    %x{\n      self.$$data = {}\n      var keys = Object.keys(from.$$data), i, max, name;\n      for (i = 0, max = keys.length; i < max; i++) {\n        name = keys[i];\n        self.$$data[name] = from.$$data[name];\n      }\n    }\n  end\n\n  def self.keyword_init?\n    `self.$$keyword_init`\n  end\n\n  def members\n    self.class.members\n  end\n\n  def hash\n    Hash.new(`self.$$data`).hash\n  end\n\n  def [](name)\n    if ::Integer === name\n      ::Kernel.raise ::IndexError, \"offset \#{name} too small for struct(size:\#{self.class.members.size})\" if name < -self.class.members.size\n      ::Kernel.raise ::IndexError, \"offset \#{name} too large for struct(size:\#{self.class.members.size})\" if name >= self.class.members.size\n\n      name = self.class.members[name]\n    elsif ::String === name\n      %x{\n        if(!self.$$data.hasOwnProperty(name)) {\n          \#{::Kernel.raise ::NameError.new(\"no member '\#{name}' in struct\", name)}\n        }\n      }\n    else\n      ::Kernel.raise ::TypeError, \"no implicit conversion of \#{name.class} into Integer\"\n    end\n\n    name = ::Opal.coerce_to!(name, ::String, :to_str)\n    `self.$$data[name]`\n  end\n\n  def []=(name, value)\n    if ::Integer === name\n      ::Kernel.raise ::IndexError, \"offset \#{name} too small for struct(size:\#{self.class.members.size})\" if name < -self.class.members.size\n      ::Kernel.raise ::IndexError, \"offset \#{name} too large for struct(size:\#{self.class.members.size})\" if name >= self.class.members.size\n\n      name = self.class.members[name]\n    elsif ::String === name\n      ::Kernel.raise ::NameError.new(\"no member '\#{