AkBC,MAAlBxG,IAAIO,OAAAA,CAAAA,CAAMkC,SAAAA,CAAAA,CAAQ+D,oBAAAA,EAAAA,CAAkB,YAAA,EAAlBA,CAAAA,EAAlBC,cAA2CpE,IAAD,EAAOqE,CAAjDD,EAAAE;;;QAA2C;QAAM;QAAGA,OAAC1C,MAAAA,CAAC5B,IAAF,EAAUrC,IAAIS,OAAAA,CAAC4B,IAAD5B,CAAbwD,CAAAA,EAAAA,MAADyC,CAACzC,OAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAArDwC,CAAAA,GAAAA,SAAAA,CAAkBD;IAHpBD,CAAAA;;AAMAK,IAAAA,yBAAAA,qBAxSF,EAwSEA;AAAAA,MAAAA;;;MAxSF;MAwSgB;MACZhG,OAAWM,MAAJN,IAAIM,OAAAA,EAAAA,EAAAA,EAAJ2F,cAAYzF,GAAZyF;;QAAY;QAAKC,OAACA,iBAAmB1F,GAAG0E,MAAAA,CAAAA,CAAMgB,OAA9CD,CAAI3F,CAAmD6F,SAAAA,CAAAA;;AAElEH;AACAA;AACAA;AACAA,UAAYtE,OAAQC,OAAAA,CAAOvB,gBAAf,EAA6B4F,4BAAD,GAAA,CAA6BA,CAACA,OAADA,CAASrG,OAAAA,CAAAA,CAAtC,CAAA,GAA6CqG,eAAjErE;AACpBqE;AACAA,oBAAsB5G,IAAIS,OAAAA,CAAEmG,OAAFnG,CAAYmG;AACtCA;AACAA;AACAA;IAXEA,CAAAA,IAAAA;;AAcAI,IAAAA,mBAAAA,eAAQC,GAAD,EAtTT,EAsTED;AAAAA,MAAAA;;;MAtTF;MAsTe;MACXE,OAAO,CAAA,QAAIF,kDAAJ,CAAA,GAAA,CACGA,uBADH,IAAA,GAAA;;AAKXA;AACAA;AACAA;AACAA;MAEI,KAAA,QAAOE,IAAIC,gBAAAA,CAAa,KAAbA,CAAX,CAAA;QACE7E,OAAQC,OAAAA,CAAOvB,gBAAf,EAA4B,EAAA,GAAA,CAAGkG,IAAI3G,OAAAA,CAAAA,CAAP,CAAA,GAAcyG,4BAAlCzE;MADV;MAIAyE,OAAIA,MAAJE,IAAIF,OAAAA,EAAK,MAACpD,IAAD,CAALoD;IAfNA,CAAAA,IAAAA;IAkBA,aAAM,MAAN,EAAW,QAAX;IACA,aAAM,MAAN,EAAW,SAAX;IACA9G,OAAA,aAAM,QAAN,EAAa,MAAb;EAxUFA,GAAM,IAANA,EAAAA,IAAAA;AAFAH;"}}, {:offset=>{:line=>23248, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/set.rb"], :sourcesContent=>["# helpers: freeze\n# Portions Copyright (c) 2002-2013 Akinori MUSHA <knu@iDaemons.org>\nclass ::Set\n  include ::Enumerable\n\n  def self.[](*ary)\n    new(ary)\n  end\n\n  def initialize(enum = nil, &block)\n    @hash = {}\n\n    return if enum.nil?\n    ::Kernel.raise ::ArgumentError, 'value must be enumerable' unless ::Enumerable === enum\n\n    if block\n      enum.each { |item| add yield(item) }\n    else\n      merge(enum)\n    end\n  end\n\n  def dup\n    result = self.class.new\n    result.merge(self)\n  end\n\n  def -(enum)\n    unless enum.respond_to? :each\n      ::Kernel.raise ::ArgumentError, 'value must be enumerable'\n    end\n\n    dup.subtract(enum)\n  end\n\n  def inspect\n    \"#<Set: {\#{to_a.join(',')}}>\"\n  end\n\n  def ==(other)\n    if equal?(other)\n      true\n    elsif other.instance_of?(self.class)\n      @hash == other.instance_variable_get(:@hash)\n    elsif other.is_a?(::Set) && size == other.size\n      other.all? { |o| @hash.include?(o) }\n    else\n      false\n    end\n  end\n\n  def add(o)\n    @hash[o] = true\n    self\n  end\n\n  def classify(&block)\n    return enum_for(:classify) unless block_given?\n\n    result = ::Hash.new { |h, k| h[k] = self.class.new }\n\n    each { |item| result[yield(item)].add item }\n\n    result\n  end\n\n  def collect!(&block)\n    return enum_for(:collect!) unless block_given?\n    result = self.class.new\n    each { |item| result << yield(item) }\n    replace result\n  end\n\n  def compare_by_identity\n    if @hash.respond_to?(:compare_by_identity)\n      @hash.compare_by_identity\n      self\n    else\n      raise NotImplementedError, \"\#{self.class.name}\\#\#{__method__} is not implemented\"\n    end\n  end\n\n  def compare_by_identity?\n    @hash.respond_to?(:compare_by_identity?) && @hash.compare_by_identity?\n  end\n\n  def delete(o)\n    @hash.delete(o)\n    self\n  end\n\n  def delete?(o)\n    if include?(o)\n      delete(o)\n      self\n    end\n  end\n\n  def delete_if\n    return enum_for(:delete_if) unless block_given?\n    # @hash.delete_if should be faster, but using it breaks the order\n    # of enumeration in subclasses.\n    select { |o| yield o }.each { |o| @hash.delete(o) }\n    self\n  end\n\n  def freeze\n    return self if frozen?\n\n    @hash.freeze\n    `$freeze(self)`\n  end\n\n  def keep_if\n    return enum_for(:keep_if) unless block_given?\n    reject { |o| yield o }.each { |o| @hash.delete(o) }\n    self\n  end\n\n  def reject!(&block)\n    return enum_for(:reject!) unless block_given?\n    before = size\n    delete_if(&block)\n    size == before ? nil : self\n  end\n\n  def select!(&block)\n    return enum_for(:select!) unless block_given?\n    before = size\n    keep_if(&block)\n    size == before ? nil : self\n  end\n\n  def add?(o)\n    if include?(o)\n      nil\n    else\n      add(o)\n    end\n  end\n\n  def each(&block)\n    return enum_for(:each) unless block_given?\n    @hash.each_key(&block)\n    self\n  end\n\n  def empty?\n    @hash.empty?\n  end\n\n  def eql?(other)\n    @hash.eql?(other.instance_eval { @hash })\n  end\n\n  def clear\n    @hash.clear\n    self\n  end\n\n  def include?(o)\n    @hash.include?(o)\n  end\n\n  def merge(enum)\n    enum.each { |item| add item }\n    self\n  end\n\n  def replace(enum)\n    clear\n    merge(enum)\n\n    self\n  end\n\n  def size\n    @hash.size\n  end\n\n  def subtract(enum)\n    enum.each { |item| delete item }\n    self\n  end\n\n  def |(enum)\n    unless enum.respond_to? :each\n      ::Kernel.raise ::ArgumentError, 'value must be enumerable'\n    end\n    dup.merge(enum)\n  end\n\n  %x{\n    function is_set(set) {\n      \#{`set`.is_a?(::Set) || ::Kernel.raise(::ArgumentError, 'value must be a set')}\n    }\n  }\n\n  def superset?(set)\n    `is_set(set)`\n    return false if size < set.size\n    set.all? { |o| include?(o) }\n  end\n\n  def proper_superset?(set)\n    `is_set(set)`\n    return false if size <= set.size\n    set.all? { |o| include?(o) }\n  end\n\n  def subset?(set)\n    `is_set(set)`\n    return false if set.size < size\n    all? { |o| set.include?(o) }\n  end\n\n  def proper_subset?(set)\n    `is_set(set)`\n    return false if set.size <= size\n    all? { |o| set.include?(o) }\n  end\n\n  def intersect?(set)\n    `is_set(set)`\n    if size < set.size\n      any? { |o| set.include?(o) }\n    else\n      set.any? { |o| include?(o) }\n    end\n  end\n\n  def disjoint?(set)\n    !intersect?(set)\n  end\n\n  def to_a\n    @hash.keys\n  end\n\n  alias + |\n  alias < proper_subset?\n  alias << add\n  alias <= subset?\n  alias > proper_superset?\n  alia