AAAoC,MAAAA,CAAAA,CAAH6D,CAAzB,CAAA;QAAA,OAAO;MAAP;MACAM,OAAAlE,MAAArC,IAAAqC,QAAAA,EAAAA,EAAAA,EAAAmE,cAAQjE,CAARiE;;QAAQ;QAAGC,OAAAb,GAAGnD,aAAAA,CAAUF,CAAVE,EAAd+D,CAAAnE;IAHFkE,CAAAA;;AAMAG,IAAAA,0BAAAA,gCAAed,GAAfc;AAAAA,MAAAA;;;MACGA;MACD,IAAA,QAAQb,OAAL7F,IAAAoC,MAAAA,CAAAA,CAAKyD,EAAED,GAAGxD,MAAAA,CAAAA,CAALyD,CAAR,CAAA;QACEa,OAAAC,MAAA3G,IAAA2G,QAAAA,EAAAA,EAAAA,EAAAC,cAAQrE,CAARqE;;UAAQ;UAAGC,OAAAjB,GAAGnD,aAAAA,CAAUF,CAAVE,EAAdmE,CAAAD;MADF;QAGED,OAAGC,MAAHf,GAAGe,QAAAA,EAAAA,EAAAA,EAAHC,cAAYrE,CAAZqE,EAAAC;;;UAAY;UAAGA,OAAA7G,IAAAyC,aAAAA,CAASF,CAATE,EAAfmE,CAAAA,GAAAA,SAAAA,CAAGD;MAHL;IAFFD,CAAAA;;AASAI,IAAAA,yBAAAA,+BAAclB,GAAdkB;AAAAA,MAAAA;;MACEA,OAAC9G,IAAA0G,eAAAA,CAAWd,GAAXc,CAADK,MAAAA,CAAAA;IADFD,CAAAA;;AAIAnF,IAAAA,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAAAnB,SAAKwG,MAAAA,CAAAA;IADPrF,CAAAA;IAIA,aAAM,GAAN,EAAQ,GAAR;IACA,aAAM,GAAN,EAAQ,gBAAR;IACA,aAAM,IAAN,EAAS,KAAT;IACA,aAAM,IAAN,EAAS,SAAT;IACA,aAAM,GAAN,EAAQ,kBAAR;IACA,aAAM,IAAN,EAAS,WAAT;IACA,aAAM,YAAN,EAAiB,GAAjB;IACA,aAAM,SAAN,EAAc,SAAd;IACA,aAAM,QAAN,EAAa,MAAb;IACA,aAAM,MAAN,EAAW,UAAX;IACA,aAAM,SAAN,EAAc,UAAd;IACA5B,OAAA,aAAM,OAAN,EAAY,GAAZ;EAxPFA,GAAM,IAANA,EAAAA,IAAAA;AAFAD;"}}, {:offset=>{:line=>23721, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/dir.rb"], :sourcesContent=>["class ::Dir\n  class << self\n    def chdir(dir)\n      prev_cwd = `Opal.current_dir`\n      `Opal.current_dir = \#{dir}`\n      yield\n    ensure\n      `Opal.current_dir = \#{prev_cwd}`\n    end\n\n    def pwd\n      `Opal.current_dir || '.'`\n    end\n\n    def home\n      ::ENV['HOME'] || '.'\n    end\n\n    alias getwd pwd\n  end\nend\n"], :names=>["<top (required)>", "<class:Dir>", "chdir", "dir", "prev_cwd", "pwd", "home", "$ret_or_1", "ENV", "[]", "self"], :mappings=>"AAAAA,8BAAAA,gBAAAA;EAAAA;;EAAAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAA;;;;AACEC,MAAAA,qBAAAA,iBAAUC,GAAVD;AAAAA,QAAAA;;QAAAA;QACEA,OAAA,cAAA;;QAAAE,WAAYF;QACXA,mBAAqBC;QACtB,OAAA,qBAAA,EAAA;QAFA;UAICD,mBAAqBE;QAJtB,CAAA;MADFF,CAAAA;;AAQAG,MAAAA,mBAAAA,eAAAA;AAAAA;QACEA,OAACA,uBAADA;MADFA,CAAAA;;AAIAC,MAAAA,oBAAAA,gBAAAA;AAAAA,QAAAA;;QACE,IAAA,QAAAC,CAAAA,YAAAC,UAAKC,OAAAA,CAACH,MAADG,CAALF,CAAA,CAAA;UAAAD,OAAA;QAAA;UAAiBA,OAAAA;QAAjB;MADFA,CAAAA;MAIA,OAAA,aAAM,OAAN,EAAY,KAAZ;IAjBF,4BAASI,IAAT;EADFT,GAAM,IAANA,EAAAA,IAAAA;AAAAD;"}}, {:offset=>{:line=>23766, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/file.rb"], :sourcesContent=>["# helpers: truthy\n\nclass ::File < ::IO\n  Separator = SEPARATOR = '/'\n  ALT_SEPARATOR = nil\n  PATH_SEPARATOR = ':'\n  # Assuming case insenstive filesystem\n  FNM_SYSCASE = 0\n  windows_root_rx = %r{^[a-zA-Z]:(?:\\\\|\\/)}\n\n  class << self\n    def absolute_path(path, basedir = nil)\n      sep = SEPARATOR\n      sep_chars = `$sep_chars()`\n      new_parts = []\n\n      path = path.respond_to?(:to_path) ? path.to_path : path\n      path = ::Opal.coerce_to!(`path`, ::String, :to_str)\n\n      basedir ||= ::Dir.pwd\n      path_abs    = `path.substr(0, sep.length) === sep || windows_root_rx.test(path)`\n      basedir_abs = `basedir.substr(0, sep.length) === sep || windows_root_rx.test(basedir)`\n\n      if path_abs\n        parts       = path.split(/[\#{sep_chars}]/)\n        leading_sep = `windows_root_rx.test(path) ? '' : \#{path.sub(/^([\#{sep_chars}]+).*$/, '\\1')}`\n        abs         = true\n      else\n        parts       = basedir.split(/[\#{sep_chars}]/) + path.split(/[\#{sep_chars}]/)\n        leading_sep = `windows_root_rx.test(basedir) ? '' : \#{basedir.sub(/^([\#{sep_chars}]+).*$/, '\\1')}`\n        abs         = basedir_abs\n      end\n\n      %x{\n        var part;\n        for (var i = 0, ii = parts.length; i < ii; i++) {\n          part = parts[i];\n\n          if (\n            (part === nil) ||\n            (part === ''  && ((new_parts.length === 0) || abs)) ||\n            (part === '.' && ((new_parts.length === 0) || abs))\n          ) {\n            continue;\n          }\n          if (part === '..') {\n            new_parts.pop();\n          } else {\n            new_parts.push(part);\n          }\n        }\n\n        if (!abs && parts[0] !== '.') {\n          \#{new_parts.unshift '.'}\n        }\n      }\n\n      new_path = new_parts.join(sep)\n      new_path = leading_sep + new_path if abs\n      new_path\n    end\n\n    def expand_path(path, basedir = nil)\n      sep = SEPARATOR\n      sep_chars = `$sep_chars()`\n      if `path[0] === '~' || (basedir && basedir[0] === '~')`\n        home = Dir.home\n        ::Kernel.raise(::ArgumentError, \"couldn't find HOME environment -- expanding `~'\") unless home\n        leading_sep = `windows_root_rx.test(home) ? '' : \#{home.sub(/^([\#{sep_chars}]+).*$/, '\\1')}`\n        ::Kernel.raise(::ArgumentError, 'non-absolute home') unless home.start_with?(leading_sep)\n\n        home            += sep\n        home_path_regexp = /^\\~(?:\#{sep}|$)/\n        path             = path.sub(home_path_regexp, home)\n        basedir          = basedir.sub(home_path_regexp, home) if basedir\n      end\n      absolute_path(path, basedir)\n    end\n\n    %x{\n      // Coerce a given path to a path string using #to_path and #to_str\n      function $coerce_to_path(path) {\n        if ($truthy(\#{`path`.respond_to?(:to_path)})) {\n          path = path.$to_path();\n        }\n\n        path = \#{::Opal.coerce_to!(`path`, ::String, :to_str)};\n\n        return path;\n      }\n\n      // Return a RegExp compatible char class\n      function $sep_chars() {\n        if (\#{ALT_SEPARATOR} === nil) {\n          return Opal.escape_regexp(\#{SEPARATOR});\n        } else {\n          return Opal.escape_regexp(\#{SEPARATOR + ALT_SEPARATOR});\n        }\n      }\n    }\n\n    def dirname(path, level = 1)\n      return path if level == 0\n      ::Kernel.raise ::ArgumentError, \"level can't be negative\" if level < 0\n\n      sep_chars = `$sep_chars()`\n      path = `$coerce_to_path(path)`\n      %x{\n        var absolute = path.match(new RegExp(\#{\"^[\#{sep_chars}]\"})), out;\n\n        path = path.replace(new RegExp(\#{\"[\#{sep_chars}]+$\"}), ''); // remove trailing separators\n        path = path.replace(new RegExp(\#{\"[^\#{sep_chars}]+$\"}), ''); // remove trailing basename\n        path = path.replace(new RegExp(\#{\"[\#{sep_chars}]+$\"}), ''); // remove final trailing separators\n\n        if (path === '') {\n          out = absolute ? '/' : '.';\n        }\n        else {\n          out = path;\n        }\n\n        if (level == 1) {\n          return out;\n        }\n        else {\n          return \#{dirname(`out`, level - 1)}\n        }\n      }\n    end\n\n    def basename(name, suffix = nil)\n      sep_chars = `$sep_chars()`\n      name = `$coerce_to_path(name)`\n      %x{\n        if (name.length == 0) {\n          return name;\n        }\n\n        if (suffix !== nil) {\n          suffix = \#{::Opal.coerce_to!(suffix, ::String, :to_str)}\n        } else {\n          suffix = null;\n        }\n\n        name = name.replace(new RegExp(\#{\"(.)[\#{sep_chars}]*$\"}), '$1');\n        name = name.replace(new RegExp(\#{\"^(?:.*[\#{sep_chars}])?([^\#{sep_chars}]+)$\"}), '$1');\n\n        if (suffix === \".*\") {\n          name = name.replace(/\\.[^\\.]+$/, '');\n        } else if(suffix !== null) {\n          suffix = Opal.escape_regexp(suffix);\n          name = name.replace(new RegExp(\#{\"\#{suffix}$\"}), '');\n        }\n\n        return name;\n      }\n    end\n\n    def extname(path)\n      `path = $coerce_to_path(path)`\n      filename = basename(path)\n      return '' if filename.empty?\n      last_dot_idx = filename[1..-1].rindex('.')\n      # extension name must contains at least one character .(something)\n      last_dot_idx.nil? || last_dot_idx + 1 == filename.length - 1 ? '' : filename[(last_dot_idx + 1)..-1]\n    end\n\n    def exist?(path)\n      `Opal.modules[\#{path}] != null`\n    end\n\n    def directory?(path)\n      files = []\n      %x{\n        for (var key in Opal.modules) {\n          \#{files}.push(key)\n        }\n      }\n      path = path.gsub(/(^.\#{SEPARATOR}+|\#{SEPARATOR}+$)/)\n      file = files.find { |f| f =~ /^\#{path}/ }\n      file\n    end\n\n    def join(*paths)\n      if paths.empty?\n        return ''\n      end\n      result = ''\n      paths = paths.flatten.each_with_index.map do |item, index|\n        if index == 0 && item.empty?\n          SEPARATOR\n        elsif paths.length == index + 1 && item.empty?\n          SEPARATOR\n        else\n          item\n        end\n      end\n      paths = paths.reject(&:empty?)\n      paths.each_with_index do |item, index|\n        next_item = paths[index + 1]\n        if next_item.nil?\n          result = \"\#{result}\#{item}\"\n        else\n          if item.end_with?(SEPARATOR) && next_item.start_with?(SEPARATOR)\n            item = item.sub(/\#{SEPARATOR}+$/, '')\n          end\n          result = if item.end_with?(SEPARATOR) || next_item.start_with?(SEPARATOR)\n                     \"\#{result}\#{item}\"\n                   else\n                     \"\#{result}\#{item}\#{SEPARATOR}\"\n                   end\n        end\n      end\n      result\n    end\n\n    def split(path)\n      path.split(SEPARATOR)\n    end\n\n    alias realpath expand_path\n    alias exists? exist?\n  end\nend\n"], :names=>["<top (required)>", "<class:File>", "0", "windows_root_rx", "absolute_path", "path", "basedir", "sep", "SEPARATOR", "sep_chars", "new_parts", "respond_to?", "to_path", "Opal", "coerce_to!", "String", "$ret_or_1", "Dir", "pwd", "path_abs", "basedir_abs", "parts", "split", "leading_sep", "sub", "abs", "+", "unshift", "new_path", "join", "expand_path", "home", "Kernel", "raise", "ArgumentError", "start_with?", "home_path_regexp", "self", "ALT_SEPARATOR", "dirname", "level", "1", "<", "-", "basename", "name", "suffix", "extname", "filename", "empty?", "last_dot_idx", "[]", "-1", "rindex", "nil?", "length", "exist?", "directory?", "files", "gsub", "find", "block in directory?", "f", "block (2 le