  def self.pid\n    0\n  end\n\n  def self.times\n    t = ::Time.now.to_f\n    ::Benchmark::Tms.new(t, t, t, t, t)\n  end\n\n  def self.clock_gettime(clock_id, unit = :float_second)\n    (clock = @__clocks__[clock_id]) || ::Kernel.raise(::Errno::EINVAL, \"clock_gettime(\#{clock_id}) \#{@__clocks__[clock_id]}\")\n    %x{\n      var ms = clock();\n      switch (unit) {\n        case 'float_second':      return  (ms / 1000);         // number of seconds as a float (default)\n        case 'float_millisecond': return  (ms / 1);            // number of milliseconds as a float\n        case 'float_microsecond': return  (ms * 1000);         // number of microseconds as a float\n        case 'second':            return ((ms / 1000)    | 0); // number of seconds as an integer\n        case 'millisecond':       return ((ms / 1)       | 0); // number of milliseconds as an integer\n        case 'microsecond':       return ((ms * 1000)    | 0); // number of microseconds as an integer\n        case 'nanosecond':        return ((ms * 1000000) | 0); // number of nanoseconds as an integer\n        default: \#{::Kernel.raise ::ArgumentError, \"unexpected unit: \#{unit}\"}\n      }\n    }\n  end\nend\n"], :names=>["<top (required)>", "<module:Process>", "@__clocks__", "__register_clock__", "self", "name", "func", "const_set", "size", "<<", "monotonic", "pid", "0", "times", "t", "Time", "now", "to_f", "Benchmark::Tms", "Benchmark", "new", "clock_gettime", "clock_id", "unit", "$ret_or_1", "clock", "[]", "Kernel", "raise", "Errno::EINVAL", "Errno", "ArgumentError"], :mappings=>"AAAAA,kCAAAA,gBAAAA;EAAAA;;EAAAA,OAAAC;EAAAA;;IAAAA;;;IACEC,kBAAc;IACdC,MAAIC,IAAJD,yBAAAA,8BAA4BE,IAAD,EAAOC,IAAlCH;AAAAA,MAAAA;AAAAA;;;MACEC,IAAAG,WAAAA,CAAUF,IAAV,EAAgBH,eAAWM,MAAAA,CAAAA,CAA3BD;MACAJ,OAAAD,eAAYO,OAAAA,CAAGH,IAAHG;IAFdN,CAAAA;IAKAC,IAAAD,oBAAAA,CAAmB,gBAAnB,EAAqCF,gCAArCE;IAEAO,YAAY;;AAGdT;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;IAEE,IAAA,QAAmDS,SAAnD,CAAA;MAAAN,IAAAD,oBAAAA,CAAmB,iBAAnB,EAAqCO,SAArCP;IAAA;IAEAQ,MAAIP,IAAJO,UAAAA,YACEC,CADFD,CAAAA;IAIAE,MAAIT,IAAJS,YAAAA,iBAAAA;AAAAA,MAAAA;;;MACEC,IAAIC,WAAMC,KAAAA,CAAAA,CAAIC,MAAAA,CAAAA;MACdJ,OAAAK,IAAAC,gBAAAD,QAAgBE,KAAAA,CAAKN,CAArB,EAAwBA,CAAxB,EAA2BA,CAA3B,EAA8BA,CAA9B,EAAiCA,CAAjBM;IAFlBP,CAAAA;IAKAZ,OAAAoB,MAAIjB,IAAJiB,oBAAAA,yBAAuBC,QAAD,EAAWC,IAAjCF;AAAAA,MAAAA;AAAAA;;;MAAiC,yBAAO;MACtC,IAAA,QAAAG,CAAAA,YAACC,CAAAA,QAAQvB,eAAWwB,OAAAA,CAACJ,QAADI,CAAnBD,CAADD,CAAA,CAAA;QAAA;MAAA;QAAmCG,OAAQC,OAAAA,CAAOC,IAAAC,YAAAD,WAAf,EAAiCR,gBAAD,GAAA,CAAiBC,QAAjB,CAAA,GAA0BD,IAA1B,GAAA,CAA8BnB,eAAWwB,OAAAA,CAACJ,QAADI,CAAzC,CAAxBE;MAA3C;;AAEJP;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA,iBAAmBM,OAAQC,OAAAA,CAAOG,oBAAf,EAAiCV,mBAAD,GAAA,CAAoBE,IAApB,CAAxBK;AAC3BP;AACAA;IAdEA,CAAAA,IAAAA;EAxCFpB,GAAO,IAAPA;AAAAD;"}}, {:offset=>{:line=>24145, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/random/formatter.rb"], :sourcesContent=>["class ::Random\n  module self::Formatter\n    def hex(count = nil)\n      count = ::Random._verify_count(count)\n      %x{\n        var bytes = \#{bytes(count)};\n        var out = \"\";\n        for (var i = 0; i < \#{count}; i++) {\n          out += bytes.charCodeAt(i).toString(16).padStart(2, '0');\n        }\n        return \#{`out`.encode('US-ASCII')};\n      }\n    end\n\n    def random_bytes(count = nil)\n      bytes(count)\n    end\n\n    def base64(count = nil)\n      ::Base64.strict_encode64(random_bytes(count)).encode('US-ASCII')\n    end\n\n    def urlsafe_base64(count = nil, padding = false)\n      ::Base64.urlsafe_encode64(random_bytes(count), padding).encode('US-ASCII')\n    end\n\n    def uuid\n      str = hex(16).split('')\n      str[12] = '4'\n      str[16] = `(parseInt(\#{str[16]}, 16) & 3 | 8).toString(16)`\n      str = [str[0...8], str[8...12], str[12...16], str[16...20], str[20...32]]\n      str = str.map(&:join)\n      str.join('-')\n    end\n\n    # Implemented in terms of `#bytes` for SecureRandom, but Random overrides this\n    # method to implement `#bytes` in terms of `#random_float`. Not part of standard\n    # Ruby interface - use random_number for portability.\n    def random_float\n      bs = bytes(4)\n      num = 0\n      4.times do |i|\n        num <<= 8\n        num |= bs[i].ord\n      end\n      num.abs / 0x7fffffff\n    end\n\n    def random_number(limit = undefined)\n      %x{\n        function randomFloat() {\n          return \#{random_float};\n        }\n\n        function randomInt(max) {\n          return Math.floor(randomFloat() * max);\n        }\n\n        function randomRange() {\n          var min = limit.begin,\n              max = limit.end;\n\n          if (min === nil || max === nil) {\n            return nil;\n          }\n\n          var length = max - min;\n\n          if (length < 0) {\n            return nil;\n          }\n\n          if (length === 0) {\n            return min;\n          }\n\n          if (max % 1 === 0 && min % 1 === 0 && !limit.excl) {\n            length++;\n          }\n\n          return randomInt(length) + min;\n        }\n\n        if (limit == null) {\n          return randomFloat();\n        } else if (limit.$$is_range) {\n          return randomRange();\n        } else if (limit.$$is_number) {\n          if (limit <= 0) {\n            \#{::Kernel.raise ::ArgumentError, \"invalid argument - \#{limit}\"}\n          }\n\n          if (limit % 1 === 0) {\n            // integer\n            return randomInt(limit);\n          } else {\n            return randomFloat() * limit;\n          }\n        } else {\n          limit = \#{::Opal.coerce_to!(limit, ::Integer, :to_int)};\n\n          if (limit <= 0) {\n            \#{::Kernel.raise ::ArgumentError, \"invalid argument - \#{limit}\"}\n          }\n\n          return randomInt(limit);\n        }\n      }\n    end\n\n    def alphanumeric(count = nil)\n      count = Random._verify_count(count)\n      map = ['0'..'9', 'a'..'z', 'A'..'Z'].map(&:to_a).flatten\n      ::Array.new(count) do |i|\n        map[random_number(map.length)]\n      end.join\n    end\n  end\n\n  include ::Random::Formatter\n  extend ::Random::Formatter\nend\n"], :names=>["<top (required)>", "<class:Random>", "<module:self::Formatter>", "hex", "count", "Random", "_verify_count", "self", "bytes", "encode", "random_bytes", "base64", "Base64", "strict_encode64", "urlsafe_base64", "padding", "urlsafe_encode64", "uuid", "str", "16", "split", "[]=", "12", "[]", "0", "8", "20", "32", "map", "to_proc", "join", "random_float", "bs", "4", "num", "times", "block in random_float", "i", "<<", "block (2 levels) in random_float", "|", "ord", "/", "abs", "2147483647", "random_number", "limit", "Kernel", "raise", "ArgumentError", "Opal", "coerce_to!", "Integer", "alphanumeric", "flatten", "new", "Array", "block in alphanumeric", "block (2 levels) in alphanumeric", "length", "include", "Random::Formatter", "extend"], :mappings=>"AAAAA,2CAAAA,gBAAAA;EAAAA;;EAAAA,OAAAC;EAAAA;;IAAAA;;;IACEC;IAAAA;;MAAAA;;;;AACEC,MAAAA,mBAAAA,eAAQC,KAARD;AAAAA,QAAAA;;;QAAQ,2BAAQ;QACdC,QAAQC,aAAQC,eAAAA,CAAeF,KAAfE;;AAEtBH,oBAAsBI,IAAAC,OAAAA,CAAMJ,KAANI,CAAaL;AACnCA;AACAA,4BAA8BC,KAAMD;AACpCA;AACAA;AACAA,eAAiBA,CAACA,GAADA,CAAKM,QAAAA,CAAQN,UAARM,CAAoBN;AAC1CA;MATIA,CAAAA,IAAAA;;AAYAO,MAAAA,4BAAAA,wBAAiBN,KAAjBM;AAAAA,QAAAA;;;QAAiB,2BAAQ;QACvBA,OAAAH,IAAAC,OAAAA,CAAMJ,KAANI;MADFE,CAAAA,IAAAA;;AAIAC,MAAAA,sBAAAA,kBAAWP,KAAXO;AAAAA,QAAAA;;;QAAW,2BAAQ;QACjBA,OAAAC,aAAQC,iBAAAA,CAAiBN,IAAAG,cAAAA,CAAaN,KAAbM,CAAjBG,CAAqCJ,QAAAA,CAAQE,UAARF;MAD/CE,CAAAA,IAAAA;;AAIAG,MAAAA,8BAAAA,0BAAmBV,KAAD,EAAcW,OAAhCD;AAAAA,QAAAA;;;QAAmB,2BAAQ;QAAK,+BAAU;QACxCA,OAAAF,aAAQI,kBAAAA,CAAkBT,IAAAG,cAAAA,CAAaN,KAAbM,CAA1B,EAA+CK,OAAvCC,CAA+CP,QAAAA,CAAQK,UAARL;MADzDK,CAAAA,IAAAA;;AAIAG,MAAAA,oBAAAA,gBAAAA;AAAAA,QAAAA;;;QACEC,MAAMX,IAAAJ,KAAAA,CAAIgB,EAAJhB,CAAOiB,OAAAA,CAAOH,EAAPG;QACbF,GAAGG,QAAAA,CAACC,EAAJ,EAAUL,GAAPI;QACHH,GAAGG,QAAAA,CAACF,EAAJ,EAAWF,UAAYC,GAAGK,OAAAA,CAACJ,EAADI,CAAKN,2BAA