ARD;IACA3D,OAAAM,IAAAuD,QAAAA,CAAOD,IAAAxD,aAAAwD,cAAPC;EAxHF7D,GAAM,IAANA,EAAAA,IAAAA;AAAAD;"}}, {:offset=>{:line=>24312, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/random/mersenne_twister.rb"], :sourcesContent=>["# This is based on an adaptation of Makoto Matsumoto and Takuji Nishimura's code\n# done by Sean McCullough <banksean@gmail.com> and Dave Heitzman\n# <daveheitzman@yahoo.com>, subsequently readapted from an updated version of\n# ruby's random.c (rev c38a183032a7826df1adabd8aa0725c713d53e1c).\n#\n# The original copyright notice from random.c follows.\n#\n#   This is based on trimmed version of MT19937.  To get the original version,\n#   contact <http://www.math.sci.hiroshima-u.ac.jp/~m-mat/MT/emt.html>.\n#\n#   The original copyright notice follows.\n#\n#      A C-program for MT19937, with initialization improved 2002/2/10.\n#      Coded by Takuji Nishimura and Makoto Matsumoto.\n#      This is a faster version by taking Shawn Cokus's optimization,\n#      Matthe Bellew's simplification, Isaku Wada's real version.\n#\n#      Before using, initialize the state by using init_genrand(mt, seed)\n#      or init_by_array(mt, init_key, key_length).\n#\n#      Copyright (C) 1997 - 2002, Makoto Matsumoto and Takuji Nishimura,\n#      All rights reserved.\n#\n#      Redistribution and use in source and binary forms, with or without\n#      modification, are permitted provided that the following conditions\n#      are met:\n#\n#        1. Redistributions of source code must retain the above copyright\n#           notice, this list of conditions and the following disclaimer.\n#\n#        2. Redistributions in binary form must reproduce the above copyright\n#           notice, this list of conditions and the following disclaimer in the\n#           documentation and/or other materials provided with the distribution.\n#\n#        3. The names of its contributors may not be used to endorse or promote\n#           products derived from this software without specific prior written\n#           permission.\n#\n#      THIS SOFTWARE IS PROVIDED BY THE COPYRIGHT HOLDERS AND CONTRIBUTORS\n#      \"AS IS\" AND ANY EXPRESS OR IMPLIED WARRANTIES, INCLUDING, BUT NOT\n#      LIMITED TO, THE IMPLIED WARRANTIES OF MERCHANTABILITY AND FITNESS FOR\n#      A PARTICULAR PURPOSE ARE DISCLAIMED.  IN NO EVENT SHALL THE COPYRIGHT OWNER OR\n#      CONTRIBUTORS BE LIABLE FOR ANY DIRECT, INDIRECT, INCIDENTAL, SPECIAL,\n#      EXEMPLARY, OR CONSEQUENTIAL DAMAGES (INCLUDING, BUT NOT LIMITED TO,\n#      PROCUREMENT OF SUBSTITUTE GOODS OR SERVICES; LOSS OF USE, DATA, OR\n#      PROFITS; OR BUSINESS INTERRUPTION) HOWEVER CAUSED AND ON ANY THEORY OF\n#      LIABILITY, WHETHER IN CONTRACT, STRICT LIABILITY, OR TORT (INCLUDING\n#      NEGLIGENCE OR OTHERWISE) ARISING IN ANY WAY OUT OF THE USE OF THIS\n#      SOFTWARE, EVEN IF ADVISED OF THE POSSIBILITY OF SUCH DAMAGE.\n#\n#\n#      Any feedback is very welcome.\n#      http://www.math.keio.ac.jp/matumoto/emt.html\n#      email: matumoto@math.keio.ac.jp\nmersenne_twister = %x{(function() {\n  /* Period parameters */\n  var N = 624;\n  var M = 397;\n  var MATRIX_A = 0x9908b0df;      /* constant vector a */\n  var UMASK = 0x80000000;         /* most significant w-r bits */\n  var LMASK = 0x7fffffff;         /* least significant r bits */\n  var MIXBITS = function(u,v) { return ( ((u) & UMASK) | ((v) & LMASK) ); };\n  var TWIST = function(u,v) { return (MIXBITS((u),(v)) >>> 1) ^ ((v & 0x1) ? MATRIX_A : 0x0); };\n\n  function init(s) {\n    var mt = {left: 0, next: N, state: new Array(N)};\n    init_genrand(mt, s);\n    return mt;\n  }\n\n  /* initializes mt[N] with a seed */\n  function init_genrand(mt, s) {\n    var j, i;\n    mt.state[0] = s >>> 0;\n    for (j=1; j<N; j++) {\n      mt.state[j] = (1812433253 * ((mt.state[j-1] ^ (mt.state[j-1] >> 30) >>> 0)) + j);\n      /* See Knuth TAOCP Vol2. 3rd Ed. P.106 for multiplier. */\n      /* In the previous versions, MSBs of the seed affect   */\n      /* only MSBs of the array state[].                     */\n      /* 2002/01/09 modified by Makoto Matsumoto             */\n      mt.state[j] &= 0xffffffff;  /* for >32 bit machines */\n    }\n    mt.left = 1;\n    mt.next = N;\n  }\n\n  /* generate N words at one time */\n  function next_state(mt) {\n    var p = 0, _p = mt.state;\n    var j;\n\n    mt.left = N;\n    mt.next = 0;\n\n    for (j=N-M+1; --j; p++)\n      _p[p] = _p[p+(M)] ^ TWIST(_p[p+(0)], _p[p+(1)]);\n\n    for (j=M; --j; p++)\n      _p[p] = _p[p+(M-N)] ^ TWIST(_p[p+(0)], _p[p+(1)]);\n\n    _p[p] = _p[p+(M-N)] ^ TWIST(_p[p+(0)], _p[0]);\n  }\n\n  /* generates a random number on [0,0xffffffff]-interval */\n  function genrand_int32(mt) {\n    /* mt must be initialized */\n    var y;\n\n    if (--mt.left <= 0) next_state(mt);\n    y = mt.state[mt.next++];\n\n    /* Tempering */\n    y ^= (y >>> 11);\n    y ^= (y << 7) & 0x9d2c5680;\n    y ^= (y << 15) & 0xefc60000;\n    y ^= (y >>> 18);\n\n    return y >>> 0;\n  }\n\n  function int_pair_to_real_exclusive(a, b) {\n    a >>>= 5;\n    b >>>= 6;\n    return(a*67108864.0+b)*(1.0/9007199254740992.0);\n  }\n\n  // generates a random number on [0,1) with 53-bit resolution\n  function genrand_real(mt) {\n    /* mt must be initialized */\n    var a = genrand_int32(mt), b = genrand_int32(mt);\n    return int_pair_to_real_exclusive(a, b);\n  }\n\n  return { genrand_real: genrand_real, init: init };\n})()}\n\nclass ::Random\n  `var MAX_INT = Number.MAX_SAFE_INTEGER || Math.pow(2, 53) - 1`\n\n  self::MERSENNE_TWISTER_GENERATOR = `{\n    new_seed: function() { return Math.round(Math.random() * MAX_INT); },\n    reseed: function(seed) { return mersenne_twister.init(seed); },\n    rand: function(mt) { return mersenne_twister.genrand_real(mt); }\n  }`\n\n  self.generator = self::MERSENNE_TWISTER_GENERATOR\nend\n"], :names=>["<top (required)>", "mersenne_twister", "<class:Random>", "self", "generator=", "self::MERSENNE_TWISTER_GENERATOR"], :mappings=>"AAAAA,kDAAAA,gBAAAA;EAAAA;;;EAsDAC,mBAAsBD;AACtBA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;EAEAA,OAAAE;EAAAA;;IAAAA;;;IACGA;IAED,WAAAC,IAAA,gCAAoCD;AACtCA;AACAA;AACAA;AACAA,GAJE;IAMAA,OAAIE,MAAAA,CAAaC,IAAAF,IAAAE,+BAAbD,CAAAA,EAAAA,MAAJD,IAAIC,cAAAA,EAAAA,EAAAA,CAAAA,EAAAA;EATNF,GAAM,IAANA,EAAAA,IAAAA;AAxIAF;"}}, {:offset=>{:line=>24413, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["corelib/random.rb"], :sourcesContent=>["# helpers: truthy\n\nrequire 'corelib/random/formatter'\n\nclass ::Random\n  attr_reader :seed, :state\n\n  def self._verify_count(count)\n    %x{\n      if (!$truthy(count)) count = 16;\n      if (typeof count !== \"number\") count = \#{`count`.to_int};\n      if (count < 0) \#{::Kernel.raise ::ArgumentError, 'negative string size (or size too big)'};\n      count = Math.floor(count);\n      return count;\n    }\n  end\n\n  def initialize(seed = ::Random.new_seed)\n    seed = ::Opal.coerce_to!(seed, ::Integer, :to_int)\n    @state = seed\n    reseed(seed)\n  end\n\n  def reseed(seed)\n    @seed = seed\n    `self.$rng = Opal.$$rand.reseed(seed)`\n  end\n\n  def self.new_seed\n    `Opal.$$rand.new_seed()`\n  end\n\n  def self.rand(limit = undefined)\n    self::DEFAULT.rand(limit)\n  end\n\n  def self.srand(n = ::Random.new_seed)\n    n = ::Opal.coerce_to!(n, ::Integer, :to_int)\n\n    previous_seed = self::DEFAULT.seed\n    self::DEFAULT.reseed(n)\n    previous_seed\n  end\n\n  def self.urandom(size)\n    ::SecureRandom.bytes(size)\n  end\n\n  def ==(other)\n    return false unless ::Random === other\n\n    seed == other.seed && state == other.state\n  end\n\n  def bytes(length)\n    length = ::Random._verify_count(length)\n\n    ::Array.new(length) { rand(255).chr }.join.encode('ASCII-8BIT')\n  end\n\n  def self.bytes(length)\n    self::DEFAULT.bytes(length)\n  end\n\n  def rand(limit = undefined)\n    random_number(limit)\n  end\n\n  # Not part of the Ruby interface (use #random_number for portability), but\n  # used by Random::Formatter as a shortcut, as for Random interface the float\n  # RNG is primary.\n  def random_float\n    %x{\n      self.state++;\n      return Opal.$$rand.rand(self.$rng);\n    }\n  end\n\n  def self.random_float\n    self::DEFAULT.random_float\n  end\n\n  def self.generator=(generator)\n    `Opal.$$rand = \#{generator}`\n\n    if const_defined? :DEFAULT\n      self::DEFAULT.reseed\n    else\n      const_set :DEFAULT, new(new_seed)\n    end\n  end\nend\n\nrequire 'corelib/random/mersenne_twister'\n"], :names=>["<top (required)>", "self", "require", "<class:Random>", "attr_reader", "_verify_count", "count", "to_int", "Kernel", "raise", "ArgumentError", "initialize", "seed", "Random", "new_seed", "Opal", "coerce_to!", "Integer", "@state", "reseed", "@seed", "rand", "limit", "self::DEFAULT", "srand", "n", "previous_seed", "urandom", "size", "SecureRandom", "bytes", "==", "other", "$ret_or_1", "state", "length", "new", "Array", "block in bytes", "block (2 levels) in bytes", "255", "chr", "join", "encode", "random_number", "random_float", "generator=", "generator", "const_defined?", "const_set"], :mappings=>"AAAAA,iCAAAA,gBAAAA;EAAAA;;;EAEAC,IAAAC,SAAAA,CAAQF,0BAARE;EAEAC;EAAAA;;;;IACEF,IAAAG,aAAAA,CAAY,MAAZ,EAAmB,OAAnBA;IAEAC,MAAIJ,IAAJI,oBAAAA,yBAAuBC,KAAvBD;AAAAA;;AAEFA;AACAA,6CAA+CA,CAACA,KAADA,CAAOE,QAAAA,CAAAA,CAAQF;AAC9DA,qBAAuBG,OAAQC,OAAAA,CAAOC,oBAAf,EAAgCL,wCAAxBI,CAAiEJ;AAChGA;AACAA;AACAA;IAPEA,CAAAA;;AAUAM,IAAAA,0BAAAA,sBAAeC,IAAfD;AAAAA,MAAAA;;;MAAe,yBAAOE,aAAQC,UAAAA,CAAAA;MAC5BF,OAAOG,KAAMC,eAAAA,CAAYJ,IAAlB,EAAwBK,cAAxB,EAAmC,QAA7BD;MACbE,aAASN;MACTD,OAAAV,IAAAkB,QAAAA,CAAOP,IAAPO;IAHFR,CAAAA,IAAAA;;AAMAQ,IAAAA,