lic_class_method private_class_method\n  alias public_instance_method instance_method\n  alias public_instance_methods instance_methods\n  alias public_method_defined? method_defined?\nend\n\nmodule ::Kernel\n  def private_methods(*methods)\n    []\n  end\n\n  alias protected_methods private_methods\n  alias private_instance_methods private_methods\n  alias protected_instance_methods private_methods\nend\n\nmodule ::Kernel\n  def eval(*)\n    ::Kernel.raise ::NotImplementedError, \"To use Kernel#eval, you must first require 'opal-parser'. \"\\\n                                          \"See https://github.com/opal/opal/blob/\#{RUBY_ENGINE_VERSION}/docs/opal_parser.md for details.\"\n  end\nend\n\ndef self.public(*methods)\n  `return (methods.length === 1) ? methods[0] : methods`\nend\n\ndef self.private(*methods)\n  `return (methods.length === 1) ? methods[0] : methods`\nend\n"], :names=>["<top (required)>", "Kernel", "raise", "NotImplementedError", "self", "warn", "<class:String>", "each", "block in <class:String>", "method_name", "block (2 levels) in <class:String>", "define_method", "block (3 levels) in <class:String>", "%", "<module:Kernel>", "taint", "untaint", "tainted?", "<class:Module>", "public", "private_class_method", "private_method_defined?", "private_constant", "private_methods", "eval", "RUBY_ENGINE_VERSION", "private"], :mappings=>"AAAAA,sCAAAA,gBAAAA;EAAAA;;;;AACAA;;AAEAA;AACAA;AACAA;AACAA,MAAQC,OAAQC,OAAAA,CAAOC,0BAAf,EAAuCH,OAA/BE;AAChBF;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;;AAEAA;AACAA,IAAMI,IAAAC,MAAAA,CAAML,MAANK,CAAeL;AACrBA;;EAGAM;EAAAA;;;;IACGA;IAEDA,OAICC,MAJD,CACE,IADF,EACK,aADL,EACiB,QADjB,EACwB,OADxB,EAC8B,WAD9B,EACwC,OADxC,EAC8C,SAD9C,EACsD,OADtD,EAC4D,UAD5D,EAEE,QAFF,EAES,UAFT,EAEkB,QAFlB,EAEyB,MAFzB,EAE8B,OAF9B,EAEoC,WAFpC,EAE8C,KAF9C,EAEkD,OAFlD,EAEwD,SAFxD,EAEgE,SAFhE,EAGE,KAHF,EAGM,OAHN,EAGY,SAHZ,EAGoB,oBAHpB,CAICA,QAAAA,EAAAA,EAAAA,EAJDC,mBAIWC,WAJXD,EAAAE;;;MAIW;MACTA,OAAAC,MAAAP,IAAAO,iBAAAA,EAAAA,