, @scope_variables, @receiver, @source_location = \\\n      jseval, scope_variables, receiver, source_location\n    receiver = js_eval('self') unless `typeof receiver !== undefined`\n  end\n\n  def js_eval(*args)\n    if @jseval\n      @jseval.call(*args)\n    else\n      ::Kernel.raise 'Evaluation on a Proc#binding is not supported'\n    end\n  end\n\n  def local_variable_get(symbol)\n    js_eval(symbol)\n  rescue ::Exception\n    ::Kernel.raise ::NameError, \"local variable `\#{symbol}' is not defined for \#{inspect}\"\n  end\n\n  def local_variable_set(symbol, value)\n    `Opal.Binding.tmp_value = value`\n    js_eval(\"\#{symbol} = Opal.Binding.tmp_value\")\n    `delete Opal.Binding.tmp_value`\n    value\n  end\n\n  def local_variables\n    @scope_variables\n  end\n\n  def local_variable_defined?(value)\n    @scope_variables.include?(value)\n  end\n\n  def eval(str, file = nil, line = nil)\n    return receiver if str == 'self'\n\n    ::Kernel.eval(str, self, file, line)\n  end\n\n  attr_reader :receiver, :source_location\nend\n\nmodule ::Kernel\n  def binding\n    ::Kernel.raise \"Opal doesn't support dynamic calls to binding\"\n  end\nend\n\nTOPLEVEL_BINDING = ::Binding.new(\n  %x{\n    function(js) {\n      return (new Function(\"self\", \"return \" + js))(self);\n    }\n  },\n  [], self, ['<main>', 0]\n)\n"], :names=>["<top (required)>", "<class:Binding>", "initialize", "jseval", "scope_variables", "receiver", "source_location", "@jseval", "@scope_variables", "@receiver", "@source_location", "self", "js_eval", "call", "args", "Kernel", "raise", "local_variable_get", "symbol", "Exception", "NameError", "inspect", "local_variable_set", "value", "local_variables", "local_variable_defined?", "include?", "eval", "str", "file", "line", "attr_reader", "<module:Kernel>", "binding", "Binding", "new", "0"], :mappings=>"AAAAA,kCAAAA,gBAAAA;EAAAA;;;EAAAC;EAAAA;;IAAAA;;AAAAA;;;AAEEC,IAAAA,0BAAAA,sBAAeC,MAAD,EAASC,eAAT,EAA+BC,QAA/B,EAAqDC,eAAnEJ;AAAAA,MAAAA;;;MAAuB,+CAAkB;;