tion, that opal-parser or\n# opal-replutils will not be loaded, in which case we will do what we can\n# to provision it.\n\nmodule Opal\n  module IRB\n    def self.ensure_loaded(library)\n      return if `Opal.loaded_features`.include? library\n\n      version = if RUBY_ENGINE_VERSION.include? 'dev'\n                  'master'\n                else\n                  RUBY_ENGINE_VERSION\n                end\n\n      url = \"https://cdn.opalrb.com/opal/\#{version}/\#{library}.js\"\n\n      %x{\n        var libcode;\n\n        if (typeof XMLHttpRequest !== 'undefined') { // Browser\n          var r = new XMLHttpRequest();\n          r.open(\"GET\", url, false);\n          r.send('');\n          libcode = r.responseText;\n        }\n        else {\n          \#{::Kernel.raise \"You need to provision \#{library} yourself in this environment\"}\n        }\n\n        (new Function('Opal', libcode))(Opal);\n\n        Opal.require(library);\n      }\n\n      ::Kernel.raise \"Could not load \#{library} for some reason\" unless `Opal.loaded_features`.include? library\n    end\n\n    singleton_class.attr_accessor :output\n\n    def self.prepare_console(&block)\n      self.output = ''\n\n      original = {\n        $stdout => ->(i) { $stdout = i },\n        $stderr => ->(i) { $stderr = i },\n      }\n\n      # Prepare a better prompt experience for a browser\n      if browser?\n        original.each do |pipe, pipe_setter|\n          new_pipe = pipe.dup\n          new_pipe.write_proc = proc do |str|\n            self.output += str\n            self.output = output.split(\"\\n\").last(30).join(\"\\n\")\n            self.output += \"\\n\" if str.end_with? \"\\n\"\n\n            pipe.write_proc.call(str)\n          end\n          new_pipe.tty = false\n          pipe_setter.call(new_pipe)\n        end\n\n        original_read_proc = $stdin.read_proc\n        $stdin.read_proc = `function(s) { var p = prompt(\#{output}); if (p !== null) return p + \"\\n\"; return nil; }`\n      end\n\n      yield\n    ensure\n      original.each do |pipe, pipe_setter|\n        pipe_setter.call(pipe)\n      end\n      $stdin.read_proc = original_read_proc\n      self.output = ''\n    end\n\n    def self.browser?\n      `typeof(document) !== 'undefined' && typeof(prompt) !== 'undefined'`\n    end\n\n    LINEBREAKS = [\n      'unexpected token $end',\n      'unterminated string meets end of file'\n    ].freeze\n\n    class Silencer\n      def initialize\n        @stderr = $stderr\n      end\n\n      def silence\n        @collector = ::StringIO.new\n        $stderr = @collector\n        yield\n      ensure\n        $stderr = @stderr\n      end\n\n      def warnings\n        @collector.string\n      end\n    end\n  end\nend\n\nclass ::Binding\n  def irb\n    ::Opal::IRB.ensure_loaded('opal-replutils')\n\n    silencer = ::Opal::IRB::Silencer.new\n\n    ::Opal::IRB.prepare_console do\n      loop do\n        print '>> '\n        line = gets\n        break unless line\n        code = ''\n\n        puts line if ::Opal::IRB.browser?\n\n        if line.start_with? 'ls '\n          code = line[3..-1]\n          mode = :ls\n        elsif line == \"ls\\n\"\n          code = 'self'\n          mode = :ls\n        elsif line.start_with? 'show '\n          code = line[5..-1]\n          mode = :show\n        else\n          code = line\n          mode = :inspect\n        end\n\n        js_code = nil\n\n        begin\n          silencer.silence do\n            js_code = `Opal.compile(code, {irb: true})`\n          end\n        rescue SyntaxError => e\n          if ::Opal::IRB::LINEBREAKS.include?(e.message)\n            print '.. '\n            line = gets\n            return unless line\n            puts line if ::Opal::IRB.browser?\n            code += line\n            retry\n          elsif silencer.warnings.empty?\n            warn e.full_message\n          else\n            # Most likely a parser error\n            warn silencer.warnings\n          end\n        end\n\n        if mode == :show\n          puts js_code\n          return\n        end\n\n        puts ::REPLUtils.eval_and_print(js_code, mode, false, self)\n      end\n    end\n  end\nend\n\n%x{\n  // Run in WebTools console with: Opal.irb(c => eval(c))\n  Opal.irb = function(fun) {\n    \#{::Binding.new(`fun`).irb}\n  }\n\n  Opal.load_parser = function() {\n    Opal.Opal.IRB.$ensure_loaded('opal-parser');\n  }\n\n  if (typeof Opal.eval === 'undefined') {\n    Opal.eval = function(str) {\n      Opal.load_parser();\n      return Opal.eval(str);\n    }\n  }\n\n  if (typeof Opal.compile === 'undefined') {\n    Opal.compile = function(str, options) {\n      Opal.load_parser();\n      return Opal.compile(str, options);\n    }\n  }\n}\n"], :names=>["<top (required)>", "<module:Opal>", "<module:IRB>", "ensure_loaded", "self", "library", "include?", "version", "RUBY_ENGINE_VERSION", "url", "Kernel", "raise", "singleton_class", "attr_accessor", "prepare_console", "output=", "original", "$stdout", "block in prepare_console", "i", "block (2 levels) in prepare_console", "$stderr", "browser?", "each", "pipe", "pipe_setter", "new_pipe", "dup", "write_proc=", "proc", "str", "block (3 levels) in prepare_console", "+", "output", "split", "last", "30", "join", "end_with?", "write_proc", "call", "tty=", "original_read_proc", "$stdin", "read_proc", "read_proc=", "freeze", "<class:Silencer>", "initialize", "@stderr", "silence", "@collector", "StringIO", "new", "warnings", "string", "<class:Binding>", "irb", "Opal::IRB", "Opal", "silencer", "Opal::IRB::Silencer", "block in irb", "block (2 levels) in irb", "loop", "block (3 levels) in irb", "print", "line", "gets", "code", "puts", "start_with?", "[]", "3", "-1", "mode", "5", "js_code", "block (4 levels) in irb", "SyntaxError", "e", "Opal::IRB::LINEBREAKS", "message", "empty?", "warn", "full_message", "REPLUtils", "eval_and_print", "Binding"], :mappings=>"AAAAA,8BAAAA,gBAAAA;EAAAA;;;EAKAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;;MACEC,MAAIC,IAAJD,oBAAA