uire", "autoload"], :mappings=>"AAAAA,2BAAAA;EAAAA;;;EAAAC,OAAQC,SAAAA,CAASF,WAATE;EACRD,OAAQC,SAAAA,CAASF,WAATE;EAERD,OAAQC,SAAAA,CAASF,uBAATE;EACRD,OAAQC,SAAAA,CAASF,yBAATE;EACRD,OAAQE,UAAAA,CAAU,MAAlB,EAAyBH,cAAjBG;EACRF,OAAQC,SAAAA,CAASF,sBAATE;EACRD,OAAQE,UAAAA,CAAU,SAAlB,EAA4BH,iBAApBG;EACRF,OAAQC,SAAAA,CAASF,uBAATE;EACRD,OAAQE,UAAAA,CAAU,UAAlB,EAA6BH,kBAArBG;EACRF,OAAQC,SAAAA,CAASF,cAATE;EACRD,OAAQE,UAAAA,CAAU,QAAlB,EAA2BH,gBAAnBG;EACRF,OAAQE,UAAAA,CAAU,KAAlB,EAAwBH,aAAhBG;EACRF,OAAQE,UAAAA,CAAU,KAAlB,EAAwBH,aAAhBG;EACRF,OAAQE,UAAAA,CAAU,MAAlB,EAAyBH,cAAjBG;EAERF,OAAQC,SAAAA,CAASF,sBAATE;EACRD,OAAQE,UAAAA,CAAU,SAAlB,EAA4BH,iBAApBG;EACRF,OAAQE,UAAAA,CAAU,QAAlB,EAA2BH,gBAAnBG;EAERF,OAAQC,SAAAA,CAASF,qBAATE;EAERD,OAAQC,SAAAA,CAASF,iBAATE;EACRF,OAAAC,OAAQC,SAAAA,CAASF,aAATE;AAvBRF;"}}, {:offset=>{:line=>25097, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["./native.rb"], :sourcesContent=>["# Provides a complete set of tools to wrap native JavaScript\n# into nice Ruby objects.\n#\n# @example\n#\n#   $$.document.querySelector('p').classList.add('blue')\n#   # => adds \"blue\" class to <p>\n#\n#   $$.location.href = 'https://google.com'\n#   # => changes page location\n#\n#   do_later = $$[:setTimeout] # Accessing the \"setTimeout\" property\n#   do_later.call(->{ puts :hello}, 500)\n#\n# `$$` and `$global` wrap `Opal.global`, which the Opal JS runtime\n# sets to the global `this` object.\n#\nmodule Native\n  def self.is_a?(object, klass)\n    %x{\n      try {\n        return \#{object} instanceof \#{try_convert(klass)};\n      }\n      catch (e) {\n        return false;\n      }\n    }\n  end\n\n  def self.try_convert(value, default = nil)\n    %x{\n      if (\#{native?(value)}) {\n        return \#{value};\n      }\n      else if (\#{value.respond_to? :to_n}) {\n        return \#{value.to_n};\n      }\n      else {\n        return \#{default};\n      }\n    }\n  end\n\n  def self.convert(value)\n    %x{\n      if (\#{native?(value)}) {\n        return \#{value};\n      }\n      else if (\#{value.respond_to? :to_n}) {\n        return \#{value.to_n};\n      }\n      else {\n        \#{raise ArgumentError, \"\#{value.inspect} isn't native\"};\n      }\n    }\n  end\n\n  def self.call(obj, key, *args, &block)\n    %x{\n      var prop = \#{obj}[\#{key}];\n\n      if (prop instanceof Function) {\n        var converted = new Array(args.length);\n\n        for (var i = 0, l = args.length; i < l; i++) {\n          var item = args[i],\n              conv = \#{try_convert(`item`)};\n\n          converted[i] = conv === nil ? item : conv;\n        }\n\n        if (block !== nil) {\n          converted.push(block);\n        }\n\n        return \#{Native(`prop.apply(\#{obj}, converted)`)};\n      }\n      else {\n        return \#{Native(`prop`)};\n      }\n    }\n  end\n\n  def self.proc(&block)\n    raise LocalJumpError, 'no block given' unless block\n\n    ::Kernel.proc { |*args|\n      args.map! { |arg| Native(arg) }\n      instance = Native(`this`)\n\n      %x{\n        // if global is current scope, run the block in the scope it was defined\n        if (this === Opal.global) {\n          return block.apply(self, \#{args});\n        }\n\n        var self_ = block.$$s;\n        block.$$s = null;\n\n        try {\n          return block.apply(\#{instance}, \#{args});\n        }\n        finally {\n          block.$$s = self_;\n        }\n      }\n    }\n  end\n\n  module Helpers\n    # Exposes a native JavaScript method to Ruby\n    #\n    #\n    # @param new [String]\n    #       The name of the newly created method.\n    #\n    # @param old [String]\n    #       The name of the native JavaScript method to be exposed.\n    #       If the name ends with \"=\" (e.g. `foo=`) it will be interpreted as\n    #       a property setter. (default: the value of \"new\")\n    #\n    # @param as [Class]\n    #       If provided the values returned by the original method will be\n    #       returned as instances of the passed class. The class passed to \"as\"\n    #       is expected to accept a native JavaScript value.\n    #\n    # @example\n    #\n    #   class Element\n    #     extend Native::Helpers\n    #\n    #     alias_native :add_class, :addClass\n    #     alias_native :show\n    #     alias_native :hide\n    #\n    #     def initialize(selector)\n    #       @native = `$(\#{selector})`\n    #     end\n    #   end\n    #\n    #   titles = Element.new('h1')\n    #   titles.add_class :foo\n    #   titles.hide\n    #   titles.show\n    #\n    def alias_native(new, old = new, as: nil)\n      if old.end_with? '='\n        define_method new do |value|\n          `\#{@native}[\#{old[0..-2]}] = \#{Native.convert(value)}`\n\n          value\n        end\n      elsif as\n        define_method new do |*args, &block|\n          value = Native.call(@native, old, *args, &block)\n          if value\n            as.new(value.to_n)\n          end\n        end\n      else\n        define_method new do |*args, &block|\n          Native.call(@native, old, *args, &block)\n        end\n      end\n    end\n\n    def native_reader(*names)\n      names.each do |name|\n        define_method name do\n          Native(`\#{@native}[name]`)\n        end\n      end\n    end\n\n    def native_writer(*names)\n      names.each do |name|\n        define_method \"\#{name}=\" do |value|\n          Native(`\#{@native}[name] = value`)\n        end\n      end\n    end\n\n    def native_accessor(*names)\n      native_reader(*names)\n      native_writer(*names)\n    end\n  end\n\n  module Wrapper\n    def initialize(native)\n      unless ::Kernel.native?(native)\n        ::Kernel.raise ArgumentError, \"\#{native.inspect} isn't native\"\n      end\n\n      @native = native\n    end\n\n    # Returns the internal native JavaScript value\n    def to_n\n      @native\n    end\n\n    def self.included(klass)\n      klass.extend Helpers\n    end\n  end\n\n  def self.included(base)\n    warn 'Including ::Native is deprecated. Please include Native::Wrapper instead.'\n    base.include Wrapper\n  end\nend\n\nmodule Kernel\n  def native?(value)\n    `value == null || !value.$$class`\n  end\n\n  # Wraps a native JavaScript with `Native::Object.new`\n  #\n  # @return [Native::Object] The wrapped object if it is native\n  # @return [nil] for `null` and `undefined`\n  # @return [obj] The object itself if it's not native\n  def Native(obj)\n    if `\#{obj} == null`\n      nil\n    elsif native?(obj)\n      Native::Object.new(obj)\n    elsif obj.is_a?(Array)\n      obj.map do |o|\n        Native(o)\n      end\n    elsif obj.is_a?(Proc)\n      proc do |*args, &block|\n        Native(obj.call(*args, &block))\n      end\n    else\n      obj\n    end\n  end\n\n  alias _Array Array\n\n  # Wraps array-like JavaScript objects in Native::Array\n  def Array(object, *args, &block)\n    if native?(object)\n      return Native::Array.new(object, *args, &block).to_a\n    end\n    _Array(object)\n  end\nend\n\nclass Native::Object < BasicObject\n  include ::Native::Wrapper\n\n  def ==(other)\n    `\#{@native} === \#{::Native.try_convert(other)}`\n  end\n\n  def has_key?(name)\n    `Opal.hasOwnProperty.call(\#{@native}, \#{name})`\n  end\n\n  def each(*args)\n    if block_given?\n      %x{\n        for (var key in \#{@native}) {\n          \#{yield `key`, `\#{@native}[key]`}\n        }\n      }\n\n      self\n    else\n      method_missing(:each, *args)\n    end\n  end\n\n  def [](key)\n    %x{\n      var prop = \#{@native}[key];\n\n      if (prop instanceof Function) {\n        return prop;\n      }\n      else {\n        return \#{::Native.call(@native, key)}\n      }\n    }\n  end\n\n  def []=(key, value)\n    native = ::Native.try_convert(value)\n\n    if `\#{native} === nil`\n      `\#{@native}[key] = \#{value}`\n    else\n      `\#{@native}[key] = \#{native}`\n    end\n  end\n\n  def merge!(other)\n    %x{\n      other = \#{::Native.convert(other)};\n\n      for (var prop in other) {\n        \#{@native}[prop] = other[prop];\n      }\n    }\n\n    self\n  end\n\n  def respond_to?(name, include_all = false)\n    ::Kernel.instance_method(:respond_to?).bind(self).call(name, include_all)\n  end\n\n  def respond_to_missing?(name, include_all = false)\n    `Opal.hasOwnProperty.call(\#{@native}, \#{name})`\n  end\n\n  def method_missing(mid, *args, &block)\n    %x{\n      if (mid.charAt(mid.length - 1) === '=') {\n        return \#{self[mid.slice(0, mid.length - 1)] = args[0]};\n      }\n      else {\n        return \#{::Native.call(@native, mid, *args, &block)};\n      }\n    }\n  end\n\n  def nil?\n    false\n  end\n\n  def is_a?(klass)\n    `Opal.is_a(self, klass)`\n  end\n\n  def instance_of?(klass)\n    `self.$$class === klass`\n  end\n\n  def class\n    `self.$$class`\n  end\n\n  def to_a(options = {}, &block)\n    ::Native::Array.new(@native, options, &block).to_a\n  end\n\n  def inspect\n    \"#<Native:\#{`String(\#{@native})`}>\"\n  end\n\n  alias include? has_key?\n  alias key? has_key?\n  alias kind_of? is_a?\n  alias member? has_key?\nend\n\nclass Native::Array\n  include Native::Wrapper\n  include Enumerable\n\n  def initialize(native, options = {}, &block)\n    super(native)\n\n    @get    = options[:get] || options[:access]\n    @named  = options[:named]\n    @set    = options[:set] || options[:access]\n    @length = options[:length] || :length\n    @block  = block\n\n    if `\#{length} == null`\n      raise ArgumentError, 'no length found on the array-like object'\n    end\n  end\n\n  def each(&block)\n    return enum_for :each unless block\n\n    %x{\n      for (var i = 0, length = \#{length}; i < length; i++) {\n        Opal.yield1(block, \#{self[`i`]});\n      }\n    }\n\n    self\n  end\n\n  def [](index)\n    result = case index\n             when String, Symbol\n               @named ? `\#{@native}[\#{@named}](\#{index})` : `\#{@native}[\#{index}]`\n             when Integer\n               @get ? `\#{@native}[\#{@get}](\#{index})` : `\#{@native}[\#{index}]`\n             end\n\n    if result\n      if @block\n        @block.call(result)\n      else\n        Native(result)\n      end\n    end\n  end\n\n  def []=(index, value)\n    if @set\n      `\#{@native}[\#{@set}](\#{index}, \#{Native.convert(value)})`\n    else\n      `\#{@native}[\#{index}] = \#{Native.convert(value)}`\n    end\n  end\n\n  def last(count = nil)\n    if count\n      index  = length - 1\n      result = []\n\n      while index >= 0\n        result << self[index]\n        index  -= 1\n      end\n\n      result\n    else\n      self[length - 1]\n    end\n  end\n\n  def length\n    `\#{@native}[\#{@length}]`\n  end\n\n  def inspect\n    to_a.inspect\n  end\n\n  alias to_ary to_a\nend\n\nclass Numeric\n  # @return the internal JavaScript value (with `valueOf`).\n  def to_n\n    `self.valueOf()`\n  end\nend\n\nclass Proc\n  # @return itself (an instance of `Function`)\n  def to_n\n    self\n  end\nend\n\nclass String\n  # @return the internal JavaScript value (with `valueOf`).\n  def to_n\n    `self.valueOf()`\n  end\nend\n\nclass Regexp\n  # @return the internal JavaScript value (with `valueOf`).\n  def to_n\n    `self.valueOf()`\n  end\nend\n\nclass MatchData\n  # @return the array of matches\n  def to_n\n    @matches\n  end\nend\n\nclass Struct\n  # @return a JavaScript object with the members as keys and their\n  # values as values.\n  def to_n\n    result = `{}`\n\n    each_pair do |name, value|\n      `\#{result}[\#{name}] = \#{Native.try_convert(value, value)}`\n    end\n\n    result\n  end\nend\n\nclass Array\n  # Retuns a copy of itself trying to call #to_n on each member.\n  def to_n\n    %x{\n      var result = [];\n\n      for (var i = 0, length = self.length; i < length; i++) {\n        var obj = self[i];\n\n        result.push(\#{Native.try_convert(`obj`, `obj`)});\n      }\n\n      return result;\n    }\n  end\nend\n\nclass Boolean\n  # @return the internal JavaScript value (with `valueOf`).\n  def to_n\n    `self.valueOf()`\n  end\nend\n\nclass Time\n  # @return itself (an instance of `Date`).\n  def to_n\n    self\n  end\nend\n\nclass NilClass\n  # @return the corresponding JavaScript value (`null`).\n  def to_n\n    `null`\n  end\nend\n\n# Running this code twice results in an infinite loop. While it's true\n# that we shouldn't run this file twice, there are certain cases, like\n# for example live reload, when this may happen.\nunless Hash.method_defined? :_initialize\n  class Hash\n    alias _initialize initialize\n\n    def initialize(defaults = undefined, &block)\n      %x{\n        if (defaults != null &&\n             (defaults.constructor === undefined ||\n               defaults.constructor === Object)) {\n          var smap = self.$$smap,\n              keys = self.$$keys,\n              key, value;\n\n          for (key in defaults) {\n            value = defaults[key];\n\n            if (value &&\n                 (value.constructor === undefined ||\n                   value.constructor === Object)) {\n              smap[key] = \#{Hash.new(`value`)};\n            } else if (value && value.$$is_array) {\n              value = value.map(function(item) {\n                if (item &&\n                     (item.constructor === undefined ||\n                       item.constructor === Object)) {\n                  return \#{Hash.new(`item`)};\n                }\n\n                return \#{Native(`item`)};\n              });\n              smap[key] = value\n            } else {\n              smap[key] = \#{Native(`value`)};\n            }\n\n            keys.push(key);\n          }\n\n          return self;\n        }\n\n        return \#{_initialize(defaults, &block)};\n      }\n    end\n\n    # @return a JavaScript object with the same keys but calling #to_n on\n    # all values.\n    def to_n\n      %x{\n        var result = {},\n            keys = self.$$keys,\n            smap = self.$$smap,\n            key, value;\n\n        for (var i = 0, length = keys.length; i < length; i++) {\n          key = keys[i];\n\n          if (key.$$is_string) {\n            value = smap[key];\n          } else {\n            key = key.key;\n            value = key.value;\n          }\n\n          result[key] = \#{Native.try_convert(`value`, `value`)};\n        }\n\n        return result;\n      }\n    end\n  end\nend\n\nclass Module\n  # Exposes the current module as a property of\n  # the global object (e.g. `window`).\n  def native_module\n    `Opal.global[\#{name}] = \#{self}`\n  end\nend\n\nclass Class\n  def native_alias(new_jsid, existing_mid)\n    %x{\n      var aliased = \#{self}.prototype[Opal.jsid(\#{existing_mid})];\n      if (!aliased) {\n        \#{raise NameError.new(\"undefined method `\#{existing_mid}' for class `\#{inspect}'\", existing_mid)};\n      }\n      \#{self}.prototype[\#{new_jsid}] = aliased;\n    }\n  end\n\n  def native_class\n    native_module\n    `self[\"new\"] = self.$new`\n  end\nend\n\n# Exposes the global value (would be `window` inside a browser)\n$$ = $global = Native(`Opal.global`)\n"], :names=>["<main>", "<module:Native>", "is_a?", "self", "object", "klass", "try_convert", "value", "default$", "native?", "respond_to?", "to_n", "convert", "raise", "ArgumentError", "inspect", "call", "obj", "key", "Native", "proc", "block", "LocalJumpError", "Kernel", "block in proc", "block (2 levels) in proc", "map!", "args", "arg", "block (3 levels) in proc", "instance", "<module:Helpers>", "alias_native", "new$", "old", "end_with?", "define_method", "block in alias_native", "block (2 levels) in alias_native", "@native", "[]", "0", "-2", "as", "to_proc", "new", "native_reader", "each", "names", "block in native_reader", "name", "block (2 levels) in native_reader", "block (3 levels) in native_reader", "native_writer", "block in native_writer", "block (2 levels) in native_writer", "block (3 levels) in native_writer", "native_accessor", "<module:Wrapper>", "initialize", "native$", "included", "extend", "Helpers", "base", "warn", "include", 