CAAFF,CAARtD;MAXN;IADF4E,CAAAA,IAAAA;;AAgBArB,IAAAA,sBAAAA,kBAAAA;AAAAA,MAAAA;;MACEA,OAAGxD,cAAQwD,CAAGa,WAAQb;IADxBA,CAAAA;;AAIAhF,IAAAA,uBAAAA,mBAAAA;AAAAA,MAAAA;;MACEA,OAAAZ,IAAA0E,MAAAA,CAAAA,CAAI9D,SAAAA,CAAAA;IADNA,CAAAA;IAIAuF,OAAA,aAAM,QAAN,EAAa,MAAb;EA/EFA,GAAMnF,YAANmF,EAAAA,IAAAA;EAkFAkB;EAAAA;;;IAEEA,OAAA7G,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAACA,cAADA;IADFA,CAAAA;EAFF6G,GAAAA,WAAAA,EAAAA,IAAAA;EAOAC;EAAAA;;;IAEEA,OAAA9G,oBAAAA,YAAAA;EAFF8G,GAAAA,WAAAA,EAAAA,IAAAA;EAOAC;EAAAA;;;IAEEA,OAAA/G,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAACA,cAADA;IADFA,CAAAA;EAFF+G,GAAAA,WAAAA,EAAAA,IAAAA;EAOAC;EAAAA;;;IAEEA,OAAAhH,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAACA,cAADA;IADFA,CAAAA;EAFFgH,GAAAA,WAAAA,EAAAA,IAAAA;EAOAC;EAAAA;;;IAEEA,OAAAjH,oBAAAA,aACE,SADFA,CAAAA;EAFFiH,GAAAA,WAAAA,EAAAA,IAAAA;EAOAC;EAAAA;;IAAAA;;IAGEA,OAAAlH,oBAAAA,gBAAAA;AAAAA,MAAAA;;;MACEqG,SAAUrG;MAEVmH,MAAA3H,IAAA2H,aAAAA,EAAAA,EAAAA,EAAAC,cAAc7E,IAAD,EAAO3C,KAApBwH;;QAAc;QAAM;QAClBC,OAAGhB,MAAOgB,CAAG9E,IAAK8E,IAAM7G,YAAMb,aAAAA,CAAaC,KAAnB,EAA0BA,KAApBD,EADhCyH,CAAAD;MAIAnH,OAAAqG;IAPFrG,CAAAA;EAHFkH,GAAAA,WAAAA,EAAAA,IAAAA;EAcAI;EAAAA;;IAAAA;;IAEEA,OAAAtH,oBAAAA,gBAAAA;AAAAA,MAAAA;;;AAEFA;;AAEAA;AACAA;;AAEAA,oBAAsBQ,YAAMb,aAAAA,CAAcK,GAApB,EAA2BA,GAArBL,CAA2BK;AACvDA;;AAEAA;AACAA;IAXEA,CAAAA;EAFFsH,GAAAA,WAAAA,EAAAA,IAAAA;EAiBAC;EAAAA;;;IAEEA,OAAAvH,oBAAAA,gBAAAA;AAAAA,MAAAA;;MACEA,OAACA,cAADA;IADFA,CAAAA;EAFFuH,GAAAA,WAAAA,EAAAA,IAAAA;EAOAC;EAAAA;;;IAEEA,OAAAxH,oBAAAA,YAAAA;EAFFwH,GAAAA,WAAAA,EAAAA,IAAAA;EAOAC;EAAAA;;;IAEEA,OAAAzH,oBAAAA,gBAAAA;AAAAA;MACEA,OAACA,IAADA;IADFA,CAAAA;EAFFyH,GAAAA,WAAAA,EAAAA,IAAAA;EAUA,KAAA,QAAOC,UAAIC,oBAAAA,CAAiB,aAAjBA,CAAX,CAAA;IACEC;IAAAA;;MAAAA;;;MACE,aAAM,aAAN,EAAkB,YAAlB;;AAEA5E,MAAAA,0BAAAA,sBAAe6E,QAAf7E;AAAAA,QAAAA;;QAAAA;;;;;AAEJA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;AACAA,0BAA4B0E,UAAIxF,KAAAA,CAAMc,KAANd,CAAcc;AAC9CA;AACAA;AACAA;AACAA;AACAA;AACAA,yBAA2B0E,UAAIxF,KAAAA,CAAMc,IAANd,CAAac;AAC5CA;;AAEAA,uBAAyBxD,IAAAgB,QAAAA,CAAQwC,IAARxC,CAAewC;AACxCA;AACAA;AACAA;AACAA,0BAA4BxD,IAAAgB,QAAAA,CAAQwC,KAARxC,CAAgBwC;AAC5CA;;AAEAA;AACAA;;AAEAA;AACAA;;AAEAA,eAAiB8E,MAAAtI,IAAAsI,eAAAA,EAAAA,CAAYD,QAAZC,CAAAA,EAAuBpH,KAADuB,SAAAA,CAAAA,CAAtB6F,CAA8B9E;AAC/CA;MAtCIA,CAAAA,IAAAA;MA2CA4E,OAAA5H,oBAAAA,gBAAAA;AAAAA,QAAAA;;;AAEJA;AACAA;AACAA;AACAA;;AAEAA;AACAA;;AAEAA;AACAA;AACAA;AACAA;AACAA;AACAA;;AAEAA,wBAA0BQ,YAAMb,aAAAA,CAAcK,KAApB,EAA6BA,KAAvBL,CAA+BK;AAC/DA;;AAEAA;AACAA;MArBIA,CAAAA;IA9CF4H,GAAAA,WAAAA,EAAAA,IAAAA;EADF;EAyEAG;EAAAA;;;IAGEA,OAAAC,6BAAAA,yBAAAA;AAAAA,MAAAA;;MACEA,OAACA,YAAcxI,IAAA+C,MAAAA,CAAAA,CAAKyF,IAAMxI;IAD5BwI,CAAAA;EAHFD,GAAAA,WAAAA,EAAAA,IAAAA;EAQAE;EAAAA;;IAAAA;;;;AACEC,IAAAA,4BAAAA,wBAAiBC,QAAD,EAAWC,YAA3BF;AAAAA,MAAAA;;;AAEFA,oBAAsB1I,IAAK0I,qBAAuBE,YAAaF;AAC/DA;AACAA,QAAU1I,IAAAU,OAAAA,CAAMmI,eAASnG,KAAAA,CAAMgG,oBAAD,GAAA,CAAqBE,YAArB,CAAA,GAAkCF,eAAlC,GAAA,CAAiD1I,IAAAY,SAAAA,CAAAA,CAAjD,CAAA,GAAyD8H,GAAvE,EAA2EE,YAAlElG,CAAfhC,CAA+FgI;AACzGA;AACAA,MAAQ1I,IAAK0I,WAAaC,QAASD;AACnCA;IAPEA,CAAAA;IAUAD,OAAAK,4BAAAA,wBAAAA;AAAAA,MAAAA;;;MACE9I,IAAAwI,eAAAA,CAAAA;MACAM,OAACA,uBAADA;IAFFA,CAAAA;EAXFL,GAAAA,WAAAA,EAAAA,IAAAA;EAkBA5I,OAAAkJ,CAAAA,WAAKC,CAAAA,gBAAUhJ,IAAAgB,QAAAA,CAAQnB,WAARmB,CAAVgI,CAALD;AAxnBAlJ;"}}, {:offset=>{:line=>25892, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["./strscan.rb"], :sourcesContent=>["class StringScanner\n  attr_reader :pos, :matched\n\n  def initialize(string)\n    @string  = string\n    @pos     = 0\n    @matched = nil\n    @working = string\n    @match   = []\n  end\n\n  attr_reader :string\n\n  def beginning_of_line?\n    `\#{@pos} === 0 || \#{@string}.charAt(\#{@pos} - 1) === \"\\n\"`\n  end\n\n  def scan(pattern)\n    pattern = anchor(pattern)\n\n    %x{\n      var result = pattern.exec(\#{@working});\n\n      if (result == null) {\n        return \#{@matched} = nil;\n      }\n      \#{@prev_pos} = \#{@pos};\n      \#{@pos}     += result[0].length;\n      \#{@working}  = \#{@working}.substring(result[0].length);\n      \#{@matched}  = result[0];\n      \#{@match}    = result;\n\n      return result[0];\n    }\n  end\n\n  def scan_until(pattern)\n    pattern = anchor(pattern)\n\n    %x{\n      var working = \#{@working}\n\n      for(var i = 0; working.length != i; ++i) {\n        var result  = pattern.exec(working.substr(i));\n        if (result !== null) {\n          var matched_size = i + result[0].length\n          var matched = working.substr(0, matched_size)\n\n          \#{@matched}  = result[0]\n          \#{@match}  = result\n          \#{@prev_pos} = \#{@pos} + i; // Position of first character of matched\n          \#{@pos} += matched_size // Position one after last character of matched\n          \#{@working} = working.substr(matched_size)\n\n          return matched\n        }\n      }\n      return \#{@matched} = nil;\n    }\n  end\n\n  def [](idx)\n    if @match.empty?\n      return nil\n    end\n    case idx\n    when Symbol\n      idx = idx.to_s\n    when String\n      # noop\n    else\n      idx = ::Opal.coerce_to!(idx, Integer, :to_int)\n    end\n    %x{\n      var match = \#{@match};\n\n      if (idx < 0) {\n        idx += match.length;\n      }\n\n      if (idx < 0 || idx >= match.length) {\n        return nil;\n      }\n\n      if (match[idx] == null) {\n        return nil;\n      }\n\n      return match[idx];\n    }\n  end\n\n  def check(pattern)\n    pattern = anchor(pattern)\n\n    %x{\n      var result = pattern.exec(\#{@working});\n\n      if (result == null) {\n        return \#{@matched} = nil;\n      }\n\n      return \#{@matched} = result[0];\n    }\n  end\n\n  def check_until(pattern)\n    %x{\n      var old_prev_pos = \#{@prev_pos};\n      var old_pos      = \#{@pos};\n      var old_working  = \#{@working};\n\n      var result = \#{scan_until(pattern)};\n\n      \#{@prev_pos} = old_prev_pos;\n      \#{@pos}      = old_pos;\n      \#{@working}  = old_working;\n\n      return result;\n    }\n  end\n\n  def peek(length)\n    `\#{@working}.substring(0, length)`\n  end\n\n  def eos?\n    `\#{@working}.length === 0`\n  end\n\n  def exist?(pattern)\n    %x{\n      var result = pattern.exec(\#{@working});\n\n      if (result == null) {\n        return nil;\n      }\n      else if (result.index == 0) {\n        return 0;\n      }\n      else {\n        return result.index + 1;\n      }\n    }\n  end\n\n  def skip(pattern)\n    pattern = anchor(pattern)\n\n    %x{\n      var result = pattern.exec(\#{@working});\n\n      if (result == null) {\n        \#{@match} = [];\n        return \#{@matched} = nil;\n      }\n      else {\n        var match_str = result[0];\n        var match_len = match_str.length;\n\n        \#{@matched}   = match_str;\n        \#{@match}     = result;\n        \#{@prev_pos}  = \#{@pos};\n        \#{@pos}      += match_len;\n        \#{@working}   = \#{@working}.substring(match_len);\n\n        return match_len;\n      }\n    }\n  end\n\n  def skip_until(pattern)\n    %x{\n      var result = \#{scan_until(pattern)};\n\n      if (result === nil) {\n        return nil;\n      }\n      else {\n        \#{@matched} = result.substr(-1);\n\n        return result.length;\n      }\n    }\n  end\n\n  def get_byte\n    %x{\n      var result = nil;\n\n      if (\#{@pos} < \#{@string}.length) {\n        \#{@prev_pos}  = \#{@pos};\n        \#{@pos}      += 1;\n        result      = \#{@matched} = \#{@working}.substring(0, 1);\n        \#{@working}   = \#{@working}.substring(1);\n      }\n      else {\n        \#{@matched} = nil;\n      }\n\n      return result;\n    }\n  end\n\n  def match?(pattern)\n    pattern = anchor(pattern)\n\n    %x{\n      var result = pattern.exec(\#{@working});\n\n      if (result == null) {\n        return nil;\n      }\n      else {\n        \#{@prev_pos} = \#{@pos};\n\n        return result[0].length;\n      }\n    }\n  end\n\n  def pos=(pos)\n    %x{\n      if (pos < 0) {\n        pos += \#{@string.length};\n      }\n    }\n\n    @pos     = pos\n    @working = `\#{@string}.slice(pos)`\n  